-- Poems batch 132
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('0ef129d1-b693-4621-a34f-0d70e8eeb0b0','克信弟坐上賦梅花二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','對酒初驚髮半華，折梅還覺興殊佳。',64,'全唐诗/poet.song.140000.json','["對酒初驚髮半華，折梅還覺興殊佳。", "如何屋角西南月，只照梢頭一兩花。", "自是向來香寂寞，不須更道影橫斜。", "北枝別有春無價，和靖何曾覓得些。"]'),
('ea214259-afcc-49d4-a07d-ed367bc71a8e','克信弟坐上賦梅花二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','月波成露露成霜，借與南枝作淡妝。',64,'全唐诗/poet.song.140000.json','["月波成露露成霜，借與南枝作淡妝。", "寒入玉衣燈下薄，春撩雪骨酒邊香。", "却於老樹半枯處，忽走一梢如許長。", "道是疎花不解語，伴人醒醉替人狂。"]'),
('963fa238-cc39-4888-abc3-51c21658b99e','德遠叔坐上賦肴核八首 糟蟹','楊萬里','宋','宋诗','song-poetry','','[]','橫行湖海浪生花，糟粕招邀到酒家。',32,'全唐诗/poet.song.140000.json','["橫行湖海浪生花，糟粕招邀到酒家。", "酥片滿螯凝作玉，金穰鎔腹未成沙。"]'),
('2bd7050c-befd-4ab1-9233-339f86222319','德遠叔坐上賦肴核八首 牛尾狸','楊萬里','宋','宋诗','song-poetry','','[]','瓊瑶風骨褐衣裘，野果初紅玉露秋。',32,'全唐诗/poet.song.140000.json','["瓊瑶風骨褐衣裘，野果初紅玉露秋。", "僧孺喚渠登榜尾，季狸只合隠山頭。"]'),
('6c92b47f-011a-4d5a-9ca3-35ec6c2dd611','德遠叔坐上賦肴核八首 蔊菜','楊萬里','宋','宋诗','song-poetry','','[]','齏臼文辭粲受辛，子牙爲祖芥爲孫。',32,'全唐诗/poet.song.140000.json','["齏臼文辭粲受辛，子牙爲祖芥爲孫。", "勸君莫謁獨醒客，只謁高陽社裏人。"]'),
('67fa526b-7c60-4aac-a249-8b85feee2486','德遠叔坐上賦肴核八首 蜜金橘','楊萬里','宋','宋诗','song-poetry','','[]','風餐露飲橘洲仙，胸次清於月樣圜。',32,'全唐诗/poet.song.140000.json','["風餐露飲橘洲仙，胸次清於月樣圜。", "俠客偶遺金彈子，蜂王撚作菊花鈿。"]'),
('967f2ac5-bd05-49aa-8ad2-11885aaa708d','德遠叔坐上賦肴核八首 藕','楊萬里','宋','宋诗','song-poetry','','[]','荷衣芰製雪爲容，家住雲煙太華峰。',32,'全唐诗/poet.song.140000.json','["荷衣芰製雪爲容，家住雲煙太華峰。", "外面看來真璞玉，胸中琱出許玲瓏。"]'),
('c12ad177-4f38-4ac5-a528-14090f823b17','德遠叔坐上賦肴核八首 人面子','楊萬里','宋','宋诗','song-poetry','','[]','喜時能笑醉能歌，眉映青山眼映波。',32,'全唐诗/poet.song.140000.json','["喜時能笑醉能歌，眉映青山眼映波。", "舊日美如潘騎省，只今瘦似病維摩。"]'),
('fc730b78-3712-4a78-bcda-f48d40809dfc','德遠叔坐上賦肴核八首 糖霜','楊萬里','宋','宋诗','song-poetry','','[]','亦非崖蜜亦非餳，青女吹霜凍作冰。',32,'全唐诗/poet.song.140000.json','["亦非崖蜜亦非餳，青女吹霜凍作冰。", "透骨清寒輕著齒，嚼成人迹板橋聲。"]'),
('3927ada1-e205-443f-b2d0-263df3c691b8','德遠叔坐上賦肴核八首 銀杏','楊萬里','宋','宋诗','song-poetry','','[]','深灰淺火略相遭，小苦微甘韻最高。',32,'全唐诗/poet.song.140000.json','["深灰淺火略相遭，小苦微甘韻最高。", "未必雞頭如鴨脚，不妨銀杏伴金桃。"]'),
('27ff6583-e734-4c60-86eb-94aae4bdc5bd','送談命曾南翔二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','官職牽人也可憐，老來那更問行年。',32,'全唐诗/poet.song.140000.json','["官職牽人也可憐，老來那更問行年。", "渠儂解事無它語，道我慈親壽八千。"]'),
('16f78788-5980-4b65-809a-77c86e576f86','送談命曾南翔二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','今年見說也無錐，政坐談天泄密機。',32,'全唐诗/poet.song.140000.json','["今年見說也無錐，政坐談天泄密機。", "舉世近來憎直語，貴人剩許未爲癡。"]'),
('71714f8e-2562-46e9-9faf-ed8d7ce814bd','題孫舜俞府判瑞石圖','楊萬里','宋','宋诗','song-poetry','','[]','雞冠山青龜浦碧，松桂捎雲三萬尺。',99,'全唐诗/poet.song.140000.json','["雞冠山青龜浦碧，松桂捎雲三萬尺。", "何年星霣化爲石，風吹未凝冰玉色。", "仙人擘開光燭天，山下人家夜不眠。", "松花桂子落如雪，飛入石中堅似鐵。", "石中種樹人不知，石中生樹人始奇。", "君不見只今瑞圖滿四海，騷人詩卷牛腰大。"]'),
('75d0049b-8a2b-4e73-81c7-cdf6772908f1','過周陂江','楊萬里','宋','宋诗','song-poetry','','[]','溪暖無冰可得銷，清波白石小魚跳。',32,'全唐诗/poet.song.140000.json','["溪暖無冰可得銷，清波白石小魚跳。", "忽逢寸碧翩然起，翡翠驚飛上柳條。"]'),
('354f7009-3095-4af8-9759-f56b3e7f7b20','送談星辰許季升二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','許子儒冠怨誤身，如今投筆說星辰。',32,'全唐诗/poet.song.140000.json','["許子儒冠怨誤身，如今投筆說星辰。", "未須道我何時貴，且道何時子脫貧。"]'),
('2f39b9b9-f3fd-4e39-9707-2be80ecb3434','送談星辰許季升二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','連珠合璧轉璇霄，也被星家不見饒。',32,'全唐诗/poet.song.140000.json','["連珠合璧轉璇霄，也被星家不見饒。", "災曜元來怯檮杌，福星不是背簞瓢。"]'),
('8d0fc604-cf1f-4095-8bc7-bf8e6a99858c','紀羅楊二子游南嶺石人峰','楊萬里','宋','宋诗','song-poetry','','[]','二子同游石人峰，深行翠篠黄茅中。',176,'全唐诗/poet.song.140000.json','["二子同游石人峰，深行翠篠黄茅中。", "初嫌微徑無人蹤，行到半嶺徑亦窮。", "來時猶自聞雞犬，且行且語不覺遠。", "上頭無梯下無岸，前頭難攀後難返。", "黄茅翠篠深復深，忽有笛聲出暗林。", "草根一把牛骨骼，血點濺地驚人心。", "二子相看面無色，疾趨山後空王宅。", "野僧聞此叫絕天，拊破禪床椎倒壁。", "荒山豈有吹笛聲，乃是卧虎鼻息鳴。", "二子歸來向儂說，猶道茲游最清絕。", "茲游清絕豈不佳，二子性命如泥沙。"]'),
('adb7d0f2-53b0-4360-aa04-784dfdb7c4d0','題黄辰告愚齋','楊萬里','宋','宋诗','song-poetry','','[]','聖門如天不可梯，諸子欲以智取之。',64,'全唐诗/poet.song.140000.json','["聖門如天不可梯，諸子欲以智取之。", "杏壇獨立無箇事，只有回愚也大奇。", "吾黨少年子黄子，問津陋巷參顔氏。", "只今此事冷如漿，來年八月槐花黄。"]'),
('4792eaf4-eecc-4bf7-a583-a318508ac0bc','寄題萬安縣劉元襲橫秀閣','楊萬里','宋','宋诗','song-poetry','','[]','玉簪成陣雪成堆，秀氣橫空撥不開。',64,'全唐诗/poet.song.140000.json','["玉簪成陣雪成堆，秀氣橫空撥不開。", "楚岫蒼寒五雲外，贛江白寫九天來。", "煙銷日出皆詩句，月色波聲喚夢回。", "早晚携家過高閣，寄詩聊當一枝梅。"]'),
('c99736b7-2acf-43e6-9b8c-48e7480ec41b','廷弼弟座上絕句','楊萬里','宋','宋诗','song-poetry','','[]','黄雀初肥入口銷，玉醅新熟得春饒。',32,'全唐诗/poet.song.140000.json','["黄雀初肥入口銷，玉醅新熟得春饒。", "主人更恐香無味，沉水龍涎作伴燒。"]'),
('1bb2f367-c73b-464f-937c-bd5574404726','十二月二十七日大雪中過吉水小盤渡西歸三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','風卷寒江浪濕天，斜吹亂雪忽平船。',32,'全唐诗/poet.song.140000.json','["風卷寒江浪濕天，斜吹亂雪忽平船。", "碧琉璃上瓊花裏，獨載詩人孟浩然。"]'),
('463c6f52-565e-4e31-a886-0f16375e839c','十二月二十七日大雪中過吉水小盤渡西歸三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','臘殘滕六不歸家，白晝乘風撒玉沙。',32,'全唐诗/poet.song.140000.json','["臘殘滕六不歸家，白晝乘風撒玉沙。", "旋種瓊田茁瑶草，更栽琪樹著銀花。"]'),
('f6d6b0fc-8860-41ea-9427-6cf3d46b4341','十二月二十七日大雪中過吉水小盤渡西歸三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','雪吹醉面不知寒，信脚千山與萬山。',32,'全唐诗/poet.song.140000.json','["雪吹醉面不知寒，信脚千山與萬山。", "天甃瓊街三十里，更飛柳絮與君看。"]'),
('5114e800-eb46-41d8-ad75-7c477d959f3f','山居雪後二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','春近能餘幾許寒，雪花纔落便銷殘。',32,'全唐诗/poet.song.140000.json','["春近能餘幾許寒，雪花纔落便銷殘。", "青松梢上蘭根下，猶得三朝兩日看。"]'),
('a7ac1847-fc86-42fa-b9cb-fc41fd354d62','山居雪後二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','一點紅塵未敢生，松間雪後政堪行。',32,'全唐诗/poet.song.140000.json','["一點紅塵未敢生，松間雪後政堪行。", "日光半破風微度，時作高林落果聲。"]'),
('d211c080-cf89-4989-8b91-611464178d0b','庚子正月五日曉過大皋渡二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','霧外江山看不真，只憑雞犬認前村。',32,'全唐诗/poet.song.140000.json','["霧外江山看不真，只憑雞犬認前村。", "渡船滿板霜如雪，印我青鞋第一痕。"]'),
('7af975ca-01d9-471f-a3de-c15ce0492767','庚子正月五日曉過大皋渡二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','危沙崩岸欲侵牆，直下清江百尺强。',32,'全唐诗/poet.song.140000.json','["危沙崩岸欲侵牆，直下清江百尺强。", "過了筍輿元未覺，忽然回首冷思量。"]'),
('7fcdd925-9fcf-4575-90c8-d00dce52f31a','曉霧','楊萬里','宋','宋诗','song-poetry','','[]','不知香務濕人鬚，日照鬚端細有珠。',32,'全唐诗/poet.song.140000.json','["不知香務濕人鬚，日照鬚端細有珠。", "政是春山眉樣翠，被渠淡粉作糊塗。"]'),
('2694fcba-f9de-4117-b158-355cc03c2052','送胡端明赴召','楊萬里','宋','宋诗','song-poetry','','[]','紫泥夜下日星暉，赤舄朝看衮繡歸。',64,'全唐诗/poet.song.140000.json','["紫泥夜下日星暉，赤舄朝看衮繡歸。", "中國如今相司馬，四夷見說問非衣。", "金魚玉带明霜鬢，斗極台符拱太微。", "衛武年齡子儀考，一身雙美古來稀。"]'),
('e8c4a57e-ee0c-4db4-86cb-92e8a63d0116','晚出郡城往值夏謁胡端明泛舟夜歸','楊萬里','宋','宋诗','song-poetry','','[]','郡城至值夏，兩日非寬程。',168,'全唐诗/poet.song.140000.json','["郡城至值夏，兩日非寬程。", "奔走豈吾願，詔書促南征。", "出郭星未已，歸棹月已生。", "問人水深淺，舟子喧未應。", "水石代之對，淙然落灘聲。", "危峰起夕蒼，暗潭生夜清。", "江轉風颯至，病肩難隠稜。", "添衣初嬾尋，忍寒良不能。", "近城一二里，遠岸三四燈。", "望關恐早閉，驅舟祗遲行。", "多情半環月，久矣將西傾。", "欲落且小留，知我要入城。", "月細光未多，大星助之明。", "至舍心未穩，麗譙才一更。"]'),
('b258bf50-aded-4294-976a-caddbc3bf2b5','之官五羊過太和縣登快閣觀山谷石刻賦兩絕句呈知縣李紳公垂主簿趙蕃昌父  其一','楊萬里','宋','宋诗','song-poetry','','[]','閣中陳迹故依然，欲問風流已百年。',32,'全唐诗/poet.song.140000.json','["閣中陳迹故依然，欲問風流已百年。", "南岸一峰東一塔，自言曾識老詩仙。"]'),
('979dbc6d-26d9-40e9-bb18-24e764717dcf','之官五羊過太和縣登快閣觀山谷石刻賦兩絕句呈知縣李紳公垂主簿趙蕃昌父  其二','楊萬里','宋','宋诗','song-poetry','','[]','廬陵山水說西昌，天遣金華印此邦。',32,'全唐诗/poet.song.140000.json','["廬陵山水說西昌，天遣金華印此邦。", "詩本道他將取去，如何遺下一澄江。"]'),
('71442b03-186f-4f12-9cd9-7e61741655c8','題龍舜臣遜志齋','楊萬里','宋','宋诗','song-poetry','','[]','龍子辛勤蒔紙田，少年筆勢已翩翩。',32,'全唐诗/poet.song.140000.json','["龍子辛勤蒔紙田，少年筆勢已翩翩。", "欲知聖處真消息，不是原夫一兩聯。"]'),
('92b6d2f3-fa39-4b47-aeb9-696fd8f60f89','二月一日曉渡太和江三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','綠楊接葉杏交花，嫩水新生尚露沙。',32,'全唐诗/poet.song.140000.json','["綠楊接葉杏交花，嫩水新生尚露沙。", "過了春江偶回首，隔江一片好人家。"]'),
('6b3d09f1-c50e-4feb-a528-a24133bf0b6d','二月一日曉渡太和江三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','曉翠妨人看遠山，小風偏入客衣單。',32,'全唐诗/poet.song.140000.json','["曉翠妨人看遠山，小風偏入客衣單。", "桃花愛做春寒信，只恐桃花也自寒。"]'),
('012850c1-8327-4dac-a70e-2bff8ecc2beb','二月一日曉渡太和江三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','二月初頭春向中，花梢薄日柳梢風。',32,'全唐诗/poet.song.140000.json','["二月初頭春向中，花梢薄日柳梢風。", "折花客子渾無頼，狼藉須教滿路紅。"]'),
('4661bc4f-5239-4e1d-a273-8f1cb8a48d2f','晨炊黄宙鋪飯後山行','楊萬里','宋','宋诗','song-poetry','','[]','山行行得軟如綿，急上籃輿睡霎間。',32,'全唐诗/poet.song.140000.json','["山行行得軟如綿，急上籃輿睡霎間。", "夢裏只聞人喝道，不知過盡數重山。"]'),
('697f32bd-01c3-49eb-b5e4-b1b290e333d9','宿灘頭海智寺','楊萬里','宋','宋诗','song-poetry','','[]','平生行路敢求安，便要求安也大難。',32,'全唐诗/poet.song.140000.json','["平生行路敢求安，便要求安也大難。", "古寺無門更無壁，若教半夜作春寒。"]'),
('196d03cf-e3d7-41de-9c6d-9884c93995a0','明發海智寺遇雨二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','枉教一月費春風，不及朝來細雨功。',32,'全唐诗/poet.song.140000.json','["枉教一月費春風，不及朝來細雨功。", "草色染來藍樣翠，桃花洗得肉般紅。"]'),
('fed46c29-0095-4fea-bcd3-439ec1981258','明發海智寺遇雨二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','可惜新年雨未多，不妨剩與決天河。',32,'全唐诗/poet.song.140000.json','["可惜新年雨未多，不妨剩與決天河。", "農人皺得眉頭破，無水種秧君奈何。"]'),
('430b0174-7e06-4068-a8d5-f1e85d0bf5bf','題太和主簿趙昌父思隠堂','楊萬里','宋','宋诗','song-poetry','','[]','西昌主簿如禪僧，日餐秋菊嚼春冰。',112,'全唐诗/poet.song.140000.json','["西昌主簿如禪僧，日餐秋菊嚼春冰。", "西昌官舍如佛屋，一物也無唯有竹。", "俸錢三月不曾支，竹陰過午未晨炊。", "大兒叫怒小兒啼，乃翁對竹方哦詩。", "詩人與竹一樣瘦，詩句與竹一樣秀。", "故山蒼玉摇綠雲，月梢風葉最關身。", "勸渠未要思舊隠，且與西昌作好春。"]'),
('f2d43d03-97be-48e6-928c-75c17de60c0f','萬安道中書事三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','玉峰雲剝逗斜明，花徑泥乾得晚行。',32,'全唐诗/poet.song.140000.json','["玉峰雲剝逗斜明，花徑泥乾得晚行。", "細細一風寒裏暖，時時數點雨中晴。"]'),
('0b347646-6a65-4064-be3a-170edd3db1b6','萬安道中書事三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','携家滿路踏春華，兒女欣欣不憶家。',32,'全唐诗/poet.song.140000.json','["携家滿路踏春華，兒女欣欣不憶家。", "騎吏也忘行役苦，一人人插一枝花。"]'),
('9d092265-7f24-49e0-b70f-48857ee75b37','萬安道中書事三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','桃花薄相點燕脂，輸與梨花雪作肌。',32,'全唐诗/poet.song.140000.json','["桃花薄相點燕脂，輸與梨花雪作肌。", "只有垂楊不脂粉，縷金鋪翠襯腰支。"]'),
('ef2f9325-6615-4222-91af-8d7f93e90d9d','萬安出郭早行','楊萬里','宋','宋诗','song-poetry','','[]','玉花小朶是山礬，香殺行人只欲顛。',32,'全唐诗/poet.song.140000.json','["玉花小朶是山礬，香殺行人只欲顛。", "風掠水衣無處去，柳塘著在角頭邊。"]'),
('54dfa50b-2675-4b1c-8fef-d076298e53c0','皇恐灘三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','兩山夾岸走蒼龍，未放中間過玉虹。',32,'全唐诗/poet.song.140000.json','["兩山夾岸走蒼龍，未放中間過玉虹。", "只愛當頭一峰好，一峰外面更三峰。"]'),
('e3b5b4a1-3b03-46b6-9c1d-d439c38bae27','皇恐灘三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','只愁江水去無還，石打銀濤倒上灘。',32,'全唐诗/poet.song.140000.json','["只愁江水去無還，石打銀濤倒上灘。", "道是此灘天下惡，古今放過幾檣竿。"]'),
('6a483cf0-eadd-4397-8599-ef992c30da97','皇恐灘三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','小煩溪友語陽侯，好遣漂沙蓋石頭。',32,'全唐诗/poet.song.140000.json','["小煩溪友語陽侯，好遣漂沙蓋石頭。", "能費奔流多少力，前頭幸有一沙洲。"]'),
('78c789b1-2308-4d5d-a478-72726f2c0f8e','過皂口','楊萬里','宋','宋诗','song-poetry','','[]','贛石三百里，春流十八灘。',48,'全唐诗/poet.song.140000.json','["贛石三百里，春流十八灘。", "路從青壁絕，船到半江寒。", "不是春光好，誰供客子看。", "猶須一尊淥，併遣百憂寬。"]'),
('29b7aeaf-dccd-4599-840a-77434d321682','宿皂口驛','楊萬里','宋','宋诗','song-poetry','','[]','倦投破驛歇征驂，喜見山光政蔚藍。',32,'全唐诗/poet.song.140000.json','["倦投破驛歇征驂，喜見山光政蔚藍。", "不奈東風無檢束，亂吹花片點春衫。"]'),
('8a929c07-7bf3-4a7e-bea3-0f4c610476f4','曉過皂口嶺','楊萬里','宋','宋诗','song-poetry','','[]','夜渡驚灘有底忙，曉攀絕磴更禁當。',64,'全唐诗/poet.song.140000.json','["夜渡驚灘有底忙，曉攀絕磴更禁當。", "周遭碧嶂無人跡，圍入青天小冊方。", "半世功名一雞肋，平生道路九羊腸。", "何時上到梅花嶺，北望螺峰半點蒼。"]'),
('f5111602-aafe-4b7c-b196-91406bafd67a','道傍小桃','楊萬里','宋','宋诗','song-poetry','','[]','吹盡殘桃無可殘，也無地上落花痕。',32,'全唐诗/poet.song.140000.json','["吹盡殘桃無可殘，也無地上落花痕。", "獨行尋到青苔處，拾得嫣紅一片看。"]'),
('c2e66e8e-3aa5-4b99-8495-8aed75ddfb3b','晨炊皂徑','楊萬里','宋','宋诗','song-poetry','','[]','問路無多子，驅車半日間。',48,'全唐诗/poet.song.140000.json','["問路無多子，驅車半日間。", "行穿崖石古，踏破蘚花斑。", "綠語鶑邊柳，青眠水底山。", "人家豈無地，爭住小溪灣。"]'),
('737b8751-47e3-4d5c-8ba0-8b975b614adf','步過分水嶺','楊萬里','宋','宋诗','song-poetry','','[]','路險勞人殺，儂須下轎行。',48,'全唐诗/poet.song.140000.json','["路險勞人殺，儂須下轎行。", "石從何代落，蕨傍舊根生。", "古樹無今態，幽泉有暗聲。", "只言章貢近，猶自兩三程。"]'),
('b79963b3-6c5b-46e5-9f6b-80eb5b260bea','憩分水嶺望鄉二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','嶺頭泉眼一涓流，南入虔州北吉州。',32,'全唐诗/poet.song.140000.json','["嶺頭泉眼一涓流，南入虔州北吉州。", "只隔中間些子地，水聲滴作兩鄉愁。"]'),
('dc1bdc4b-6ae9-4702-8f71-bba9679b0fc5','憩分水嶺望鄉二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','嶺北泉流分外忙，一聲一滴斷人腸。',32,'全唐诗/poet.song.140000.json','["嶺北泉流分外忙，一聲一滴斷人腸。", "浪愁出却廬陵界，未入梅山總故鄉。"]'),
('440444c3-b322-4645-90a7-fc0cb6e39d42','桂源鋪','楊萬里','宋','宋诗','song-poetry','','[]','萬山不許一溪奔，攔得溪聲日夜喧。',32,'全唐诗/poet.song.140000.json','["萬山不許一溪奔，攔得溪聲日夜喧。", "到得前頭山脚盡，堂堂溪水出前村。"]'),
('5cffeb50-b743-4fb2-b51b-1e2a3c3ab500','社日南康道中','楊萬里','宋','宋诗','song-poetry','','[]','東風試暖却成寒，春恰平分又欲殘。',64,'全唐诗/poet.song.140000.json','["東風試暖却成寒，春恰平分又欲殘。", "淡著煙雲輕著雨，近遮草樹遠遮山。", "人行柳色花光裏，天接江西嶺北間。", "管領社公須竹葉，在家在外匹如閑。"]'),
('b8460e80-e44a-4d71-8a77-a73fa0a820ed','小溪至新田四首  其一','楊萬里','宋','宋诗','song-poetry','','[]','人煙懡㦬不成村，溪水微茫劣半分。',32,'全唐诗/poet.song.140000.json','["人煙懡㦬不成村，溪水微茫劣半分。", "流到前灘忙似箭，不容雨點稍成紋。"]'),
('29e81c77-be86-4d7a-a872-a801cfe57f88','小溪至新田四首  其二','楊萬里','宋','宋诗','song-poetry','','[]','只愛孤峰惹寸雲，忽驚頭上雨翻盆。',32,'全唐诗/poet.song.140000.json','["只愛孤峰惹寸雲，忽驚頭上雨翻盆。", "北來南去緣何事，路上君看屐子痕。"]'),
('825154b8-4bd3-4c68-83af-148ce11215c9','小溪至新田四首  其三','楊萬里','宋','宋诗','song-poetry','','[]','晚雲解事忽離披，放出千峰特地奇。',32,'全唐诗/poet.song.140000.json','["晚雲解事忽離披，放出千峰特地奇。", "欲揀一峰誰子是，總如筆未退尖時。"]'),
('0c63ed72-1f4b-4d19-b3fe-93cb2fc80577','小溪至新田四首  其四','楊萬里','宋','宋诗','song-poetry','','[]','懊惱春光欲斷腸，來時長緩去時忙。',32,'全唐诗/poet.song.140000.json','["懊惱春光欲斷腸，來時長緩去時忙。", "落紅滿路無人惜，踏作花泥透脚香。"]'),
('9363ae13-b41d-47c3-a0e3-e82f114efc96','二月十九日度大庾嶺題雲封寺四首  其一','楊萬里','宋','宋诗','song-poetry','','[]','梅山未到未教休，到得梅山始欲愁。',32,'全唐诗/poet.song.140000.json','["梅山未到未教休，到得梅山始欲愁。", "知道望鄉看不見，也須一步一回頭。"]'),
('762d9112-4eb4-45bf-a7c0-75d7d1ec1d69','二月十九日度大庾嶺題雲封寺四首  其二','楊萬里','宋','宋诗','song-poetry','','[]','小立峰頭望故鄉，故鄉不見只蒼蒼。',32,'全唐诗/poet.song.140000.json','["小立峰頭望故鄉，故鄉不見只蒼蒼。", "客心恨殺雲遮却，不道無雲即斷腸。"]'),
('2b77d233-141d-4a9f-86f8-68bec6b71ab0','二月十九日度大庾嶺題雲封寺四首  其三','楊萬里','宋','宋诗','song-poetry','','[]','梅葉成陰梅子肥，梅花應恨我來遲。',32,'全唐诗/poet.song.140000.json','["梅葉成陰梅子肥，梅花應恨我來遲。", "明年若寄江西信，莫折南枝折北枝。"]'),
('a67f54ab-0f86-485d-9572-50fad5d29a17','二月十九日度大庾嶺題雲封寺四首  其四','楊萬里','宋','宋诗','song-poetry','','[]','行者南來今幾春，一回舉似一回新。',32,'全唐诗/poet.song.140000.json','["行者南來今幾春，一回舉似一回新。", "鉢盂奪得知何用，不怕梅花解笑人。"]'),
('73bb92b3-3969-41a1-8689-b9f33e00157e','題南雄驛外計堂','楊萬里','宋','宋诗','song-poetry','','[]','携家度嶺夜乘槎，小泊凌江水北涯。',64,'全唐诗/poet.song.140000.json','["携家度嶺夜乘槎，小泊凌江水北涯。", "二月山城無菜把，一年春事又楊花。", "舉頭海國星辰近，回顧梅山草樹遮。", "客子相逢聞好語，看山只欠到南華。"]'),
('eb9a924c-539f-44b6-9ea6-773fbf6e4892','二月二十三日南雄解舟二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','昨夜新雷九地鳴，今朝春漲一篙清。',32,'全唐诗/poet.song.140000.json','["昨夜新雷九地鳴，今朝春漲一篙清。", "順流更借江風便，此去韶州只兩程。"]'),
('871d5d98-4fae-4ebd-b7cd-e886f984963b','二月二十三日南雄解舟二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','水沒蒲芽尚有梢，風吹屋角半無茅。',32,'全唐诗/poet.song.140000.json','["水沒蒲芽尚有梢，風吹屋角半無茅。", "急灘未到先聞浪，枯樹遥看只見巢。"]'),
('03bcfcde-4ca3-4eab-bb62-db18441571e4','舟過黄田謁龍母護應廟二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','遠山相別忽相尋，水到黄田漸欲深。',32,'全唐诗/poet.song.140000.json','["遠山相別忽相尋，水到黄田漸欲深。", "見說前頭山更好，且留好句未須吟。"]'),
('cc799833-5f97-47ed-9994-d5d5c78068a6','舟過黄田謁龍母護應廟二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','南康名酒有殘樽，急喚荷杯作好春。',32,'全唐诗/poet.song.140000.json','["南康名酒有殘樽，急喚荷杯作好春。", "紫幕能排北風冷，夕陽偏惜半船溫。"]'),
('ba35538c-8b5f-4f6e-98de-67c3c8bfd353','舟過謝潭三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','風頭纔北忽成南，轉眼黄田到謝潭。',32,'全唐诗/poet.song.140000.json','["風頭纔北忽成南，轉眼黄田到謝潭。", "髣髴一峰船外影，褰帷急看紫巉巖。"]'),
('0aa47add-2a4c-48e7-a837-a7dff39b6c8e','舟過謝潭三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','夾江百里沒人家，最苦江流曲更斜。',32,'全唐诗/poet.song.140000.json','["夾江百里沒人家，最苦江流曲更斜。", "嶺草已青今歲葉，岸蘆猶白去年花。"]'),
('602be99a-575b-4f03-b165-fdfa1857b0a1','舟過謝潭三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','碧酒時傾一兩杯，船門纔閉又還開。',32,'全唐诗/poet.song.140000.json','["碧酒時傾一兩杯，船門纔閉又還開。", "好山萬皺無人見，都被斜陽拈出來。"]'),
('e9e21369-ec3e-48d8-a1da-6d5ba25b2607','明發階口岸下','楊萬里','宋','宋诗','song-poetry','','[]','破曉篙師報放船，今朝不似昨朝寒。',32,'全唐诗/poet.song.140000.json','["破曉篙師報放船，今朝不似昨朝寒。", "夢中草草披衣起，愛看輕舟下急灘。"]'),
('aa8af99c-b323-4d97-bd52-095aab639ca1','過鄭步','楊萬里','宋','宋诗','song-poetry','','[]','漸有人家松桂叢，韶州山水勝南雄。',32,'全唐诗/poet.song.140000.json','["漸有人家松桂叢，韶州山水勝南雄。", "未須青惜峰巒過，過了諸峰得好峰。"]'),
('ae623f42-85f0-4e3e-a64e-edf29ab22a05','過鼓鳴林小雨二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','淅淅船篷雨點聲，疎疎江面縠紋生。',32,'全唐诗/poet.song.140000.json','["淅淅船篷雨點聲，疎疎江面縠紋生。", "石峰斗起三千丈，身在假山園裏行。"]'),
('26563340-90aa-4dd2-89cb-0632b6b7edbc','過鼓鳴林小雨二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','下瀧小舫戴尖篷，未論千峰與萬峰。',32,'全唐诗/poet.song.140000.json','["下瀧小舫戴尖篷，未論千峰與萬峰。", "只是舟人頭上笠，也堪收入畫圖中。"]'),
('970808f4-103d-4f5f-9816-878e2db39f53','明發韶州過赤水渴尾灘','楊萬里','宋','宋诗','song-poetry','','[]','船下驚灘浪政喧，花汀水退走沙痕。',32,'全唐诗/poet.song.140000.json','["船下驚灘浪政喧，花汀水退走沙痕。", "一峰忽自雲端出，只見孤尖不見根。"]'),
('303dc46d-b497-49be-a61a-bc86989e61dd','三月一日過摩舍那灘阻雨泊清溪鎮二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','一聲霹靂霽光收，急泊荒茅野渡頭。',64,'全唐诗/poet.song.140000.json','["一聲霹靂霽光收，急泊荒茅野渡頭。", "摩舍那灘衝石過，曼阤羅影漾江流。", "山纔入眼雲遮斷，船欲追程雨見留。", "夜宿清溪望清遠，舉頭不見隔英州。"]'),
('1071598e-cee6-416b-ab32-279c565d5458','三月一日過摩舍那灘阻雨泊清溪鎮二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','過盡危灘百不堪，忽驚絕壁翠巉巉。',64,'全唐诗/poet.song.140000.json','["過盡危灘百不堪，忽驚絕壁翠巉巉。", "倒垂不死千年樹，下拂奔流萬丈潭。", "隔岸數峰如筆格，倚天一色染春藍。", "真陽此去無多子，到日應逢三月三。"]'),
('b2ce75a4-be57-41db-b2b3-fd4ffa56fb10','小泊英洲二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','人人藤葉嚼檳榔，戶戶茅簷覆土床。',32,'全唐诗/poet.song.140000.json','["人人藤葉嚼檳榔，戶戶茅簷覆土床。", "只有春風不寒乞，隔溪吹度柚花香。"]'),
('d9cc9eae-6a96-483d-8aaa-cbb2bdc3783a','小泊英洲二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','數家草草劣無多，跕水飛鳶也不過。',32,'全唐诗/poet.song.140000.json','["數家草草劣無多，跕水飛鳶也不過。", "道是荒城斗來大，向來此地著東坡。"]'),
('6b2bf8f1-f077-4dc8-b521-efdc25436077','過真陽峽六首  其一','楊萬里','宋','宋诗','song-poetry','','[]','玉削雙崖一水通，一重一掩更重重。',32,'全唐诗/poet.song.140000.json','["玉削雙崖一水通，一重一掩更重重。", "平生山水看多少，最愛真陽第二峰。"]'),
('b933453a-b9de-4e81-a8b4-349c5223d36c','過真陽峽六首  其二','楊萬里','宋','宋诗','song-poetry','','[]','莫道無人逕亦窮，尚餘碧篠伴青楓。',32,'全唐诗/poet.song.140000.json','["莫道無人逕亦窮，尚餘碧篠伴青楓。", "白雲不是從天降，坐看生從翠崦中。"]'),
('ca8cf5c5-5052-436c-a343-201ad660fb4f','過真陽峽六首  其三','楊萬里','宋','宋诗','song-poetry','','[]','仰見青天尺許青，無波江水不勝平。',32,'全唐诗/poet.song.140000.json','["仰見青天尺許青，無波江水不勝平。", "只驚白晝山竹裂，杜宇初聞第一聲。"]'),
('9bd8db3f-e977-4174-9d78-1bb0c59e3054','過真陽峽六首  其四','楊萬里','宋','宋诗','song-poetry','','[]','堪笑跳波數百灘，如何入峽頓無喧。',32,'全唐诗/poet.song.140000.json','["堪笑跳波數百灘，如何入峽頓無喧。", "人言此峽如巴峽，只欠三聲墮淚猿。"]'),
('ba7e23c7-79de-4980-867e-fa38809b1c8e','過真陽峽六首  其五','楊萬里','宋','宋诗','song-poetry','','[]','榕樹陰中一葦橫，鷓鴣聲裏數峰青。',32,'全唐诗/poet.song.140000.json','["榕樹陰中一葦橫，鷓鴣聲裏數峰青。", "南人到此亦腸斷，一是南人作麽生。"]'),
('46fe08a8-0b1d-40db-8d4b-741c14ff580a','過真陽峽六首  其六','楊萬里','宋','宋诗','song-poetry','','[]','百灘千港幾濤波，聚入真陽也未多。',32,'全唐诗/poet.song.140000.json','["百灘千港幾濤波，聚入真陽也未多。", "若遣峽山生塞了，不知江水倒流麽。"]'),
('9ad1105e-3ca2-4e54-ab18-a60cb468fc44','晨炊光口砦','楊萬里','宋','宋诗','song-poetry','','[]','泊船光口薦晨炊，野飯匆匆不整齊。',64,'全唐诗/poet.song.140000.json','["泊船光口薦晨炊，野飯匆匆不整齊。", "新摘柚花薰熟水，旋撈萵苣浥生虀。", "儘教坡老食無肉，未害山公醉似泥。", "過了真陽到清遠，好山自足樂人饑。"]'),
('ac8a8409-acd3-4aa5-9214-6b8d09e427ad','出蛺二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','朝來入峽悶船遲，也有欣然出峽時。',32,'全唐诗/poet.song.140000.json','["朝來入峽悶船遲，也有欣然出峽時。", "山色亦如人送客，送行倦了自應歸。"]'),
('0595f23c-8529-4838-af45-a58a8cc3abf2','出蛺二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','船行儘緩底須忙，詩卷聊堪度日長。',32,'全唐诗/poet.song.140000.json','["船行儘緩底須忙，詩卷聊堪度日長。", "瓶裏柚花偷觸鼻，忽然將謂是燒香。"]'),
('37626ba3-3c1b-4b68-a37f-7796ad424673','過沙頭三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','非煙非雨淡濛濛，深閉窗扉護晚風。',32,'全唐诗/poet.song.140000.json','["非煙非雨淡濛濛，深閉窗扉護晚風。", "船外山光簾裏翠，岸頭花影鏡中紅。"]'),
('d9c8de02-fe83-4ca0-81c0-2b2837bd754f','過沙頭三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','過了沙頭漸有村，地平江闊氣清溫。',32,'全唐诗/poet.song.140000.json','["過了沙頭漸有村，地平江闊氣清溫。", "暗潮已到無人會，只有篙師識水痕。"]'),
('f92848da-3b5e-4d57-999d-a7771cf1e3ab','過沙頭三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','昨來飛樐下危瀧，不敢窺窗只閉窗。',32,'全唐诗/poet.song.140000.json','["昨來飛樐下危瀧，不敢窺窗只閉窗。", "莫歎江平船不進，只將行役當遊江。"]'),
('2a54371e-3ee8-4d86-8614-77b8028602a5','題清遠峽峽山寺二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','只道真陽天下稀，不知清遠亦幽奇。',32,'全唐诗/poet.song.140000.json','["只道真陽天下稀，不知清遠亦幽奇。", "攀崖下照龍湫水，細詠東坡老子詩。"]'),
('4693f011-a52d-4c7c-a398-a500e635be35','題清遠峽峽山寺二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','見說巖中雪色猿，嘯聲時出翠微間。',32,'全唐诗/poet.song.140000.json','["見說巖中雪色猿，嘯聲時出翠微間。", "不看新月初三夜，却覓當時舊玉環。"]'),
('faf178b0-5e8b-4679-9e74-6db98e958129','船中蔬飯','楊萬里','宋','宋诗','song-poetry','','[]','食蕨食臂莫食拳，食笋食梢莫食根。',64,'全唐诗/poet.song.140000.json','["食蕨食臂莫食拳，食笋食梢莫食根。", "何曾萬錢方下筯，先生把菜亦飽去。", "嶺南風物似江南，笋如束薪蕨作籃。", "先生食籍知幾卷，千巖萬壑皆厨傳。"]'),
('5206c324-7177-4b7a-9963-6a30b5c1c530','過胥口鎮','楊萬里','宋','宋诗','song-poetry','','[]','桄榔葉垂翠羽鮮，木綿花暖紫霞翻。',32,'全唐诗/poet.song.140000.json','["桄榔葉垂翠羽鮮，木綿花暖紫霞翻。", "疾雷急雨忽開霽，淡白雲拂濃清山。"]'),
('dfda743c-0aa4-4b9f-8b75-ceb5a71495a3','清明日欲宿石門未到而風雨大作泊靈星小海六首  其一','楊萬里','宋','宋诗','song-poetry','','[]','風雨來從海外天，靈星海裏泊樓船。',32,'全唐诗/poet.song.140000.json','["風雨來從海外天，靈星海裏泊樓船。", "坐吟苦句斟愁酒，也是清明過一年。"]'),
('7452f4de-45a9-458b-8a84-32299907f34f','清明日欲宿石門未到而風雨大作泊靈星小海六首  其二','楊萬里','宋','宋诗','song-poetry','','[]','峽山前夕石間行，泊得船時破膽驚。',32,'全唐诗/poet.song.140000.json','["峽山前夕石間行，泊得船時破膽驚。", "驚到今宵已無膽，聽風聽浪到天明。"]'),
('f4cf2230-1d96-4943-9099-3099752360c4','清明日欲宿石門未到而風雨大作泊靈星小海六首  其三','楊萬里','宋','宋诗','song-poetry','','[]','石門欲到更無疑，隔海風濤未可期。',32,'全唐诗/poet.song.140000.json','["石門欲到更無疑，隔海風濤未可期。", "到得石門非不好，只愁未到石門時。"]'),
('bcb67d89-b22a-4f0d-8ddb-b851efccdd15','清明日欲宿石門未到而風雨大作泊靈星小海六首  其四','楊萬里','宋','宋诗','song-poetry','','[]','一生行路竟如何，樂事還稀苦事多。',32,'全唐诗/poet.song.140000.json','["一生行路竟如何，樂事還稀苦事多。", "知是風波欺客子，不知客子犯風波。"]'),
('bc301bdd-5a07-49a3-b7eb-e8d57eb66105','清明日欲宿石門未到而風雨大作泊靈星小海六首  其五','楊萬里','宋','宋诗','song-poetry','','[]','波濤端不爲君休，風雨何曾管客愁。',32,'全唐诗/poet.song.140000.json','["波濤端不爲君休，風雨何曾管客愁。", "自古詩人磨不倒，一樽大笑謝陽侯。"]'),
('1943f65a-f4f3-482e-8b1a-abbcd313c649','清明日欲宿石門未到而風雨大作泊靈星小海六首  其六','楊萬里','宋','宋诗','song-poetry','','[]','石門未到未爲遲，小泊靈星也自奇。',32,'全唐诗/poet.song.140000.json','["石門未到未爲遲，小泊靈星也自奇。", "此去五羊三十里，明朝還有到城時。"]'),
('6714c070-01c9-4206-a418-a13fd1840857','五羊官舍春盡晚步西園荷橋','楊萬里','宋','宋诗','song-poetry','','[]','波底金鴉奪眼明，脚根螮蝀界天橫。',32,'全唐诗/poet.song.140000.json','["波底金鴉奪眼明，脚根螮蝀界天橫。", "瘦藤欲度還休去，試數荷錢幾箇生。"]'),
('b28bfe2f-5b5c-4057-8c86-128c2ec25a06','讀天寶事','楊萬里','宋','宋诗','song-poetry','','[]','日晚無煙起御厨，野人豆飯未嫌粗。',32,'全唐诗/poet.song.140000.json','["日晚無煙起御厨，野人豆飯未嫌粗。", "問知雲子炊香日，政是梨花带雨初。"]'),
('9d740b38-127b-43a6-b347-890c0288b186','西園晚步二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','龍眼初如菉豆肥，荔枝已似佛螺兒。',32,'全唐诗/poet.song.140000.json','["龍眼初如菉豆肥，荔枝已似佛螺兒。", "南荒北客難將息，最是殘春首夏時。"]'),
('91d03290-8348-4b5b-8058-22021fc761f2','西園晚步二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','爲愛荷池日日來，一來一度眼雙開。',32,'全唐诗/poet.song.140000.json','["爲愛荷池日日來，一來一度眼雙開。", "畫船不曉風相戲，猛觸花堤得倒回。"]'),
('09d9b9fc-10dc-4cc4-8dfe-ea57a0b6b436','三月晦日游越王臺二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','榕樹梢頭訪古臺，下看碧海一瓊杯。',32,'全唐诗/poet.song.140000.json','["榕樹梢頭訪古臺，下看碧海一瓊杯。", "越王歌舞春風處，今日春風獨自來。"]'),
('8e7e2ccf-bb0e-4e1e-8512-703fa22a11b3','三月晦日游越王臺二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','越王臺上落花春，一掬山光兩袖塵。',32,'全唐诗/poet.song.140000.json','["越王臺上落花春，一掬山光兩袖塵。", "隨分杯盤隨處醉，自憐不及踏青人。"]'),
('d059db2d-74cf-41fd-9cdd-448b2ff6fa9b','四月八日嘗新荔子','楊萬里','宋','宋诗','song-poetry','','[]','一點臙脂染蔕旁，忽然紅遍綠衣裳。',64,'全唐诗/poet.song.140000.json','["一點臙脂染蔕旁，忽然紅遍綠衣裳。", "紫瓊骨骼丁香瘦，白雪肌膚午暑涼。", "掌上冰丸那忍觸，樽前風味獨難忘。", "老饕要啖三百顆，却怕甘寒凍斷腸。"]'),
('12136e09-131b-41d4-bd58-5abb4261dcce','夏日書事','楊萬里','宋','宋诗','song-poetry','','[]','一字看成兩，霜鬚摘轉多。',48,'全唐诗/poet.song.140000.json','["一字看成兩，霜鬚摘轉多。", "既無書冊分，奈此日長何。", "荔子紅初皺，春醅碧欲波。", "醉來愁自去，不去亦從它。"]'),
('38eb4b18-b33e-416c-b21a-f6f794ee0952','四月中休日聞蟬','楊萬里','宋','宋诗','song-poetry','','[]','荔枝葉底暑陰清，已有新蟬一兩聲。',32,'全唐诗/poet.song.140000.json','["荔枝葉底暑陰清，已有新蟬一兩聲。", "荷露柳風餐未飽，怪來學語不分明。"]'),
('e5a38ad2-b2e2-4e85-bcda-7dc65ebaad7a','觀書','楊萬里','宋','宋诗','song-poetry','','[]','客從遠方至，遺我書一編。',84,'全唐诗/poet.song.140000.json','["客從遠方至，遺我書一編。", "覽舊眼全痛，誦新神頓還。", "初披愁欲盡，久翫翳不妍。", "情知無佳處，閔免復竟篇。", "庶幾槁滓中，或瀝腴一涓。", "終然寂無獲，所獲倦且昏。", "倦甚得佳睡，猶勝不得眠。"]'),
('a6b4c978-1a49-45cc-9509-ed0602ff1d9e','得壽仁壽俊二子中塗家書三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','二子別我歸，兼旬無消息。',120,'全唐诗/poet.song.140000.json','["二子別我歸，兼旬無消息。", "客有饋荔枝，盈籃風露色。", "絳羅蹙寶髻，冰彈濺柘液。", "老夫非不饞，忍饞不忍喫。", "急呼兩健步，爲我致渠側。", "默數川陸程，幾日當返役。", "惟愁香味壞，色變那敢惜。", "十日兩騎還，千里一紙墨。", "把書五行下，廢書雙淚滴。", "不如未到時，當喜翻不懌。"]'),
('78198bde-b43e-41ab-b1d2-99712fea773e','得壽仁壽俊二子中塗家書三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','子壯祇覺幼，子學祇覺遲。',120,'全唐诗/poet.song.140000.json','["子壯祇覺幼，子學祇覺遲。", "二子忽頎然，語離又作悲。", "今年來官下，二子暫我隨。", "懸知住不久，且復相從嬉。", "鶴書自天降，槐花呼汝歸。", "伯也恐我愁，願留不忍辭。", "仲也慘不釋，飛鳴思及時。", "豈有鳳將雛，雛長禁其飛。", "決焉遣還家，一笑更不疑。", "傍人怪無淚，淚入肝與脾。"]'),
('1fba10cf-e766-4bf9-80e8-cbe130cb44f0','得壽仁壽俊二子中塗家書三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','我昔如汝長，壯志在四方。',84,'全唐诗/poet.song.140000.json','["我昔如汝長，壯志在四方。", "集賢給筆札，秉燭促夜裝。", "平明出門去，振衣不徬徨。", "先君泫然泣，感我令我傷。", "先君顧我語，汝行勿斷腸。", "它日汝養子，此悲會身當。", "老懷追陳迹，心折涕泗滂。"]'),
('944c5576-48ea-4201-b033-e668ba0a643e','繙破篋得張欽夫唱和詩','楊萬里','宋','宋诗','song-poetry','','[]','年年不是不吟詩，吟得詩成寄阿誰。',32,'全唐诗/poet.song.140000.json','["年年不是不吟詩，吟得詩成寄阿誰。", "留取朱絃不須斷，只將瑶匣鎖蛛絲。"]'),
('aa7a0081-c79b-4aee-8537-632f51c066e7','休日','楊萬里','宋','宋诗','song-poetry','','[]','休日稀公事，炎天廢故書。',48,'全唐诗/poet.song.140000.json','["休日稀公事，炎天廢故書。", "未須搔白首，留取試新梳。", "不是平生嬾，何緣作計疎。", "閑携小兒女，橋上看芙蕖。"]'),
('0ed09842-8707-48ef-90a4-643242a40697','宴客夜歸六言','楊萬里','宋','宋诗','song-poetry','','[]','月在荔支梢上，人行抹利花間。',28,'全唐诗/poet.song.140000.json','["月在荔支梢上，人行抹利花間。", "但覺胸吞碧海，不知身落南蠻。"]'),
('20987c6c-d414-44b0-abe5-7735917eed90','端午後頓熱','楊萬里','宋','宋诗','song-poetry','','[]','只今新暑已歊然，作麽禁當六月天。',32,'全唐诗/poet.song.140000.json','["只今新暑已歊然，作麽禁當六月天。", "飛上風前最涼處，年年輸與柳梢蟬。"]'),
('670c5160-9baa-4fd2-a3fa-fa7670b9af73','夏至後初暑登連天觀','楊萬里','宋','宋诗','song-poetry','','[]','登臺長早下臺遲，移遍胡牀無處移。',32,'全唐诗/poet.song.140000.json','["登臺長早下臺遲，移遍胡牀無處移。", "不是清涼罷揮扇，自緣手倦歇些時。"]'),
('c2200eda-4c86-41a9-b19e-d0ce395c79bd','六月九日曉登連天觀','楊萬里','宋','宋诗','song-poetry','','[]','小立層臺岸幅巾，除鶑作伴更無人。',32,'全唐诗/poet.song.140000.json','["小立層臺岸幅巾，除鶑作伴更無人。", "曉風草草君知麽，不爲高荷惜水銀。"]'),
('3ffed2ed-9580-46a0-a065-4468a47f2f9c','七夕新凉','楊萬里','宋','宋诗','song-poetry','','[]','商量秋思是寒螿，將息荷花得早涼。',32,'全唐诗/poet.song.140000.json','["商量秋思是寒螿，將息荷花得早涼。", "五嶺從來說炎熱，朝來已怯葛衣裳。"]'),
('aced812f-2856-4311-9263-12549c202c07','雨霽登連天觀','楊萬里','宋','宋诗','song-poetry','','[]','高臺十日不曾登，雨後搘藤拄晚晴。',64,'全唐诗/poet.song.140000.json','["高臺十日不曾登，雨後搘藤拄晚晴。", "城外諸峰迎落照，松根細草總斜明。", "眼穿嶺北書不到，秋入海南愁頓生。", "只有荷花舊相識，風前翠蓋爲人傾。"]'),
('98d785fd-3123-476b-a921-1326d32392a9','秋夕雨餘','楊萬里','宋','宋诗','song-poetry','','[]','虛堂無人獨自行，畫簷雨歇殘點聲。',112,'全唐诗/poet.song.140000.json','["虛堂無人獨自行，畫簷雨歇殘點聲。", "朝來餘暑忽然過，昨來初暑誰能那。", "一生畏暑如於菟，老年畏暑菟不如。", "人言嶺南分外熱，匹似江南猶可說。", "今年六月雨如秋，只今七月當更愁。", "短檠幸未卧牆角，喚取渠來相博約。", "老眼那能舒簡編，只要玉蟲伴杯酌。"]'),
('cbaf227b-dcee-44df-a378-c75449883f0a','游蒲澗呈周帥蔡漕張舶','楊萬里','宋','宋诗','song-poetry','','[]','勝日從公蒲澗游，萬壑聲滿千崖秋。',265,'全唐诗/poet.song.140000.json','["勝日從公蒲澗游，萬壑聲滿千崖秋。", "一逕如蛇三百曲，繞盡山腹到山頭。", "穹巖千仞欹欲裂，仰看飛泉瀉雲窟。", "鏘成環佩奏成琴，濺作珠璣霏作雪。", "步穿危磴攀蒼藤，忽上穹巖頂上行。", "人在半天泉在井，不敢下瞰惟聞聲。", "只怪前驅深不見，須臾却向前山轉。", "海風吹袖萬丈長，海水去人一弓遠。", "老僧雲卧晏未興，先遣長松夾道迎。", "小參古殿黄面老，不見舊日安期生。", "景泰上方半堵壁，城中望之雪山白。", "却從景泰望城中，曉日樓臺煥金碧。", "君不見中流千金博一壺，不如游山饑時粥一盂。", "金印繫肘大如斗，不如游山倦時一杯酒。", "安期飛昇今幾年，祖龍不是不求仙。", "至今年年七月二十五，傾城游人來訪古。"]'),
('f35b0181-7d9d-4a56-abbf-cf24fabe00d9','得壽仁壽俊二子書皆以病不及就試且報來期二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','二子何時到，三秋欲盡頭。',48,'全唐诗/poet.song.140000.json','["二子何時到，三秋欲盡頭。", "收渠半張紙，洗我一年愁。", "不得毛錐力，元非子墨羞。", "海山寒更碧，整駕待同游。"]'),
('ead2b724-e711-4c22-98e7-0b3562d9b960','得壽仁壽俊二子書皆以病不及就試且報來期二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','滿望鵬飛上，誰令馬不前。',48,'全唐诗/poet.song.140000.json','["滿望鵬飛上，誰令馬不前。", "草玄真浪苦，曳白亦無緣。", "兄弟年二十，塵埃路四千。", "速來飲官酒，不用一銅錢。"]'),
('7a510b57-d96d-4e44-8d6b-d44ccfaa3f5c','送蔡定夫赴湖南提刑二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','菊後霜前換繡衣，湘南嶺北看梅枝。',64,'全唐诗/poet.song.140000.json','["菊後霜前換繡衣，湘南嶺北看梅枝。", "還將方策汗青語，拈出圜扉草綠時。", "四海幾人憐我老，三年兩作送君詩。", "借令貴殺衡陽紙，半幅無妨慰夢思。"]'),
('cca88120-95a0-4c18-8281-ee4f62a9efcb','送蔡定夫赴湖南提刑二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','方丈蓬萊第一人，星軺玉節正青春。',64,'全唐诗/poet.song.140000.json','["方丈蓬萊第一人，星軺玉節正青春。", "只今回雁峰頭客，曾觸神龍頷下鱗。", "未遣五紋朝補衮，便應三字夜司綸。", "湘江綠浄不可唾，却要珠璣欬唾新。"]'),
('527db7c5-13ef-499a-9995-14d393218389','和石湖居士范至能與周子充夜游石湖松江詩韻','楊萬里','宋','宋诗','song-poetry','','[]','石湖醉眼小太空，烏紗白紵雙鬢蓬。',128,'全唐诗/poet.song.140000.json','["石湖醉眼小太空，烏紗白紵雙鬢蓬。", "翰林來從昭回上，滿袖天香山水中。", "青山半邊日欲沒，珠宮湧出初圜月。", "兩仙一棹軟琉璃，碎撼廣寒桂花雪。", "中流浪作凜不回，兩手播灑千銀堆。", "不知浩浩洪流後，曾有茲遊奇特來。", "古人今人煙一抹，誰煎麟角續弦絕。", "一生句裏萬斛愁，只白秋來千丈髮。"]'),
('6f6a7f40-9015-4c8a-a8a6-93bfcce215bf','遣騎問訊范明州參政報章寄二絕句和韻謝之  其一','楊萬里','宋','宋诗','song-poetry','','[]','南海人從東海歸，新詩到日恰梅時。',32,'全唐诗/poet.song.140000.json','["南海人從東海歸，新詩到日恰梅時。", "撚梅細比新詩看，未必梅花瘦似詩。"]'),
('9650ac70-e216-48a5-8524-4f8d0511f6bf','遣騎問訊范明州參政報章寄二絕句和韻謝之  其二','楊萬里','宋','宋诗','song-poetry','','[]','一別姑蘇江上臺，綠波碧草恨悠哉。',32,'全唐诗/poet.song.140000.json','["一別姑蘇江上臺，綠波碧草恨悠哉。", "忽然兩袖珠璣滿，割取三吳風月來。"]'),
('481cc231-0619-4428-8019-165ef0ca216f','至日薄寒','楊萬里','宋','宋诗','song-poetry','','[]','舊傳冬不到南中，今歲南中稍稍冬。',64,'全唐诗/poet.song.140000.json','["舊傳冬不到南中，今歲南中稍稍冬。", "曦幕暖吹紅皺起，霜橋冷步縞聲鬆。", "裁縫苦思詩千首，排遣清愁酒一鍾。", "不是梅花開獨早，似憐北客老相逢。"]'),
('b37369c2-6580-471d-b764-ab64add0987e','晚登連天觀望越臺山','楊萬里','宋','宋诗','song-poetry','','[]','暮山如淡復如濃，煙拂山前一兩重。',32,'全唐诗/poet.song.140000.json','["暮山如淡復如濃，煙拂山前一兩重。", "山背更將霞萬疋，生紅錦障裹青峰。"]'),
('d6cdcb90-2f13-47c0-a4b2-6f2781b65060','近臘暄甚','楊萬里','宋','宋诗','song-poetry','','[]','霜日知春有信歸，臘前偷暖漏春暉。',32,'全唐诗/poet.song.140000.json','["霜日知春有信歸，臘前偷暖漏春暉。", "北風也翦寒梢葉，吹作鵝黄亂蝶飛。"]'),
('a6eb7f25-e8bc-47ab-96d1-5e298f23c309','西園早梅二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','已刻酥花趁臘前，更團蠟糝等春妍。',32,'全唐诗/poet.song.140000.json','["已刻酥花趁臘前，更團蠟糝等春妍。", "不知天巧能多少，一朶梅花占兩年。"]'),
('80d23466-2d46-43cc-a049-0daea744cef4','西園早梅二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','小朶生來便瘦斜，蕊宮桂殿即渠家。',32,'全唐诗/poet.song.140000.json','["小朶生來便瘦斜，蕊宮桂殿即渠家。", "只言瘴雨無南雪，爲底橫枝雪作花。"]'),
('978ba5fc-a104-4fae-8210-43b9bc77f608','病中夜坐','楊萬里','宋','宋诗','song-poetry','','[]','月流銀漢小徘徊，似戀空庭獨樹梅。',64,'全唐诗/poet.song.140000.json','["月流銀漢小徘徊，似戀空庭獨樹梅。", "玉漏聽來更二點，燭花翦了暈重開。", "病身不飲看人醉，乾雪無端上鬢來。", "後日老衰知健否，只今六九已摧隤。"]'),
('6041952b-6eeb-45d2-9454-a177ccd2b11e','辛丑正月二十五日遊蒲澗晚歸','楊萬里','宋','宋诗','song-poetry','','[]','桃李深酣日，池塘淺試春。',48,'全唐诗/poet.song.140000.json','["桃李深酣日，池塘淺試春。", "霽暉摇遠水，新暖軟遊人。", "生酒清無色，青梅脆有仁。", "煙鐘能底急，催我入城闉。"]'),
('da4bdbb9-1133-4742-affb-e73e9ce9ba9b','二月一日雨寒五首  其一','楊萬里','宋','宋诗','song-poetry','','[]','南方氣候北方殊，春裏清寒臘裏無。',32,'全唐诗/poet.song.140000.json','["南方氣候北方殊，春裏清寒臘裏無。", "雨入竹林渾不見，只來葉尾作真珠。"]'),
('9af2e762-ec83-4c39-a5b5-c5cd2077b2a7','二月一日雨寒五首  其二','楊萬里','宋','宋诗','song-poetry','','[]','補盡窗櫺閉盡門，茶甌火閣對爐熏。',32,'全唐诗/poet.song.140000.json','["補盡窗櫺閉盡門，茶甌火閣對爐熏。", "中庭淺水休教掃，政要留看雨點紋。"]'),
('5976a25a-0da4-497c-9252-cc83c3efb467','二月一日雨寒五首  其三','楊萬里','宋','宋诗','song-poetry','','[]','梳頭正美睡相催，理盡霜絲夢恰回。',32,'全唐诗/poet.song.140000.json','["梳頭正美睡相催，理盡霜絲夢恰回。", "窗隙小風能幾許，也吹蛛網去還來。"]'),
('a68093a7-2865-4346-96fc-6e69d2811b08','二月一日雨寒五首  其四','楊萬里','宋','宋诗','song-poetry','','[]','姚黄魏紫向誰賒，郁李櫻桃也沒些。',32,'全唐诗/poet.song.140000.json','["姚黄魏紫向誰賒，郁李櫻桃也沒些。", "却是南中春色別，滿城都是木綿花。"]'),
('0eabeaf9-aecb-4c4d-ab0a-38a77b72f62d','二月一日雨寒五首  其五','楊萬里','宋','宋诗','song-poetry','','[]','只見春晴道是晴，不知半夜嫩寒生。',32,'全唐诗/poet.song.140000.json','["只見春晴道是晴，不知半夜嫩寒生。", "疾風吹落林間雨，細雨還成大雨聲。"]'),
('b3653390-80da-42ac-897f-fa4077c9de5b','謝福建茶使吳德華送東坡新集','楊萬里','宋','宋诗','song-poetry','','[]','黄金白璧明月珠，清歌妙舞傾城姝。',304,'全唐诗/poet.song.140000.json','["黄金白璧明月珠，清歌妙舞傾城姝。", "他家都有儂家無，却有四壁環相如。", "此外更有一床書，不堪自飽飽蠹魚。", "故人遠送東坡集，舊書避席皆讓渠。", "兒時作劇百不嬾，說著讀書偏起晚。", "乃翁作惡嗔兒癡，强遣饑腸饞蠹簡。", "老來萬事落人後，浪取故書遮病眼。", "病眼逢書輒著花，筆下蠅頭成老鴉。", "病眼將奈故書何，故書一開一長嗟。", "東坡文集儂亦有，未及終篇已停手。", "印墨模糊紙不佳，亦非魚網非科斗。", "富沙棗木新雕文，傳刻疎瘦不失真。", "紙如雪繭出玉盆，字如霜雁點秋雲。", "老來兩眼如隔霧，逢柳逢花不曾覷。", "只逢書冊佳且新，把翫崇朝那肯去。", "東坡癡絕過於儂，不將一褐易三公。", "只將筆頭挂月脇，萬古凡馬不足空。", "故人憐我老愈拙，不寄金丹扶病骨。", "却寄此書來惱人，挑落青燈搔白髮。"]'),
('f2f975ff-4126-4a0f-88f2-26f8344bb099','新晴西園散步四首  其一','楊萬里','宋','宋诗','song-poetry','','[]','久雨令人不出門，新晴喚我到西園。',32,'全唐诗/poet.song.140000.json','["久雨令人不出門，新晴喚我到西園。", "要知春事深和淺，試看青梅大幾分。"]'),
('50b92b00-161f-4b71-aa7a-c7549e3f4d3c','新晴西園散步四首  其二','楊萬里','宋','宋诗','song-poetry','','[]','池水初生蓋玉沙，雨餘碧草卧堤斜。',32,'全唐诗/poet.song.140000.json','["池水初生蓋玉沙，雨餘碧草卧堤斜。", "日摇波影纏橋柱，繡出欒枝遍地花。"]'),
('40f1dfee-ed7c-4d60-a310-5c1e1d756c77','新晴西園散步四首  其三','楊萬里','宋','宋诗','song-poetry','','[]','紅雨斑斑竹外蹊，黄金嫋嫋水邊絲。',32,'全唐诗/poet.song.140000.json','["紅雨斑斑竹外蹊，黄金嫋嫋水邊絲。", "舉頭揀遍低陰處，带葉青梅摘一枝。"]'),
('d59ee056-e018-483a-be72-6afe41d3129a','新晴西園散步四首  其四','楊萬里','宋','宋诗','song-poetry','','[]','厭見山居要出來，出來厭了却思回。',32,'全唐诗/poet.song.140000.json','["厭見山居要出來，出來厭了却思回。", "人生畢竟如何是，且看桃花晚莟開。"]'),
('f8e2f608-3f3a-49e5-81f1-9db5cc4af287','連天觀望春憶毗陵翟園','楊萬里','宋','宋诗','song-poetry','','[]','中和節後社前時，春到園林最晚枝。',64,'全唐诗/poet.song.140000.json','["中和節後社前時，春到園林最晚枝。", "弄水不冰携扇手，登臺猶粟向風肌。", "鳥烏聲裏山光濕，花柳陰中日脚遲。", "北望翟園春正閙，海棠錦繞雪酴醾。"]'),
('25008fb5-0a9d-418b-8518-f41954a428e5','二月將半寒暄不常','楊萬里','宋','宋诗','song-poetry','','[]','南中冷暖直難齊，一日之間具四時。',32,'全唐诗/poet.song.140000.json','["南中冷暖直難齊，一日之間具四時。", "脫了又添添又脫，寒衣暑服鎮相隨。"]'),
('4350b3d4-cd32-41ff-983b-06f1c688d698','二月十三日謁西廟早起','楊萬里','宋','宋诗','song-poetry','','[]','起來洗面更焚香，粥罷東窗未肯光。',64,'全唐诗/poet.song.140000.json','["起來洗面更焚香，粥罷東窗未肯光。", "古語舊傳春夜短，漏聲新覺五更長。", "近來事事都無味，老去波波有底忙。", "還憶山居桃李曉，酴醾爲枕睡爲鄉。"]'),
('d2288a3b-2fee-4ab5-9c6f-e3e2739c0a77','寄題蕭國賢佚我堂','楊萬里','宋','宋诗','song-poetry','','[]','軟紅塵裏幾時休，重碧杯中且拍浮。',64,'全唐诗/poet.song.140000.json','["軟紅塵裏幾時休，重碧杯中且拍浮。", "坐看癡兒夸絕足，可憐到老不回頭。", "幅巾藜杖聊三徑，明月清風自一丘。", "我亦年來厭奔走，夢騎野鶴訪沙鷗。"]'),
('0ef1b088-4ef5-423c-88f6-56a2e7d0eeff','題桄榔樹','楊萬里','宋','宋诗','song-poetry','','[]','化工到得巧窮時，東補西移也大奇。',32,'全唐诗/poet.song.140000.json','["化工到得巧窮時，東補西移也大奇。", "君看桄榔一窠子，竹身杏葉海棕枝。"]'),
('9a3d5f16-5aa4-4102-b641-c95281de3eb1','春晴懷故園海棠二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','故園今日海棠開，夢入江西錦繡堆。',64,'全唐诗/poet.song.140000.json','["故園今日海棠開，夢入江西錦繡堆。", "萬物皆春人獨老，一年過社燕方回。", "似青如白天濃淡，欲墮還飛絮往來。", "無那風光餐不得，遣詩招入翠瓊杯。"]'),
('ab43e50f-dffe-40c5-a0f4-bd9255808cf9','春晴懷故園海棠二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','竹邊臺榭水邊亭，不要人隨只獨行。',64,'全唐诗/poet.song.140000.json','["竹邊臺榭水邊亭，不要人隨只獨行。", "乍暖柳條無氣力，淡晴花影不分明。", "一番過雨來幽徑，無數新禽有喜聲。", "只欠翠紗紅映肉，兩年寒食負先生。"]'),
('47bee5d2-0c94-47fa-b7d1-4d8c8ca565e7','初食笋蕨','楊萬里','宋','宋诗','song-poetry','','[]','庖鳳烹龍世浪傳，猩脣熊掌我無緣。',64,'全唐诗/poet.song.140000.json','["庖鳳烹龍世浪傳，猩脣熊掌我無緣。", "只逢笋蕨杯盤日，便是山林富貴天。", "穉子玉膚新脫錦，小兒紫臂未開拳。", "只嫌嶺外無珍饌，一味春蔬不直錢。"]'),
('df6e72c4-2609-4194-b481-2d8b02134aa0','上巳前一日欲雨復晴','楊萬里','宋','宋诗','song-poetry','','[]','去年上巳政南來，明日初三忽又催。',64,'全唐诗/poet.song.140000.json','["去年上巳政南來，明日初三忽又催。", "雨壓雲頭渾欲落，風翻日脚急吹開。", "莫因嶺外無花卉，便對春光廢酒杯。", "只揀茂林脩竹處，蘭亭禊事足追回。"]'),
('adcf8556-ac56-4d9e-81eb-c6b9b378b6c3','寒食對酒','楊萬里','宋','宋诗','song-poetry','','[]','荔支園園花，寒食日日雨。',132,'全唐诗/poet.song.140000.json','["荔支園園花，寒食日日雨。", "先生老多病，頗已疎綠醑。", "兒童喜時節，笑語治樽俎。", "南烹俱前陳，北果亦草具。", "蝤蛑方絕甘，笋蕨未作苦。", "先生欲獨醒，兒意難多拒。", "初心且一杯，三杯亦漫許。", "醒時本强飲，醉後忽快舉。", "一杯至三杯，一二三四五。", "偶然問兒輩，卒爵是何處。", "兒言翁但醉，已忘酒巡數。"]'),
('076e947d-f34a-4d42-b893-77d4912e7213','三月晦日閑步西園','楊萬里','宋','宋诗','song-poetry','','[]','嶺南春去儘從伊，元自無花可得飛。',32,'全唐诗/poet.song.140000.json','["嶺南春去儘從伊，元自無花可得飛。", "只有草花偏稱意，强留蝴蝶不教歸。"]'),
('1474e3c1-867d-4659-9d6f-620338d7538f','閏三月二日發船廣州來歸亭下之官憲臺','楊萬里','宋','宋诗','song-poetry','','[]','詩人政坐愛閑遊，天遣南游天盡頭。',32,'全唐诗/poet.song.140000.json','["詩人政坐愛閑遊，天遣南游天盡頭。", "到得廣州天盡處，方教回首向韶州。"]'),
('2f5af953-8481-41ff-add1-604a0845557f','曉過石門回望浄慧塔','楊萬里','宋','宋诗','song-poetry','','[]','昨晚匆匆解畫船，石門未到已黄昏。',32,'全唐诗/poet.song.140000.json','["昨晚匆匆解畫船，石門未到已黄昏。", "殷勤浄慧煙中塔，送我今朝過石門。"]'),
('903cf3bf-e212-43d8-8352-e6171c763fc9','舟行得風晚至靈洲','楊萬里','宋','宋诗','song-poetry','','[]','春盡儂隨去，江行興未窮。',48,'全唐诗/poet.song.140000.json','["春盡儂隨去，江行興未窮。", "時煩數點雨，輕洒一孤篷。", "岸樹蒼茫外，人家點綴中。", "海神能餞我，借與半帆風。"]'),
('14e733f6-a0df-4652-829c-495e8653de83','明發青塘蘆包','楊萬里','宋','宋诗','song-poetry','','[]','青塘無店亦無人，只有青蛙紫蚓聲。',64,'全唐诗/poet.song.140000.json','["青塘無店亦無人，只有青蛙紫蚓聲。", "蘆荻葉深蒲葉淺，荔支花暗楝花明。", "船行兩岸山都動，水入諸村海旋成。", "回望越臺煙雨外，萬峰盡處五羊城。"]'),
('26ba10ba-1d35-40d8-9883-bcc0ac0c168e','過胥口江水大漲舟楫不進','楊萬里','宋','宋诗','song-poetry','','[]','北江西水兩相逢，胥口波濤特地雄。',64,'全唐诗/poet.song.140000.json','["北江西水兩相逢，胥口波濤特地雄。", "萬事向儂冰與炭，一生行役雨和風。", "急流欲上人聲閙，近岸還移牽路窮。", "河伯喜歡儂苦惱，併將恩怨惱天公。"]'),
('4fd93e11-c947-422b-9759-a623495b8d23','岸沙','楊萬里','宋','宋诗','song-poetry','','[]','水嫌岸窄要衝開，細蕩沙痕似翦裁。',32,'全唐诗/poet.song.140000.json','["水嫌岸窄要衝開，細蕩沙痕似翦裁。", "蕩去蕩來元不覺，忽然一片岸沙摧。"]'),
('e1802872-86e1-4443-9af3-32334523f5e2','遣悶','楊萬里','宋','宋诗','song-poetry','','[]','江樹深春色，村雞薄晚聲。',48,'全唐诗/poet.song.140000.json','["江樹深春色，村雞薄晚聲。", "雨添青笠重，人減畫船輕。", "遣悶惟須睡，哦詩只强成。", "獨判連日雨，却惜半朝晴。"]'),
('55f91925-32c1-418c-9207-d20852cde766','曉發黄巢磯芭蕉林中','楊萬里','宋','宋诗','song-poetry','','[]','清遠山前煙雨濛，黄巢磯畔水連空。',32,'全唐诗/poet.song.140000.json','["清遠山前煙雨濛，黄巢磯畔水連空。", "旋芟蘆荻炊朝飯，更斫芭蕉補漏篷。"]'),
('e592e9d0-544e-408d-8b0a-48f76843b86d','水落二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','桑椹垂紅似荔支，荻芽如臂與人齊。',32,'全唐诗/poet.song.140000.json','["桑椹垂紅似荔支，荻芽如臂與人齊。", "夜來水落知深淺，看取芭蕉五尺泥。"]'),
('733984ef-eebb-4695-b3a5-415bc43f7bd1','水落二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','輕寒瑟瑟入船中，閉却船門下却篷。',32,'全唐诗/poet.song.140000.json','["輕寒瑟瑟入船中，閉却船門下却篷。", "要得新晴江水落，不應更恨打頭風。"]'),
('e30b399d-6a99-4a1c-a5c4-ab2f12a3c58d','蜑戶','楊萬里','宋','宋诗','song-poetry','','[]','天公分付水生涯，從小教它踏浪花。',64,'全唐诗/poet.song.140000.json','["天公分付水生涯，從小教它踏浪花。", "煮蟹當糧那識米，緝蕉爲布不須紗。", "夜來春漲吞沙觜，急遣兒童斸荻芽。", "自笑平生老行路，銀山堆裏正浮家。"]'),
('b1401d97-446e-4f22-ac22-4439dbef1fee','回望黄巢磯之險心悸久之','楊萬里','宋','宋诗','song-poetry','','[]','夜雲到曉不教收，初日微明又却休。',64,'全唐诗/poet.song.140000.json','["夜雲到曉不教收，初日微明又却休。", "雨爲岸花新洗面，水撩江草只摇頭。", "千篙百棹力都竭，十里九磯船正愁。", "若到峽中應更險，却思峽外是安流。"]'),
('76aa8240-63e7-4d4f-b090-615ae267e4a5','入峽歌','楊萬里','宋','宋诗','song-poetry','','[]','峽山未到日日愁，峽山已到愁却休。',112,'全唐诗/poet.song.140000.json','["峽山未到日日愁，峽山已到愁却休。", "不是朝來愁便散，愁殺人來山不管。", "昨宵遠望最高尖，今朝近看雲隔簾。", "樓船衝雨過山下，兩扇屏風生色畫。", "江神不遣客心驚，雲去雲來遮巖扃。", "忽然褰雲露山脚，仰見千丈翠玉削。", "篙師相賀漲痕落，今夕可到鴉磯泊。"]'),
('c24c3ca4-9216-4de7-a15a-856849a182a0','峽山寺竹枝詞五首  其一','楊萬里','宋','宋诗','song-poetry','','[]','峽裏撐船更不行，櫂郎相語改行程。',32,'全唐诗/poet.song.140000.json','["峽裏撐船更不行，櫂郎相語改行程。", "却從西岸拋東岸，依舊船頭不可撐。"]'),
('32f2dc8c-7539-4886-be43-52f5cb9a00df','峽山寺竹枝詞五首  其二','楊萬里','宋','宋诗','song-poetry','','[]','一水雙崖千萬縈，有天無地只心驚。',32,'全唐诗/poet.song.140000.json','["一水雙崖千萬縈，有天無地只心驚。", "無人打殺杜鵑子，雨外飛來頭上聲。"]'),
('f6ed750d-b308-4dea-b4da-d8353c53bb86','峽山寺竹枝詞五首  其三','楊萬里','宋','宋诗','song-poetry','','[]','龜魚到此總回頭，不但龜魚蟹亦愁。',32,'全唐诗/poet.song.140000.json','["龜魚到此總回頭，不但龜魚蟹亦愁。", "底事詩人輕老命，犯灘衝石去韶州。"]'),
('f6566f67-115a-481f-9a56-cc3f6beb3e07','峽山寺竹枝詞五首  其四','楊萬里','宋','宋诗','song-poetry','','[]','一灘過了一灘奔，一石橫來一石蹲。',32,'全唐诗/poet.song.140000.json','["一灘過了一灘奔，一石橫來一石蹲。", "若怨古來天設險，峽山不到也由君。"]'),
('ea6d243d-f901-418c-aa73-47093a273c9d','峽山寺竹枝詞五首  其五','楊萬里','宋','宋诗','song-poetry','','[]','天齊浪自說浯溪，峽與天齊真箇齊。',32,'全唐诗/poet.song.140000.json','["天齊浪自說浯溪，峽與天齊真箇齊。", "未必峽山高爾許，看來只恐是天低。"]'),
('73665451-f02c-42db-a270-a71967d1349b','峽中得風掛帆','楊萬里','宋','宋诗','song-poetry','','[]','樓船上水不寸步，兩山慘慘愁將暮。',80,'全唐诗/poet.song.140000.json','["樓船上水不寸步，兩山慘慘愁將暮。", "一聲霹靂天欲雨，隔江草樹忽起舞。", "風從海南天外來，怒吹峽山山倒開。", "百夫絕叫椎大鼓，一夫飛上千尺桅。", "布帆掛了却袖手，坐看水上鵝毛走。"]'),
('04b8576a-adbe-4c7f-baaf-305cc642703c','夜泊鴉磯','楊萬里','宋','宋诗','song-poetry','','[]','峽中盡日沒人煙，船泊鴉磯也有村。',32,'全唐诗/poet.song.140000.json','["峽中盡日沒人煙，船泊鴉磯也有村。", "已被子規酸骨死，今宵第一莫啼猿。"]'),
('c008e2ca-02dc-4e5c-9c60-d5bc6dfa5fc7','過顯濟廟前石磯竹枝詞二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','石磯作意惱舟人，束起波濤遣怒奔。',32,'全唐诗/poet.song.140000.json','["石磯作意惱舟人，束起波濤遣怒奔。", "撐折萬篙渾不枉，石磯贏得萬餘痕。"]'),
('d55b2d6d-5d02-46ba-80cc-79ef9c6c19fb','過顯濟廟前石磯竹枝詞二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','大磯愁似小磯愁，篙稍寬時船即流。',32,'全唐诗/poet.song.140000.json','["大磯愁似小磯愁，篙稍寬時船即流。", "撐得篙頭都是血，一磯又復在前頭。"]'),
('52a273ef-c107-4eb3-afe3-b5394426bce8','泊光口','楊萬里','宋','宋诗','song-poetry','','[]','風平浪靜不生紋，水面渾如鏡面新。',32,'全唐诗/poet.song.140000.json','["風平浪靜不生紋，水面渾如鏡面新。", "忽有暗流江底出，衮翻水面作車輪。"]'),
('3908f5f6-70a1-4af2-bbda-bd1a0c854a37','過虎頭磯','楊萬里','宋','宋诗','song-poetry','','[]','虎卧中流扼兩涯，目光鬚怒首仍回。',32,'全唐诗/poet.song.140000.json','["虎卧中流扼兩涯，目光鬚怒首仍回。", "真陽峽裏君須記，箇是瞿塘灧澦堆。"]'),
('46f073c9-72c7-4685-9b8d-2c5878c60770','真陽峽','楊萬里','宋','宋诗','song-poetry','','[]','清遠雖佳未足觀，真陽佳絕冠南蠻。',64,'全唐诗/poet.song.140000.json','["清遠雖佳未足觀，真陽佳絕冠南蠻。", "一泉嶺背懸崖出，亂灑江邊怪石間。", "夾岸對排雙玉筍，此峰外面萬青山。", "險艱去處多奇觀，自古何人愛險艱。"]'),
('7f2c2700-33a5-4e30-aa61-4da0de15dd8a','夜泊英州','楊萬里','宋','宋诗','song-poetry','','[]','旅病情先惡，愁眠夢更驚。',48,'全唐诗/poet.song.140000.json','["旅病情先惡，愁眠夢更驚。", "犬須終夕吠，月到五更明。", "未解波頭意，偏來枕底聲。", "平生厭行路，投老正追程。"]'),
('47fb07c2-1d58-419d-8bac-1ab398d62859','阻風鍾家村觀岸傍物化二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','水蟲纔出綠波來，細看爬沙上石崖。',32,'全唐诗/poet.song.140000.json','["水蟲纔出綠波來，細看爬沙上石崖。", "化作蜻蜓忽飛去，幾時飛去却飛回。"]'),
('38e73b34-d094-410b-95af-e9dfd432375c','阻風鍾家村觀岸傍物化二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','殻如蟬蛻濕仍新，那復浮嬉浪底春。',32,'全唐诗/poet.song.140000.json','["殻如蟬蛻濕仍新，那復浮嬉浪底春。", "却把今身飛照水，不知石上是前身。"]'),
('7a11c738-7063-464c-8460-d3c7e4ea5df1','題鍾家村石崖二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','莫愛懸崖萬丈高，只工險峭作風濤。',32,'全唐诗/poet.song.140000.json','["莫愛懸崖萬丈高，只工險峭作風濤。", "看來一一生窠眼，解與行人著過篙。"]'),
('12560e59-055a-43c2-93a8-a587b067cebf','題鍾家村石崖二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','水與高崖有底冤，相逢不得鎮相喧。',32,'全唐诗/poet.song.140000.json','["水與高崖有底冤，相逢不得鎮相喧。", "若教漁父頭無笠，只著蓑衣便是猿。"]'),
('b3faba58-5059-4727-be4d-c153e75a9f83','阻風泊鍾家村離英州已三日纔行二十里二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','南游端爲看山來，過眼匆匆首屢回。',32,'全唐诗/poet.song.140000.json','["南游端爲看山來，過眼匆匆首屢回。", "不是阻風船不進，何緣看盡萬崔嵬。"]'),
('6bfde65f-ae57-4a8f-99c7-b99fb2c002ac','阻風泊鍾家村離英州已三日纔行二十里二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','滿船兒女厭江行，我愛江行怕入城。',32,'全唐诗/poet.song.140000.json','["滿船兒女厭江行，我愛江行怕入城。", "慚愧風師教款曲，爲分一舍作三程。"]'),
('a792fe7a-3fe3-49c8-97d9-fccd52433acd','檄風伯','楊萬里','宋','宋诗','song-poetry','','[]','峭壁呀呀虎擘口，惡灘洶洶雷出吼。',64,'全唐诗/poet.song.140000.json','["峭壁呀呀虎擘口，惡灘洶洶雷出吼。", "泝流更著打頭風，如撐鐵船上牛斗。", "風伯勸爾一杯酒，何須惡劇驚詩叟。", "端能爲我霽威否，岸柳掉頭荻摇手。"]'),
('50b0c814-6880-418e-94ce-b0e002e3e205','嶺雲','楊萬里','宋','宋诗','song-poetry','','[]','好山幸自綠嶄嶄，須把輕雲護淺嵐。',32,'全唐诗/poet.song.140000.json','["好山幸自綠嶄嶄，須把輕雲護淺嵐。", "天女似憐山骨瘦，爲縫霧縠作春衫。"]'),
('9fb97b56-6457-4dff-8331-bc825caaaaa2','病中止酒二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','葛衣著了却生寒，風勢顛時正上灘。',32,'全唐诗/poet.song.140000.json','["葛衣著了却生寒，風勢顛時正上灘。", "客裏無聊已無奈，更教止酒過春殘。"]'),
('f8d2dbc9-95fa-4a91-9523-990ca1298afe','病中止酒二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','江草江花怨阿誰，山風山雨總成悲。',32,'全唐诗/poet.song.140000.json','["江草江花怨阿誰，山風山雨總成悲。", "春愁萬斛無安頓，旋旋分張乞小詩。"]'),
('9951c4ff-7cab-4ae9-88c3-891e0885e580','明發陳公徑過摩舍那灘石峰下十首  其一','楊萬里','宋','宋诗','song-poetry','','[]','遥松煙未銷，近竹露猶滴。',48,'全唐诗/poet.song.140000.json','["遥松煙未銷，近竹露猶滴。", "石峰矜孤銳，喜以江自隔。", "清潭涵曦紫，碧岫過雲白。", "回瞻宿處堤，路轉不可覓。"]'),
('e94bc2a0-00a6-4f22-937d-f985448ba5a9','明發陳公徑過摩舍那灘石峰下十首  其二','楊萬里','宋','宋诗','song-poetry','','[]','地迥人絕影，山僻虎留跡。',60,'全唐诗/poet.song.140000.json','["地迥人絕影，山僻虎留跡。", "下有無底潭，上有欲落石。", "是間一逕橫，夾以萬松直。", "樹從何時有，陳公所手植。", "陳公今焉在，逕松自寒碧。"]'),
('d3dfba23-eb6a-4262-8cca-3a72dce7b06b','明發陳公徑過摩舍那灘石峰下十首  其三','楊萬里','宋','宋诗','song-poetry','','[]','昨宵望石峰，相去無一尺。',60,'全唐诗/poet.song.140000.json','["昨宵望石峰，相去無一尺。", "今日行終朝，祇遶石峰側。", "石峰何曾遠，江路自不直。", "仰瞻碧孱顔，清峻如立壁。", "反覆得細看，何必更登陟。"]'),
('c8311b38-82ee-49ff-93c7-24c93881f0db','明發陳公徑過摩舍那灘石峰下十首  其四','楊萬里','宋','宋诗','song-poetry','','[]','後顧江已遠，前睨山若塞。',60,'全唐诗/poet.song.140000.json','["後顧江已遠，前睨山若塞。", "棹進岸自回，天水未有極。", "簾欣入絕巘，舟愕觸潜石。", "東暾澹未熹，北吹寒更寂。", "岸草不知愁，向人弄晴碧。"]'),
('75222173-bf8d-4361-9742-5053d3eb3f54','明發陳公徑過摩舍那灘石峰下十首  其五','楊萬里','宋','宋诗','song-poetry','','[]','澄潭湧暗暈，不風自成花。',48,'全唐诗/poet.song.140000.json','["澄潭湧暗暈，不風自成花。", "回流如倦客，出門復還家。", "江晴已數日，新漲沒舊沙。", "知是前溪雨，濕雲尚橫斜。"]'),
('667b4e0f-6174-4a9c-9f1d-ebc3ad7e7534','明發陳公徑過摩舍那灘石峰下十首  其六','楊萬里','宋','宋诗','song-poetry','','[]','山轉江亦轉，江行山亦行。',84,'全唐诗/poet.song.140000.json','["山轉江亦轉，江行山亦行。", "風鬟照玉鏡，素練縈青屏。", "我本山水客，澹無軒冕情。", "塵中悔一來，事外懷孤征。", "忽乘滄浪舟，仰高俯深清。", "餐翠腹可飽，飲淥身頓輕。", "鷓鴣不相識，還作故園聲。"]'),
('78d6503d-45cb-4380-9a96-f79de57de7ec','明發陳公徑過摩舍那灘石峰下十首  其七','楊萬里','宋','宋诗','song-poetry','','[]','危峰瑩無土，平地岌孤石。',72,'全唐诗/poet.song.140000.json','["危峰瑩無土，平地岌孤石。", "如何半巖間，亦有小樹碧。", "走空根苦辛，倚險榦寒瘠。", "芳蘭間叢生，紫蕤濯幽色。", "近香許世聞，遠秀絕人摘。", "而我雲外身，方茲喟行役。"]'),
('aa7f0264-9907-4633-a25b-b692dd397fa2','明發陳公徑過摩舍那灘石峰下十首  其八','楊萬里','宋','宋诗','song-poetry','','[]','城中安得山，無山安得詩。',96,'全唐诗/poet.song.140000.json','["城中安得山，無山安得詩。", "我入五羊城，遂與山水辭。", "有鏡不敢覽，塵面我自知。", "解維來歸亭，山水奔相隨。", "水光動我巾，山色染我衣。", "舟行將一月，恨速不恨遲。", "山雲來未已，江月皎無滓。", "開懷放之入，出語頗似之。"]'),
('12d94b35-9f6c-4b10-af6f-ff66d41cd273','明發陳公徑過摩舍那灘石峰下十首  其九','楊萬里','宋','宋诗','song-poetry','','[]','我從靈洲來，惟見芳草渡。',84,'全唐诗/poet.song.140000.json','["我從靈洲來，惟見芳草渡。", "蒹葭隨水遠，曠野無立樹。", "掛席上真陽，好山忽無數。", "好山如隠士，避世不自露。", "不應官道傍，乃有見山處。", "借識衛叔玠，未覩樂彥輔。", "石峰難再得，舟過更回顧。"]'),
('da290416-b551-4e1e-ae2e-173ffa239dfd','明發陳公徑過摩舍那灘石峰下十首  其一○','楊萬里','宋','宋诗','song-poetry','','[]','南中山絕佳，所恨人煙稀。',84,'全唐诗/poet.song.140000.json','["南中山絕佳，所恨人煙稀。", "略無好事人，結茅臨深溪。", "峰頂可月亭，岸石即釣磯。", "空令煙中猿，掛崖弄漣漪。", "山多人自少，人遠山益奇。", "我舟行不留，過眼山如馳。", "過眼意已足，久留亦何爲。"]'),
('506e8d7a-78f2-46c5-aa8c-e2af750d1099','遠峰','楊萬里','宋','宋诗','song-poetry','','[]','孤巘秀何似，碧蓮含未開。',24,'全唐诗/poet.song.140000.json','["孤巘秀何似，碧蓮含未開。", "誰將脩月斧，斸取一尖來。"]'),
('6b0214e6-4b81-42b1-b7d6-ad1db67ddb8c','江上松徑','楊萬里','宋','宋诗','song-poetry','','[]','一日江行百折中，回頭猶見夜來峰。',32,'全唐诗/poet.song.140000.json','["一日江行百折中，回頭猶見夜來峰。", "好山十里都如畫，更與橫排一徑松。"]'),
('d8b18861-acae-4a46-8b7e-d85bac9144c7','上濛顇灘','楊萬里','宋','宋诗','song-poetry','','[]','清江斜抱嶺根來，暗石衝波却倒回。',32,'全唐诗/poet.song.140000.json','["清江斜抱嶺根來，暗石衝波却倒回。", "幸自瑠璃青一片，落灘碎作雪花堆。"]'),
('b8032172-71ad-48c7-9e0b-c19e545d2117','回望摩舍那灘石峰','楊萬里','宋','宋诗','song-poetry','','[]','好山近看未爲奇，遠看全勝近看時。',32,'全唐诗/poet.song.140000.json','["好山近看未爲奇，遠看全勝近看時。", "回望七峰雲外筍，兩峰高絕五峰低。"]'),
('9d326d10-1c37-4c68-9a82-268f72e9129f','明發白沙灘聞布穀有感','楊萬里','宋','宋诗','song-poetry','','[]','提壺勸我飲，杜鵑勸我歸。',180,'全唐诗/poet.song.140000.json','["提壺勸我飲，杜鵑勸我歸。", "不如布穀子，勸我勤耘耔。", "我少貧且賤，不但無置錐。", "筆耒墾紙田，黑水導墨池。", "借令字堪煮，識字亦幾希。", "啼饑如不聞，饑慣自不啼。", "駿奔三十年，辛勤竟何爲。", "髮從道塗白，面爲風雪黧。", "夜來白沙灘，老命輕如絲。", "洪濤舞一葉，呼天叫神祇。", "生全乃偶然，人力初何施。", "曉聞布穀聲，如在故山時。", "坐令萬感集，初悟半世非。", "一險靡不悔，數悔庸何追。", "有田不歸耕，布穀真吾師。"]'),
('58f70f75-632a-4727-b0d3-f3cb17f2e6a0','寄賀建康留守范參政端明二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','寄衣不是未教歸，不合威名滿四夷。',64,'全唐诗/poet.song.140000.json','["寄衣不是未教歸，不合威名滿四夷。", "天與中興開日月，帝分萬乘半旌旗。", "春生錦繡山河早，秋到江淮草木遲。", "卧護北門朞月爾，却專堂印鳳凰池。"]'),
('88ff37aa-8dab-4526-a296-2d7ae68c9673','寄賀建康留守范參政端明二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','一生狂殺老猶狂，只炷先生一瓣香。',64,'全唐诗/poet.song.140000.json','["一生狂殺老猶狂，只炷先生一瓣香。", "不爲渠儂在廊廟，無端將相更文章。", "江南海北三千里，玉唾銀鈎十萬行。", "早整乾坤早巖壑，石湖風月剩分張。"]'),
('affe6e82-9f80-4a49-8c9a-dc80f4834a75','荔枝堂晝憩','楊萬里','宋','宋诗','song-poetry','','[]','荔子陰中風絕涼，菖蒲節後日偏長。',64,'全唐诗/poet.song.140000.json','["荔子陰中風絕涼，菖蒲節後日偏長。", "落殘數柄荷花蕊，浸得一瓶泉水香。", "多病早衰非破硯，欲行復倦且胡床。", "曲江近北差遲暑，不道江山勝五羊。"]'),
('79677847-de7f-4992-a5c3-9e686a7ccfba','風雨','楊萬里','宋','宋诗','song-poetry','','[]','殘風剩雨故欺人，垂箔關窗護病身。',64,'全唐诗/poet.song.140000.json','["殘風剩雨故欺人，垂箔關窗護病身。", "自拾荷花揩面汗，新將筍籜製頭巾。", "梅天筆墨都生醭，棐几文書嬾拂塵。", "帽子一峰青可掇，隔牆不敢略開門。"]'),
('8dcc0e33-7d32-48d6-9992-779cf2d468cf','謝從善挽詞','楊萬里','宋','宋诗','song-poetry','','[]','一腹儲三篋，雙鈎挽萬牛。',48,'全唐诗/poet.song.140000.json','["一腹儲三篋，雙鈎挽萬牛。", "行身平中準，閲世澹於秋。", "紫誥猶新墨，霜髯忽古丘。", "清風未作記，挂劍淚川流。"]'),
('284d38d0-fb0e-4661-b58f-7f9b16ccbbcd','送彭元忠縣丞北歸','楊萬里','宋','宋诗','song-poetry','','[]','君從循州來，却向饒州去。',204,'全唐诗/poet.song.140000.json','["君從循州來，却向饒州去。", "拍天海浪拂日峰，瓊尺裁成錦機句。", "學詩初學陳後山，霜皮脫盡山骨寒。", "近來別具一隻眼，要踏唐人最上關。", "三春弱柳三秋月，半溪清冰半峰雪。", "只今六月無此物，君能喚渠來入筆。", "恰則新鶑百囀聲，忽有寒蛩終夜鳴。", "瀟湘故人江漢客，爲君一夜頭盡白。", "我欠天公詩債多，霜髭撚盡未償它。", "君懷玉盤金叵羅，合騎天駟超天河。", "如何也鑄一大錯，自古詩人多命薄。", "黄茅起煙如黄沙，瘴母照永曼陀花。", "廣東之游樂復樂，勸君不如早還家。"]'),
('5ec4557b-0e14-43d7-959a-d30aef9f91eb','行部决獄宿新隆寺觀鄒至完題壁','楊萬里','宋','宋诗','song-poetry','','[]','道鄉千古一清風，雪壁銀鈎墨尚濃。',32,'全唐诗/poet.song.140000.json','["道鄉千古一清風，雪壁銀鈎墨尚濃。", "若愛殿前蒼玉佩，斷無身後碧紗籠。"]'),
('5ca61351-fb9a-4f01-a514-17538c7a5af8','題望韶亭','楊萬里','宋','宋诗','song-poetry','','["\u8861\u5c71", "\u6d1e\u5ead\u6e56"]','新隆寺後看韶石，三三兩兩略依稀。',320,'全唐诗/poet.song.140000.json','["新隆寺後看韶石，三三兩兩略依稀。", "金坑津頭看韶石，十十五五不整齊。", "一來望韶亭上看，九韶八音堆一案。", "金鐘大鏞浮水涯，玉瑟瑶琴倚天半。", "堯時文物也粗疎，禮樂猶带鴻荒餘。", "茅茨殿上槌土鼓，葦籥聲外無笙竽。", "黄能郎君走川嶽，領取后夔搜禮樂。", "嶧山桐樹半夜鳴，泗水石頭清晝躍。", "山祇川后爭獻珍，姚家制作初一新。", "帝思南嶽來時巡，宮琛廟寶皆駿奔。", "曲江清澈碧瓊軟，海山孤尖翠屏展。", "天顔有喜后夔知，一奏雲韶供亞飯。", "帝登九疑忘却歸，不知斑盡湘笛枝。", "后夔一脛跛莫隨，坐委衆樂江之湄。", "儀鳳舞獸掃無跡，獨留一狻守其側。", "至今喚作獅子石，雨淋日炙爛不得。", "洞庭張樂已莓苔，犍爲獲磬亦塵埃。", "不如九韶故無恙，戛擊尚可冬起雷。", "何時九秋霜月裏，來聽湘妃瑟聲美。", "曲終道是不見人，江上數峰是誰子。"]'),
('640a1da4-3408-4ee4-98f3-b568fddf4d1b','憩楹塘驛二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','夾路黄茅與樹齊，人行茅裏似山雞。',32,'全唐诗/poet.song.140000.json','["夾路黄茅與樹齊，人行茅裏似山雞。", "長松不與遮西日，却送清陰過隔溪。"]'),
('716cc199-8359-46ff-b0ee-088008200aee','憩楹塘驛二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','松鳴竹嘯響千崖，爲底炎蒸吹不開。',32,'全唐诗/poet.song.140000.json','["松鳴竹嘯響千崖，爲底炎蒸吹不開。", "自是笋輿趨北去，薰風不是不南來。"]'),
('d47c3216-72c8-45f5-9067-1caf39cae23a','官道古松','楊萬里','宋','宋诗','song-poetry','','[]','翠旌綠纛夾車輪，龍作長身鐵作鱗。',32,'全唐诗/poet.song.140000.json','["翠旌綠纛夾車輪，龍作長身鐵作鱗。", "莫笑道傍數松樹，古來老却幾官人。"]'),
('20f706ae-4e3a-44ef-ad12-1c1449d7852f','南雄驛前雙柳','楊萬里','宋','宋诗','song-poetry','','[]','外計堂前柳絕奇，南中無此兩渦絲。',32,'全唐诗/poet.song.140000.json','["外計堂前柳絕奇，南中無此兩渦絲。", "午風不動休嫌暑，要看枝枝自在垂。"]'),
('e2abbe78-e5bd-4d13-80ae-6f32c4f40534','南雄解舟','楊萬里','宋','宋诗','song-poetry','','[]','一昨春江上水船，即非上水是登天。',32,'全唐诗/poet.song.140000.json','["一昨春江上水船，即非上水是登天。", "如今下瀨江無水，始信登天却易然。"]'),
('1231ee03-f3eb-46e2-92c3-8f10e7859981','過建封寺下連魚灘二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','江收衆水赴單槽，石壁當流鬭雪濤。',32,'全唐诗/poet.song.140000.json','["江收衆水赴單槽，石壁當流鬭雪濤。", "將取危舟飛過去，黄頭郎只兩三篙。"]'),
('288d93e8-fa28-456e-ad13-95cf2efe0a8a','過建封寺下連魚灘二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','夢裏篙師忽叫灘，老夫驚殺起來看。',32,'全唐诗/poet.song.140000.json','["夢裏篙師忽叫灘，老夫驚殺起來看。", "前船過盡知無慮，末後孤舟膽自寒。"]'),
('b423f069-bf19-48e7-bb6f-9ee7ac000904','六月十八日立秋送客夜歸雨作','楊萬里','宋','宋诗','song-poetry','','[]','青天赤日更黄埃，迎送紛紛正往來。',64,'全唐诗/poet.song.140000.json','["青天赤日更黄埃，迎送紛紛正往來。", "一夜炎蒸無計奈，三更風雨領秋回。", "人生作麽禁寒暑，世事何如付酒杯。", "遮莫髯間點霜雪，何曾筆下減瓊瑰。"]'),
('84600a75-044a-44cd-b5c0-095919404d7a','送廣帥秩滿之官丹陽二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','北門卧護要耆英，小試胸中十萬兵。',64,'全唐诗/poet.song.140000.json','["北門卧護要耆英，小試胸中十萬兵。", "天借金山吟落月，身兼鐵甕作長城。", "何如嶺上因歸路，摘取梅酸去作羹。", "已有紫泥教詣闕，便應留住付鈞衡。"]'),
('29ad18ec-a212-4cf5-bb5f-b509a4ffb105','送廣帥秩滿之官丹陽二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','南海元戎禁從臣，却昇北斗捧星辰。',64,'全唐诗/poet.song.140000.json','["南海元戎禁從臣，却昇北斗捧星辰。", "回頭五嶺忽千里，屈指十賢添一人。", "笑別廣平堂下月，歸看太極殿前春。", "一尊話別端何有，綠水青山更白雲。"]'),
('c58de926-99b6-4a34-9fe0-375877c7ef87','晚步','楊萬里','宋','宋诗','song-poetry','','[]','晚暑無凉可得尋，小風一點慰人心。',32,'全唐诗/poet.song.140000.json','["晚暑無凉可得尋，小風一點慰人心。", "斜陽碎入高榕葉，翻作青瑶覆作金。"]'),
('9008bec2-539f-422b-9c89-e7cdc396b263','寄題臨武知縣李子西公廨君子亭','楊萬里','宋','宋诗','song-poetry','','[]','王家喚竹作此君，周家喚蓮作君子。',80,'全唐诗/poet.song.140000.json','["王家喚竹作此君，周家喚蓮作君子。", "泥中懷玉避俗塵，水上開花超大地。", "紅裳翠蓋在眼中，欲往從之隔秋水。", "牡丹貴人非吾徒，籬菊隠士堪鄰居。", "李侯岸巾對芙蕖，不寄新詩來起予。"]'),
('553db366-1605-4947-953b-c1b5a5105b51','謝木韞之舍人分送講筵賜茶','楊萬里','宋','宋诗','song-poetry','','[]','吳綾縫囊染菊水，蠻砂塗印題進字。',288,'全唐诗/poet.song.140000.json','["吳綾縫囊染菊水，蠻砂塗印題進字。", "淳熙錫貢新水芽，天珍誤落黄茅地。", "故人鸞渚紫微郎，金華講徹花草香。", "宣賜龍焙第一綱，殿上走趨明月璫。", "御前啜罷三危露，滿袖香煙懷璧去。", "歸來拈出兩蜿蜒，雷電晦冥驚破柱。", "北苑龍芽內樣新，銅圍銀範鑄瓊塵。", "九天寶月霏五雲，玉龍雙舞黄金鱗。", "老夫平生愛煮茗，十年燒穿折脚鼎。", "下山汲井得甘冷，上山摘芽得苦硬。", "何曾夢到龍遊窠，何曾夢喫龍芽茶。", "故人分送玉川子，春風來自玉皇家。", "鍛圭椎璧調冰水，烹龍庖鳳搜肝髓。", "石花紫笋可衙官，赤印白泥牛走爾。", "故人氣味茶樣清，故人風骨茶樣明。", "開緘不但似見面，叩之咳唾金石聲。", "麴生勸人墮巾幘，睡魔遣我拋書冊。", "老夫七椀病未能，一啜猶堪坐秋夕。"]'),
('85090881-2de4-4fff-b670-9e4542e06f5d','荔枝堂夕眺三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','夕峰褪日半鉦多，秋漢吹雲一絮過。',32,'全唐诗/poet.song.140000.json','["夕峰褪日半鉦多，秋漢吹雲一絮過。", "寂寂庭松今兩月，鶴雛去盡只留窠。"]'),
('be7da047-2df4-46b1-b6bb-fd08431d8c56','荔枝堂夕眺三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','病骨秋臞怯暮清，凉風偷带北風輕。',32,'全唐诗/poet.song.140000.json','["病骨秋臞怯暮清，凉風偷带北風輕。", "迎寒窗隔重糊遍，只放書邊數眼明。"]'),
('17430774-332c-4537-b817-707e306f2451','荔枝堂夕眺三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','閏年秋淺似秋深，蟋蟀將愁傍砌吟。',32,'全唐诗/poet.song.140000.json','["閏年秋淺似秋深，蟋蟀將愁傍砌吟。", "今夕初三元未覺，西樓西角一鈎金。"]'),
('ba30f34c-8093-4170-bdc3-e97d09fde7a3','羅仲憲送蔊菜謝以長句','楊萬里','宋','宋诗','song-poetry','','[]','學琴自有譜，相鶴自有經。',91,'全唐诗/poet.song.140000.json','["學琴自有譜，相鶴自有經。", "蔬經我繙盡，不見蔊菜名。", "金華詩裏初相識，玉友尊前每相憶。", "坐令芥孫薑子芽，一見風流俱避席。", "取士取名多失真，向來許靖亦誤人。", "君不見鄭花不得半山句，却參魯直稱門生。"]'),
('f81fc410-4e37-4e26-820a-86ef2ab79913','曲江重陽','楊萬里','宋','宋诗','song-poetry','','[]','煙描水寫老秋容，嶺外秋容也自濃。',64,'全唐诗/poet.song.140000.json','["煙描水寫老秋容，嶺外秋容也自濃。", "如見大賓新露菊，若歌商頌曉風松。", "插花醉照濂溪井，吹髮慵登帽子峰。", "莫問明年衰與健，茱萸何處不相逢。"]'),
('9f4b24f4-1772-479e-bbf0-93da02cc57b6','九日郡中送白菊','楊萬里','宋','宋诗','song-poetry','','[]','未應白菊減於黄，金作鈿心玉作裳。',64,'全唐诗/poet.song.140000.json','["未應白菊減於黄，金作鈿心玉作裳。", "一夜西風開瘦蕾，兩年南海伴重陽。", "若言佳節如常日，爲底寒花分外香。", "挼蕊浮杯莫多著，一枝留插鬢邊霜。"]'),
('df4d7aa0-d8ae-47e4-8480-1e3bd374de11','擬題綿州推官廳六一堂','楊萬里','宋','宋诗','song-poetry','','[]','一代今文伯，三巴昔産賢。',48,'全唐诗/poet.song.140000.json','["一代今文伯，三巴昔産賢。", "白珩光宇宙，藍水暗風煙。", "有客曾高枕，升堂見老仙。", "夢中五色筆，猶爲寫鳴蟬。"]'),
('1f79032c-b413-47f8-9fbe-66fd17ea7d05','擬進士金波麗鳷鵲詩','楊萬里','宋','宋诗','song-poetry','','[]','曳練爲銀漢，鎔金作月波。',72,'全唐诗/poet.song.140000.json','["曳練爲銀漢，鎔金作月波。", "桂華斜麗處，鳷鵲得光多。", "雲葉三秋浄，菱花一鏡磨。", "宮簷暉水竹，觀影澹星河。", "霧濕殘宵柝，霜明欲曉珂。", "螭頭餘映在，劍佩已相摩。"]'),
('e56ba407-2052-4905-8d95-ebc1c9a6b19d','督諸軍求盜梅州宿曹谿呈葉景伯陳守正溥禪師','楊萬里','宋','宋诗','song-poetry','','[]','南斗東偏第一山，白頭初得扣禪關。',64,'全唐诗/poet.song.140000.json','["南斗東偏第一山，白頭初得扣禪關。", "祖衣半似雲來薄，金鑰纔開霧作團。", "一鉢可能盈尺許，千年有底萬人看。", "今宵雪乳分龍焙，明日黄泥又馬鞍。"]'),
('77896bd6-954f-4b7e-baaa-150a6b679967','曉炊黄竹莊三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','染練江山宿雨餘，枝枝葉葉潤如酥。',32,'全唐诗/poet.song.140000.json','["染練江山宿雨餘，枝枝葉葉潤如酥。", "絲窠瓔珞消多少，破費天公百斛珠。"]'),
('ad71cfb3-17df-4f80-a080-345440c4ac10','曉炊黄竹莊三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','琯灰蔌蔌欲飛聲，日到牽牛第幾星。',32,'全唐诗/poet.song.140000.json','["琯灰蔌蔌欲飛聲，日到牽牛第幾星。", "地底陽生人不覺，燒痕未冷已青青。"]'),
('caad1417-d2ab-4859-acb9-887fb7b9165f','曉炊黄竹莊三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','城中殊未有梅看，莫是冬暄欠淺寒。',32,'全唐诗/poet.song.140000.json','["城中殊未有梅看，莫是冬暄欠淺寒。", "行到深山最寒處，兩株香雪照冰灘。"]'),
('cd162740-41c2-46d5-9468-6d1baf10e110','上岑水嶺二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','危峰上面更危峰，特地無梯上碧空。',32,'全唐诗/poet.song.140000.json','["危峰上面更危峰，特地無梯上碧空。", "遥望白雲生絕頂，如今身在白雲中。"]'),
('ccc3322c-26f8-43f5-9fce-f43211bff89a','上岑水嶺二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','天上雲泉脚下鳴，玉虹倒掛客心驚。',32,'全唐诗/poet.song.140000.json','["天上雲泉脚下鳴，玉虹倒掛客心驚。", "試教轉落峰頭石，衮到深溪作麽聲。"]'),
('c18432e5-97af-4772-8ec6-61d009d83258','過岑水','楊萬里','宋','宋诗','song-poetry','','[]','石瘦銅苗綠，溪腥膽水黄。',48,'全唐诗/poet.song.140000.json','["石瘦銅苗綠，溪腥膽水黄。", "是間無馬跡，何處更羊腸。", "惡路今方始，平生夢未嘗。", "如何寒刮骨，行得汗如漿。"]'),
('9b0a0a69-faf0-4603-b48f-0bca63a73291','野炊白沙沙上','楊萬里','宋','宋诗','song-poetry','','[]','半日山行底路塗，欲炊無店糴無珠。',64,'全唐诗/poet.song.140000.json','["半日山行底路塗，欲炊無店糴無珠。", "旋將白石支燃鼎，却展青油當野廬。", "一望平田皆沃壤，只生枯葦與寒蘆。", "風餐露宿何虧我，玉饌瓊樓合屬渠。"]'),
('db5e3894-4ad8-483f-8056-8c14030812bd','至節宿翁源縣與葉景伯小酌','楊萬里','宋','宋诗','song-poetry','','[]','此縣誰言是强名，古來十室亦琴鳴。',64,'全唐诗/poet.song.140000.json','["此縣誰言是强名，古來十室亦琴鳴。", "只嫌六七茅竹舍，也有兩三雞犬聲。", "村酒分冬勝虛度，霜風一夜辦新晴。", "半生客路逢佳節，佳節何曾負半生。"]'),
('8f2eac7b-38fb-411d-bb29-fc5da6f30b78','至日宿藍坑小民居竹柱荻壁壁皆不土','楊萬里','宋','宋诗','song-poetry','','[]','一路都岑寂，藍坑分外荒。',48,'全唐诗/poet.song.140000.json','["一路都岑寂，藍坑分外荒。", "屋疎茅送月，壁密荻分霜。", "病趾催趺坐，殘更妬曉光。", "暖寒無上策，來早借朝陽。"]'),
('98e04e6d-15aa-4893-b4ea-65c201e60294','曉晴過猿藤逕','楊萬里','宋','宋诗','song-poetry','','[]','厭雨欣初霽，貪程敢晏眠。',48,'全唐诗/poet.song.140000.json','["厭雨欣初霽，貪程敢晏眠。", "排天雙壁起，受日一峰先。", "入逕惟逢樹，無人況有煙。", "藤深猿不見，聲到客愁邊。"]'),
('7ad212f0-9601-4e41-a484-ecff0a59022e','古路','楊萬里','宋','宋诗','song-poetry','','[]','我生倦行路，此行欣不辭。',120,'全唐诗/poet.song.140000.json','["我生倦行路，此行欣不辭。", "我豈與人異，厭閑樂驅馳。", "王事當有行，忘身那自知。", "閩盜入吾部，梅川作潢池。", "白羽飛赤囊，碧油走紅旗。", "履霜戒不早，蔓草要勿滋。", "士皆衝冠怒，人挾報國私。", "我行梅始花，我歸柳應絲。", "會當揮蝥弧，一笑封鯨鯢。", "休愁犖确路，即賦競病詩。"]'),
('7e7ada08-52e8-4ccf-8cb4-bd6023887122','野炊猿藤逕樹下','楊萬里','宋','宋诗','song-poetry','','[]','逕仄旁無地，林開忽有天。',48,'全唐诗/poet.song.140000.json','["逕仄旁無地，林開忽有天。", "丹楓明遠樹，黄葉暗鳴泉。", "苔錦銀槍竈，蘆茸玉帳氈。", "從軍古云樂，乞與箇山川。"]'),
('718128d5-06f1-48de-b168-72711c6caebd','泉聲','楊萬里','宋','宋诗','song-poetry','','[]','初聞蟹眼雪花聲，忽有仙人玉珮鳴。',64,'全唐诗/poet.song.140000.json','["初聞蟹眼雪花聲，忽有仙人玉珮鳴。", "時作微吟清入骨，又成幽咽怨多情。", "問知古澗飛泉落，起看寒泓遶石行。", "欲解塵纓聊一濯，無塵可濯濯誰纓。"]'),
('3ed0a826-aa6c-4d77-b493-dda6087ce8c4','羽檄召諸郡兵','楊萬里','宋','宋诗','song-poetry','','[]','閩盜宵窺粵，南兵曉盡東。',48,'全唐诗/poet.song.140000.json','["閩盜宵窺粵，南兵曉盡東。", "軍聲動巖谷，旗影喜霜風。", "貔虎諸方集，欃槍一笑空。", "區區鼠子輩，不足奏膚公。"]'),
('69448e8d-c918-4d5b-afe5-d0a659b4b0be','明發瀧頭','楊萬里','宋','宋诗','song-poetry','','[]','黑甜偏至五更濃，强起侵星敢小慵。',32,'全唐诗/poet.song.140000.json','["黑甜偏至五更濃，强起侵星敢小慵。", "輪與山雲能樣嬾，日高猶宿夜來峰。"]'),
('421c6718-d6ea-4683-b2fc-609608de78cb','過烏沙望大塘石峰','楊萬里','宋','宋诗','song-poetry','','[]','城中長恨不見山，出城見山如等閑。',204,'全唐诗/poet.song.140000.json','["城中長恨不見山，出城見山如等閑。", "曹溪過了過岑嶺，不惟山粗石仍獷。", "山如可師癩滿頂，石如陳三癭聯頸。", "一路令人眼不開，眼開令人悶不醒。", "烏沙未到一溪橫，水清見底心已清。", "大塘六峰爭出迎，水精筆架琉璃屏。", "兩峰玉筍初出土，三峰冰盤飣角黍。", "一峰新琢金博山，霧作沈煙雲作縷。", "忽然前岡平截斷，萬丈青尖餘寸許。", "山神解憐客子愁，平地跳出蒼琳璆。", "更借天公修月斧，神工一夜忙琱鎪。", "近看定何者，遠看真可畫。", "山神自賀應自詫，古來此地無車馬。"]'),
('0ac0d119-4486-4949-b8ba-f1526a44b43f','竹魚','楊萬里','宋','宋诗','song-poetry','','[]','銀魚色如銀，竹魚色如竹。',118,'全唐诗/poet.song.140000.json','["銀魚色如銀，竹魚色如竹。", "渭川千畝秀可掬，都將染成一身綠。", "魚生竹溪中，家在竹根菱荇叢。", "晝餐竹葉與竹米，夜飲竹露吹竹風。", "前身王子猷，今身赤鯶公。", "只知愛竹判却命，化作此君蒼雪容。", "漁翁夜傍竹溪宿，魚驚釣絲冰底縮。", "朝來釣得水蒼玉，先生笑捫藜莧腹。"]'),
('f40048dd-d8b2-4b9f-9231-631bd708f5ce','蕈子','楊萬里','宋','宋诗','song-poetry','','[]','空山一雨山溜急，漂流桂子松花汁。',128,'全唐诗/poet.song.140000.json','["空山一雨山溜急，漂流桂子松花汁。", "土膏鬆暖都滲入，蒸出蕈花團戢戢。", "戴穿落葉忽起立，撥開落葉百數十。", "蠟面黄紫光欲濕，酥莖嬌脆手輕拾。", "響如鵝掌味如蜜，滑似蓴絲無點澀。", "傘不如笠釘勝笠，香留齒牙麝莫及。", "菘羔楮雞避席揖，餐玉茹芝當却粒。", "作羹不可疎一日，作腊仍堪貯盈笈。"]'),
('b4b9be6b-2697-43ee-8d11-8289dcd2b843','食鷓鴣','楊萬里','宋','宋诗','song-poetry','','[]','江南厭聽鷓鴣曲，嶺南初嘗鷓鴣肉。',64,'全唐诗/poet.song.140000.json','["江南厭聽鷓鴣曲，嶺南初嘗鷓鴣肉。", "年年細雨落花春，鈎輈格磔惱殺人。", "竹雞泥滑報行客，鷓鴣更道行不得。", "方兄百輩買一隻，可惜羽衣錦狼藉。"]'),
('77d4b8b9-e09e-48f0-ad4b-142aa50b9376','宿小粉村','楊萬里','宋','宋诗','song-poetry','','[]','暮宿溪邊小粉村，一峰如筆正當門。',32,'全唐诗/poet.song.140000.json','["暮宿溪邊小粉村，一峰如筆正當門。", "看來山色元無粉，拂殺濃藍淺黛痕。"]'),
('7970aafa-f53a-418a-83f7-54bef2abf45f','塘閘','楊萬里','宋','宋诗','song-poetry','','[]','山逢塘閘冠南中，小大高低十九峰。',32,'全唐诗/poet.song.140000.json','["山逢塘閘冠南中，小大高低十九峰。", "東畔連尖尤秀絕，一雙銅綠翠鋪茸。"]'),
('cc4e79d7-e77f-442f-b696-dcc8e0fe3f7a','入陂子逕','楊萬里','宋','宋诗','song-poetry','','[]','下一嶺，上一嶺，上如登天下如井，人言箇是陂子逕。',152,'全唐诗/poet.song.140000.json','["下一嶺，上一嶺，上如登天下如井，人言箇是陂子逕。", "猿藤逕裏無居民，陂子逕裏無行人。", "冷風蕭蕭日杲杲，露濕半青半黄草。", "前日猿藤猶有猿，今此一鳥亦不喧。", "樹無紅果草無蕊，縱有猿鳥將何餐。", "兩山如壁岸如削，一逕緣空劣容脚。", "溪聲千仞撼林壑，崖石欲崩人欲落。", "來日長峰逕更長，陂子逕荒未是荒。", "蔣家三逕未入手，嶺南三逕先斷腸。"]'),
('4911fac8-1b0c-4811-b782-8c3fec4a30bd','過陂子逕五十餘里喬木蔽天遣悶柒絕句  其一','楊萬里','宋','宋诗','song-poetry','','[]','林中亭午始微明，楓倒杉傾滿路橫。',32,'全唐诗/poet.song.140000.json','["林中亭午始微明，楓倒杉傾滿路橫。", "黄葉青苔深一丈，先生却愛此中行。"]'),
('4f184408-e469-4667-88b7-72b812eedf06','過陂子逕五十餘里喬木蔽天遣悶柒絕句  其二','楊萬里','宋','宋诗','song-poetry','','[]','草光葉潤亦清佳，翠裏生香不是花。',32,'全唐诗/poet.song.140000.json','["草光葉潤亦清佳，翠裏生香不是花。", "一事說來人不信，蕨長如樹蚓如蛇。"]'),
('989271b2-4b80-4247-8ead-aebff678b6a3','過陂子逕五十餘里喬木蔽天遣悶柒絕句  其三','楊萬里','宋','宋诗','song-poetry','','[]','蘆深石路旋芟開，藤絓肩輿却倒回。',32,'全唐诗/poet.song.140000.json','["蘆深石路旋芟開，藤絓肩輿却倒回。", "蘭蕙連山爲誰好，芭蕉滿谷不緣栽。"]'),
('d50b0b2f-6acd-474d-88cc-7d502356c55a','過陂子逕五十餘里喬木蔽天遣悶柒絕句  其四','楊萬里','宋','宋诗','song-poetry','','[]','爲憐上轎齧人肩，下轎行來脚底穿。',32,'全唐诗/poet.song.140000.json','["爲憐上轎齧人肩，下轎行來脚底穿。", "客子心心愁欲暮，碧雲偏作半陰天。"]'),
('a8d33fa6-7036-45f0-a6f4-13e5ad663c99','過陂子逕五十餘里喬木蔽天遣悶柒絕句  其五','楊萬里','宋','宋诗','song-poetry','','[]','晚風寂寂樹陰陰，松不悲鳴竹不吟。',32,'全唐诗/poet.song.140000.json','["晚風寂寂樹陰陰，松不悲鳴竹不吟。", "只有清泉逢白石，向人刺口說山林。"]'),
('61deed53-7d6a-49e7-8c16-d44002f944e5','過陂子逕五十餘里喬木蔽天遣悶柒絕句  其六','楊萬里','宋','宋诗','song-poetry','','[]','澗泉勸我出山遲，曲曲遮留步步隨。',32,'全唐诗/poet.song.140000.json','["澗泉勸我出山遲，曲曲遮留步步隨。", "泉自多情儂自悶，今宵會有出山時。"]'),
('d3897d4a-5a56-4543-acb9-f180bba1d2ec','過陂子逕五十餘里喬木蔽天遣悶柒絕句  其七','楊萬里','宋','宋诗','song-poetry','','[]','山窮喜見一平川，不似林中不識天。',32,'全唐诗/poet.song.140000.json','["山窮喜見一平川，不似林中不識天。", "只出此山災便散，何須更問小行年。"]'),
('db541295-c930-42dc-b4d7-f11346ab2c14','過長峰逕遇雨遣悶十絕句  其一','楊萬里','宋','宋诗','song-poetry','','[]','說著長峰十日愁，夜來發處四更頭。',32,'全唐诗/poet.song.140000.json','["說著長峰十日愁，夜來發處四更頭。", "莫令炬火風吹黑，未說紅紗絳蠟休。"]'),
('7832f2cc-879a-421b-8200-e56a6dc211bf','過長峰逕遇雨遣悶十絕句  其二','楊萬里','宋','宋诗','song-poetry','','[]','百里如何一日行，晴天猶自急追程。',32,'全唐诗/poet.song.140000.json','["百里如何一日行，晴天猶自急追程。", "山雲管得儂愁雨，强做催詩數點聲。"]'),
('a95eabb5-eaa3-4bff-a943-18d9504d6d2b','過長峰逕遇雨遣悶十絕句  其三','楊萬里','宋','宋诗','song-poetry','','[]','野炊未到也饑嗔，到得炊邊却可人。',32,'全唐诗/poet.song.140000.json','["野炊未到也饑嗔，到得炊邊却可人。", "傘作旅亭泥處坐，水漂地竈雨中薪。"]'),
('f877bbc1-bbb6-48cd-8c9b-1c3e788cea43','過長峰逕遇雨遣悶十絕句  其四','楊萬里','宋','宋诗','song-poetry','','[]','石上菖蒲鐵作鬚，寸根九節許清臞。',32,'全唐诗/poet.song.140000.json','["石上菖蒲鐵作鬚，寸根九節許清臞。", "安期自是參渠底，却重安期不重渠。"]'),
('9c2b0add-a742-406d-8a4c-7a3c9ec0d6e0','過長峰逕遇雨遣悶十絕句  其五','楊萬里','宋','宋诗','song-poetry','','[]','一眼空山空復空，欹蘆倒荻雨和風。',32,'全唐诗/poet.song.140000.json','["一眼空山空復空，欹蘆倒荻雨和風。", "却緣小隊旌旗過，教得青楓學著紅。"]'),
('4df1993b-eb3c-4f68-a3ac-811885b74027','過長峰逕遇雨遣悶十絕句  其六','楊萬里','宋','宋诗','song-poetry','','[]','何須人跡到來曾，點汙松風澗水聲。',32,'全唐诗/poet.song.140000.json','["何須人跡到來曾，點汙松風澗水聲。", "不是先生愛山水，是間却遣阿誰行。"]'),
('66161c65-c84b-4569-b003-78c713476735','過長峰逕遇雨遣悶十絕句  其七','楊萬里','宋','宋诗','song-poetry','','[]','猿藤陂子枉驚吁，未抵長峰小半塗。',32,'全唐诗/poet.song.140000.json','["猿藤陂子枉驚吁，未抵長峰小半塗。", "今夕前頭何許宿，不知出得逕來無。"]'),
('379a9231-6c73-4d04-9d04-47aab5746316','過長峰逕遇雨遣悶十絕句  其八','楊萬里','宋','宋诗','song-poetry','','[]','下到危坡斗處泥，旁臨崩岸仄邊溪。',32,'全唐诗/poet.song.140000.json','["下到危坡斗處泥，旁臨崩岸仄邊溪。", "不須杜句能驅瘧，只誦長峰遣悶詩。"]'),
('514721a3-6cd9-4f06-8659-30eec3edc8f0','過長峰逕遇雨遣悶十絕句  其九','楊萬里','宋','宋诗','song-poetry','','[]','出得山來未見村，已知村近稍多田。',32,'全唐诗/poet.song.140000.json','["出得山來未見村，已知村近稍多田。", "坐看雲脚都垂地，回望峰頭已入天。"]'),
('4057dd3e-5f33-4c90-bb57-c81be001602c','過長峰逕遇雨遣悶十絕句  其一○','楊萬里','宋','宋诗','song-poetry','','[]','鰌是蝦兄非善地，橘和瓣種带禳災。',32,'全唐诗/poet.song.140000.json','["鰌是蝦兄非善地，橘和瓣種带禳災。", "烏椑不熟還無事，小艇難乘莫載來。"]'),
('fde34334-b9fb-4cf8-96a2-abe5cb6a44b8','明發曲坑二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','雲橫平野近人低，似縠如紗只隔溪。',32,'全唐诗/poet.song.140000.json','["雲橫平野近人低，似縠如紗只隔溪。", "行到溪東元不見，回頭却復在溪西。"]'),
('66ebdaca-4974-4cc3-bf47-240ca26cf2f5','明發曲坑二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','露草欣逢曉日新，各將珠琲鬭呈珍。',32,'全唐诗/poet.song.140000.json','["露草欣逢曉日新，各將珠琲鬭呈珍。", "紅光影裏如何揀，顆顆圜明顆顆勻。"]'),
('78926706-79bb-486e-a555-687dcbaa358f','明發龍川二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','山有濃嵐水有氛，非煙非霧亦非雲。',32,'全唐诗/poet.song.140000.json','["山有濃嵐水有氛，非煙非霧亦非雲。", "北人不識南中瘴，只到龍川指似君。"]'),
('cf8b896c-8ce6-408a-ad3a-1df048126bd9','明發龍川二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','優入蠻溪受瘴煙，一生誰料到龍川。',32,'全唐诗/poet.song.140000.json','["優入蠻溪受瘴煙，一生誰料到龍川。", "早書實歷遠山考，便是中書九閏年。"]'),
('09078107-240d-4125-bac7-4da0e45586bd','發通衢驛見梅有感','楊萬里','宋','宋诗','song-poetry','','[]','忙中掠眼雪枝斜，落片紛紛點玉沙。',32,'全唐诗/poet.song.140000.json','["忙中掠眼雪枝斜，落片紛紛點玉沙。", "虛過一冬妨底事，不曾款曲是梅花。"]'),
('e5d0e797-c694-4161-be02-4c8749638ce5','過五里逕三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','瘦日當中暖稍回，冷山未許瘴全開。',32,'全唐诗/poet.song.140000.json','["瘦日當中暖稍回，冷山未許瘴全開。", "溪光遠隔深深竹，特地穿簾入轎來。"]'),
('fe5e7e9f-35de-450e-975b-e040799b76e9','過五里逕三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','野水奔流不小停，知渠何事太忙生。',32,'全唐诗/poet.song.140000.json','["野水奔流不小停，知渠何事太忙生。", "也無一箇人催促，自愛爭先落澗聲。"]'),
('35d368b4-3af1-4eed-93af-f390db93b50a','過五里逕三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','入山無路出無門，鳥語猿聲更斷魂。',32,'全唐诗/poet.song.140000.json','["入山無路出無門，鳥語猿聲更斷魂。", "當處迷塗何處問，一溪引我得前村。"]'),
('47c7efa6-73ab-4cd1-8b10-7a58a2001fcf','晨炊浦村','楊萬里','宋','宋诗','song-poetry','','[]','水出何村尾，橋橫亂篠叢。',48,'全唐诗/poet.song.140000.json','["水出何村尾，橋橫亂篠叢。", "隔溪三四屋，對面一雙峰。", "過午非常暖，疑他不是冬。", "疎梅照清淺，作意爲誰容。"]'),
('33cec56e-847f-4bd8-be23-3c83349ed660','宿長樂縣驛驛皆用葵葉蓋屋狀如椶葉云','楊萬里','宋','宋诗','song-poetry','','[]','都將葵葉蓋亭中，樹似桄榔葉似椶。',32,'全唐诗/poet.song.140000.json','["都將葵葉蓋亭中，樹似桄榔葉似椶。", "欲問天公覓微雪，裝成急響打船篷。"]'),
('07fbb3c1-17d8-473d-a9e5-064aa4126d89','題興寧縣東文嶺瀑泉在夜明場驛之東','楊萬里','宋','宋诗','song-poetry','','[]','笋輿路轉崖欹傾，只聞滿山泉水嗚。',166,'全唐诗/poet.song.140000.json','["笋輿路轉崖欹傾，只聞滿山泉水嗚。", "卷書急看已半失，眼不停注耳細聽。", "石如鐵色黑，壁立鏡面平。", "水從鏡面一飛下，蘄笛織簟風漪生。", "石知水力倦，半壁鍾作天一泓。", "水行到此欲小憩，後水忽至前水驚。", "分清裂白兩派出，跳珠躍雪雙龍爭。", "不知落處深幾許，千丈井底碎玉聲。", "安得好事者，泉上作小亭。", "釀泉爲酒不用麴，春風吹作蒲萄綠。", "醉寫泉聲入柘木，何處更尋響泉曲。"]'),
('db306de6-bb01-4fd5-876e-276e1dd60f34','入程鄉縣界','楊萬里','宋','宋诗','song-poetry','','[]','長樂昏嵐著地凝，程鄉毒霧噀人腥。',32,'全唐诗/poet.song.140000.json','["長樂昏嵐著地凝，程鄉毒霧噀人腥。", "吾詩不是南征集，只合標題作瘴經。"]'),
('6a7cda0a-8446-499b-8fe1-0058849ce989','明發梅州','楊萬里','宋','宋诗','song-poetry','','[]','市小山城寂，船稀野渡忙。',24,'全唐诗/poet.song.140000.json','["市小山城寂，船稀野渡忙。", "金暄梅蕊日，玉冷草根霜。"]'),
('c3fe918f-418c-496f-9d99-1e98893844b9','霜草','楊萬里','宋','宋诗','song-poetry','','[]','霜前亂碧未全枯，霜後紛黄却更蘇。',32,'全唐诗/poet.song.140000.json','["霜前亂碧未全枯，霜後紛黄却更蘇。", "偷喫瑶臺青女粉，都生瓊髮與銀鬚。"]'),
('429f03a7-dc9f-4142-acb4-4a57a3770a9d','夜宿房溪飲野人張珦家桂葉鹿蹄酒其法以桂葉爲餠以鹿蹄煮酒釀以八月過是則味減云','楊萬里','宋','宋诗','song-poetry','','[]','桂葉揉青作麴投，鹿蹄煮醁趁涼篘。',64,'全唐诗/poet.song.140000.json','["桂葉揉青作麴投，鹿蹄煮醁趁涼篘。", "落杯瑩滑冰中水，過口森嚴菊底秋。", "玉友黄封猶退舍，齏湯蜜汁更輸籌。", "野人未許傳醅法，剩買雙缾過別州。"]'),
('43682067-57bc-4632-8924-51eb9034eb68','明發房溪二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','山路婷婷小樹梅，爲誰零落爲誰開。',32,'全唐诗/poet.song.140000.json','["山路婷婷小樹梅，爲誰零落爲誰開。", "多情也恨無人賞，故遣低枝拂面來。"]'),
('7db2224f-254e-465d-8463-2aaff9c9e7ce','明發房溪二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','青天白日十分晴，轎上蕭蕭忽雨聲。',32,'全唐诗/poet.song.140000.json','["青天白日十分晴，轎上蕭蕭忽雨聲。", "却是松梢霜水落，雨聲那得此聲清。"]'),
('9ae93527-cf3b-4230-97f5-9a74aee6e656','瘴霧','楊萬里','宋','宋诗','song-poetry','','[]','午時猶未識金烏，對面看人一似無。',32,'全唐诗/poet.song.140000.json','["午時猶未識金烏，對面看人一似無。", "臘月黄茅猶爾許，不知八月却何如。"]'),
('3c73a642-dec9-437f-b045-2bbc6d75f71f','過水車鋪二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','盡日塗中斷客行，兩邊山色到雲青。',32,'全唐诗/poet.song.140000.json','["盡日塗中斷客行，兩邊山色到雲青。", "溪光摇碎黄金日，波面跳成白玉星。"]'),
('7678869d-60ba-401b-acfb-676df2529fa2','過水車鋪二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','轎裏看書得晝眠，夢中驚浪撼漁船。',32,'全唐诗/poet.song.140000.json','["轎裏看書得晝眠，夢中驚浪撼漁船。", "覺來書卷風吹亂，忘却前篇與後篇。"]'),
('ba13da53-0853-42b2-a756-136a5eca3619','宿萬安鋪','楊萬里','宋','宋诗','song-poetry','','[]','來朝還入鰐魚鄉，未到潮陽到揭陽。',32,'全唐诗/poet.song.140000.json','["來朝還入鰐魚鄉，未到潮陽到揭陽。", "休說春風歸路遠，只今去路不勝長。"]'),
('f7146abb-2234-4049-bd55-12565953d6d2','過單竹洋逕','楊萬里','宋','宋诗','song-poetry','','[]','兩山何許來，此焉忽相尋。',84,'全唐诗/poet.song.140000.json','["兩山何許來，此焉忽相尋。", "摩肩不少讓，爭道各載駸。", "喬木與脩竹，相招爲茂林。", "無風生翠寒，未夕起素陰。", "天垂木末近，日到谷底深。", "空山時自響，已動客子心。", "行至幽絕處，更聞啼怪禽。"]'),
('dcf9981f-d933-4c4c-a413-eba782b4853b','自彭田鋪至湯田道旁梅花十餘里','楊萬里','宋','宋诗','song-poetry','','[]','一行誰栽十里梅，下臨溪水恰齊開。',32,'全唐诗/poet.song.140000.json','["一行誰栽十里梅，下臨溪水恰齊開。", "此行便是無官事，只爲梅花也合來。"]'),
('fd88e2a4-fc2c-46ce-84c8-8b00e7266d19','觀湯田鋪溪邊湯泉','楊萬里','宋','宋诗','song-poetry','','[]','下泓堪浴上堪煎，陰火熬成未必然。',32,'全唐诗/poet.song.140000.json','["下泓堪浴上堪煎，陰火熬成未必然。", "海底日昇波自沸，偶分一眼作湯泉。"]'),
('cc73fe2d-b55b-4cc0-9548-130146d314e4','湯田早行見李花甚盛二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','此地先春信，年年只是梅。',24,'全唐诗/poet.song.140000.json','["此地先春信，年年只是梅。", "南中春更早，臘日李花開。"]'),
('3eba16f2-8b5b-4883-9f39-6246349f0ad4','湯田早行見李花甚盛二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','似妬梅花早，同時鬭雪膚。',24,'全唐诗/poet.song.140000.json','["似妬梅花早，同時鬭雪膚。", "新年三二月，還解再開無。"]'),
('8da96c50-0371-499e-b1ee-f0b4cb0681df','雨中道旁叢竹','楊萬里','宋','宋诗','song-poetry','','[]','竹色豈不好，道旁端可嗔。',24,'全唐诗/poet.song.140000.json','["竹色豈不好，道旁端可嗔。", "只教寒雨裏，將冷洒行人。"]'),
('5833196e-988f-4f42-a7ff-a24b0522d841','雨中梅花','楊萬里','宋','宋诗','song-poetry','','[]','霜晴三日不勝佳，忽作陰霖送歲華。',32,'全唐诗/poet.song.140000.json','["霜晴三日不勝佳，忽作陰霖送歲華。", "客裏清愁自無奈，却教和雨看梅花。"]'),
('364556e6-0671-4756-80f4-a9a718393359','過瘦牛嶺','楊萬里','宋','宋诗','song-poetry','','[]','行盡天涯未遣休，梅州到了又潮州。',64,'全唐诗/poet.song.140000.json','["行盡天涯未遣休，梅州到了又潮州。", "平生豈願乘肥馬，臨老須教過瘦牛。", "夢裏長驚炊劍首，春前應許賦刀頭。", "夜來尚有餘樽在，急喚渠儂破客愁。"]'),
('b94f4d26-cd40-4982-8313-d2633045d8da','題瘦牛嶺','楊萬里','宋','宋诗','song-poetry','','[]','牛頭定何向，牛尾定何指。',128,'全唐诗/poet.song.140000.json','["牛頭定何向，牛尾定何指。", "我不炙汝心，我不穿汝鼻。", "如何不許見全牛，霧隠雲藏若相避。", "行行上牛背，上下三十里。", "一雨生新泥，寸步不自致。", "胡不去作牽牛星，渴飲銀河天上水。", "胡不去作帝藉牛，天田春風牽黛耜。", "却來蠻村天盡頭，塞路長遣行人愁。", "夕陽芳草只依舊，瘦牛何苦年年瘦。"]'),
('97f65523-7d91-4056-ad2c-6b02f19f8500','道旁草木二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','山無人跡草長青，異彩奇香不識名。',32,'全唐诗/poet.song.140000.json','["山無人跡草長青，異彩奇香不識名。", "只是苔花兼蘚葉，也無半點俗塵生。"]'),
('287e1c99-098a-4eea-9922-37c0d4f227e4','道旁草木二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','古樹何年澗底生，只今已與嶺般平。',32,'全唐诗/poet.song.140000.json','["古樹何年澗底生，只今已與嶺般平。", "千梢萬葉無重數，一一分明報雨聲。"]'),
('3d10a004-c6ec-4271-8dd5-237d4475e129','葵葉','楊萬里','宋','宋诗','song-poetry','','[]','篛笠端能直幾錢，騎奴不擬雨連天。',32,'全唐诗/poet.song.140000.json','["篛笠端能直幾錢，騎奴不擬雨連天。", "蓋頭旋折山葵葉，擘破青青傘半邊。"]'),
('c8a8c47f-402a-4b94-865d-46cec03eddaa','過金沙洋望小海','楊萬里','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','海霧初開明海日，近樹遠山青歷歷。',128,'全唐诗/poet.song.140000.json','["海霧初開明海日，近樹遠山青歷歷。", "忽然咫尺黑如漆，白晝如何成暝色。", "不知一風何許來，霧開還合合還開。", "晦明百變一彈指，特地遣人驚復喜。", "海神無處逞神通，放出一斑夸客子。", "須臾滿眼賈胡船，萬頃一碧波黏天。", "恰似錢塘江上望，只無兩點海門山。", "我行但作遊山看，減却客愁九分半。"]'),
('bbd92f46-4ff5-47f1-8726-6be084b1eafa','揭陽道中二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','厭穿山徑石嶔𡼭，喜見川原路坦夷。',32,'全唐诗/poet.song.140000.json','["厭穿山徑石嶔𡼭，喜見川原路坦夷。", "更著兩行團樹子，引人行遠不教知。"]'),
('8db063a0-5398-4c0f-9f63-59ae6b49f26c','揭陽道中二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','地平如掌樹成行，野有郵亭浦有梁。',32,'全唐诗/poet.song.140000.json','["地平如掌樹成行，野有郵亭浦有梁。", "舊日潮州底處所，如今風物冠南方。"]'),
('55907d49-ad81-4cb8-824a-ea49926fb727','宿潮州海陽館獨夜不寐二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','醉來還睡睡還醒，長是三更夢便驚。',32,'全唐诗/poet.song.140000.json','["醉來還睡睡還醒，長是三更夢便驚。", "細數更聲有何益，不然作麽到天明。"]'),
('265bc101-d43b-41e6-b998-71cfcbb4b0d0','宿潮州海陽館獨夜不寐二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','臘前蚊子已能歌，揮去還來奈爾何。',32,'全唐诗/poet.song.140000.json','["臘前蚊子已能歌，揮去還來奈爾何。", "一隻攪人終夕睡，此聲元自不須多。"]'),
('1c627037-8204-49cc-b68c-3032c36a104b','謁昌黎伯廟','楊萬里','宋','宋诗','song-poetry','','[]','南海行幾徧，東潮欠一來。',48,'全唐诗/poet.song.140000.json','["南海行幾徧，東潮欠一來。", "若無韓子廟，只有越王臺。", "文字天垂日，興亡草上埃。", "聊吹鰐溪水，灑起六丁雷。"]'),
('d93a1794-6e1b-4adb-8e39-920ee0ba3a34','題韓亭韓木二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','老大韓家十八郎，猶將雲錦製衣裳。',32,'全唐诗/poet.song.140000.json','["老大韓家十八郎，猶將雲錦製衣裳。", "至今南斗無精彩，只放文星一點光。"]'),
('3dcd9b06-2a3d-4b28-ac97-6f43bfee22ee','題韓亭韓木二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','笑爲先生一問天，身前身後兩般看。',32,'全唐诗/poet.song.140000.json','["笑爲先生一問天，身前身後兩般看。", "亭前樹子關何事，也得天公賜姓韓。"]'),
('19b3deda-487b-40d9-85d2-d154e46e7b5d','登南州奇觀前臨大江浮橋江心起三石臺皆有亭子二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','梅邊樓閣海邊山，銀竹初收霽日寒。',32,'全唐诗/poet.song.140000.json','["梅邊樓閣海邊山，銀竹初收霽日寒。", "看著南州奇觀了，人間山水不須看。"]'),
('99f9fa48-258e-430e-9498-c244d2af1a4a','登南州奇觀前臨大江浮橋江心起三石臺皆有亭子二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','玉壺冰底卧青龍，海外三山墮眼中。',32,'全唐诗/poet.song.140000.json','["玉壺冰底卧青龍，海外三山墮眼中。", "奇觀揭名渾未在，只消題作小垂虹。"]'),
('bec92012-e76e-489a-b251-92debf73ce31','平賊班師明發潮州','楊萬里','宋','宋诗','song-poetry','','[]','不是潢池赤白囊，何緣杖屨到潮陽。',64,'全唐诗/poet.song.140000.json','["不是潢池赤白囊，何緣杖屨到潮陽。", "官軍已掃狐兔窟，歸路莫孤山水鄉。", "便去羅浮參玉局，更登浴日折扶桑。", "還家兒女搜行李，滿袖雲煙雪月香。"]'),
('3e71d57d-cd1b-4382-b3fa-4f60f2e0da48','潮陽海岸望海','楊萬里','宋','宋诗','song-poetry','','[]','動地驚風起海陬，爲人吹散兩眉愁。',64,'全唐诗/poet.song.140000.json','["動地驚風起海陬，爲人吹散兩眉愁。", "身行島北新春後，眼到天南最盡頭。", "衆水更來何處著，千峰赴此却回休。", "客間供給能消底，萬頃煙波一白鷗。"]'),
('45bb5808-0eeb-4f8e-9a19-6d4065330104','除夜宿石塔寺','楊萬里','宋','宋诗','song-poetry','','[]','醉後先眠客莫嗔，誰能守歲費精神。',64,'全唐诗/poet.song.140000.json','["醉後先眠客莫嗔，誰能守歲費精神。", "幸無爆竹驚寒夢，休羨椒花頌好春。", "今歲明年纔隔夕，人情物態頓趨新。", "遥憐兒女團欒處，政欠屠酥第十人。"]'),
('bdc2bc13-2368-4025-9eb2-cbbd58898a4e','壬寅歲朝發石塔寺','楊萬里','宋','宋诗','song-poetry','','[]','曉鐘夢裹苦相呼，强裹烏紗照白鬚。',64,'全唐诗/poet.song.140000.json','["曉鐘夢裹苦相呼，强裹烏紗照白鬚。", "只有銅爐燒柏子，更無玉盞瀉屠酥。", "佛桑解吐四時豔，鐵樹還如九節蒲。", "省得一朝疲造請，却教終日走長塗。"]'),
('9d710486-24c6-4228-ac1d-371da8227e65','晨炊黄岡望海','楊萬里','宋','宋诗','song-poetry','','[]','望中雪嶺界天橫，雪外青瑶甃地平。',32,'全唐诗/poet.song.140000.json','["望中雪嶺界天橫，雪外青瑶甃地平。", "白底是沙青是海，捲簾看了却心驚。"]'),
('f2fd5df4-d4fc-4642-bbf3-913e464e230e','海岸沙行','楊萬里','宋','宋诗','song-poetry','','[]','海濱半程沙上路，海風吹起成煙霧。',80,'全唐诗/poet.song.140000.json','["海濱半程沙上路，海風吹起成煙霧。", "行人合眼不敢覷，一行一步愁一步。", "步步沙痕沒芒屨，不是不行行不去。", "若爲行到無沙處，寧逢石頭齧足拇。", "寧踏黄泥濺袍袴，海濱沙路莫再度。"]'),
('cad8e173-972e-4f2e-96b5-afd1300967f4','榕樹','楊萬里','宋','宋诗','song-poetry','','[]','直不爲楹圜不輪，斧斤亦復赦渠薪。',32,'全唐诗/poet.song.140000.json','["直不爲楹圜不輪，斧斤亦復赦渠薪。", "數株連碧真成菌，一脛空肥總是筋。"]'),
('fe014a18-bebc-4a23-9afe-243c8d9ea638','食車螯','楊萬里','宋','宋诗','song-poetry','','[]','珠宮新沐浄瓊沙，石鼎初燃瀹井花。',64,'全唐诗/poet.song.140000.json','["珠宮新沐浄瓊沙，石鼎初燃瀹井花。", "紫殻旋開微滴酒，玉膚莫熟要鳴牙。", "棖拖金線成雙美，薑擘糟丘併一家。", "老子宿酲無解處，半杯羹後半甌茶。"]'),
('e1fe2135-296f-4a79-8a30-27b81b7eac31','食蠣房','楊萬里','宋','宋诗','song-poetry','','[]','蓬山側畔屹蠔山，懷玉深藏萬壑間。',32,'全唐诗/poet.song.140000.json','["蓬山側畔屹蠔山，懷玉深藏萬壑間。", "也被酒徒勾引著，薦它尊俎解它顔。"]'),
('80c1536d-e16a-4951-ba6d-e56a773251ff','食蛤蜊米脯羹','楊萬里','宋','宋诗','song-poetry','','[]','傾來百顆恰盈奩，剝作杯羹未屬厭。',64,'全唐诗/poet.song.140000.json','["傾來百顆恰盈奩，剝作杯羹未屬厭。", "莫遣下鹽傷正味，不曾著蜜若爲甜。", "雪揩玉質全身瑩，金緣冰鈿半縷纖。", "更淅香秔輕糝却，發揮風韻十分添。"]'),
('8fdf4eb9-2618-4999-85d4-308bf3012609','銀魚乾','楊萬里','宋','宋诗','song-poetry','','[]','初疑柘繭雪爭鮮，又恐楊花糝作氈。',32,'全唐诗/poet.song.140000.json','["初疑柘繭雪爭鮮，又恐楊花糝作氈。", "却是翦銀成此葉，如何入口軟於綿。"]'),
('6838f5ba-5d8a-4e7d-ad7e-42c194adc4a2','烏賊魚','楊萬里','宋','宋诗','song-poetry','','[]','秦帝東巡渡浙江，中流風緊墜書囊。',32,'全唐诗/poet.song.140000.json','["秦帝東巡渡浙江，中流風緊墜書囊。", "至今收得磨殘墨，猶带宮車載鮑香。"]'),
('6e46e347-f517-4a64-8e78-42b282b2f36a','泊流潢驛潮風大作二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','忽看草樹總離披，記得沙行昨日時。',32,'全唐诗/poet.song.140000.json','["忽看草樹總離披，記得沙行昨日時。", "除却潮來無別事，海風動地亦何爲。"]'),
('50538dde-8a33-4b02-86d5-a25b8e1ca0fc','泊流潢驛潮風大作二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','潮來潮去有何功，費盡辛勤辦一風。',32,'全唐诗/poet.song.140000.json','["潮來潮去有何功，費盡辛勤辦一風。", "若使無風潮自至，信他海伯有神通。"]'),
('e425bac9-43b8-46f1-8e52-d784e77221a8','正月三日宿范氏莊四首  其一','楊萬里','宋','宋诗','song-poetry','','[]','開歲又涉三，我征良未休。',108,'全唐诗/poet.song.140000.json','["開歲又涉三，我征良未休。", "沙行地一平，百里縱遐眸。", "景穆物自欣，磧迥情反愁。", "中田緬雲莊，聊復稅我輈。", "追程有底急，行急能至不。", "三峰從何來，駿奔若鳴騶。", "當戶不忍去，裴回爲人留。", "對之成四友，呼酒與獻酬。", "我醉山自醒，相忘却相求。"]'),
('8c071aa9-c077-4176-a1d6-8a9986e93d8f','正月三日宿范氏莊四首  其二','楊萬里','宋','宋诗','song-poetry','','[]','野踐得幽詠，不吐聊自味。',84,'全唐诗/poet.song.140000.json','["野踐得幽詠，不吐聊自味。", "健步忽傳呼，云有遠書至。", "開緘祗暄涼，此外無一事。", "奇懷坐消泯，追省寧復記。", "方驩遽成悶，俗物真敗意。", "山鵲下虛庭，對語含喜氣。", "一笑起振衣，吾心本無滯。"]'),
('e45868bf-db2e-4352-a520-ff856dc3e9e2','正月三日宿范氏莊四首  其三','楊萬里','宋','宋诗','song-poetry','','[]','酒名忘憂物，未盡酒所長。',132,'全唐诗/poet.song.140000.json','["酒名忘憂物，未盡酒所長。", "醉後忘我身，安得憂可忘。", "我飲初不多，不可無一觴。", "平生難爲酒，甘醴斷不嘗。", "要與水爭色，仍復菊敵香。", "氣盎春午花，味凜秋旭霜。", "三杯合自然，一滴詣醉鄉。", "朅來困行役，名酒安可常。", "甘淡俱不擇，芳冽那得將。", "酒味何必佳，一醉徑投床。", "但令有可飲，不醉亦何妨。"]'),
('b40c6c8e-1d94-47ee-bab3-3d5e6f7e0e45','正月三日宿范氏莊四首  其四','楊萬里','宋','宋诗','song-poetry','','[]','山歷愁寡天，沙征恨多地。',120,'全唐诗/poet.song.140000.json','["山歷愁寡天，沙征恨多地。", "兩日行海濱，雖近彌不至。", "遐瞻道旁堠，我進渠祗退。", "大風來無隔，午燠皎安避。", "今夕范氏莊，初覿三峰翠。", "愈遠故絕瑕，不多始足貴。", "巉然半几出，蹙若一拳細。", "輕霏澹晚秀，隤照燁春媚。", "翫久有餘佳，繪苦未必似。", "今夕勿掩扉，月中對山睡。"]'),
('4cb5c2cb-0d9b-4b2d-987e-ebbc79e8c65c','初四日晨炊橫翠亭','楊萬里','宋','宋诗','song-poetry','','[]','近看三峰失一峰，其餘都與昨來同。',32,'全唐诗/poet.song.140000.json','["近看三峰失一峰，其餘都與昨來同。", "多情橫翠亭前玉，伴我同行兩日中。"]'),
('3a85fe8d-331b-4c37-977d-faa337783509','人日宿味田驛','楊萬里','宋','宋诗','song-poetry','','[]','破驛荒涼晚解鞍，急呼重碧敵輕寒。',32,'全唐诗/poet.song.140000.json','["破驛荒涼晚解鞍，急呼重碧敵輕寒。", "南中氣候從頭錯，人日青梅已釅酸。"]'),
('0e3bee15-a9a1-4182-870f-af7a50cd4472','登大鞋嶺望大海','楊萬里','宋','宋诗','song-poetry','','[]','杖屨千崖表，波濤萬頃前。',48,'全唐诗/poet.song.140000.json','["杖屨千崖表，波濤萬頃前。", "瓊天吹不定，銀地濕無邊。", "一石當流出，孤尖卓筆然。", "更將垂老眼，何許看風煙。"]'),
('f11b2f75-ed34-4a0e-a114-801c8244d858','晨炊叱馭驛觀海邊野燒','楊萬里','宋','宋诗','song-poetry','','[]','南海驚濤卷玉缸，北山野燒展紅幢。',32,'全唐诗/poet.song.140000.json','["南海驚濤卷玉缸，北山野燒展紅幢。", "山神海伯爭新巧，併慰詩人眼一雙。"]'),
('330aebbd-78f7-4f29-a25d-e33354e9365d','海岸七里沙二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','大風吹起翠瑶山，近岸還成白雪團。',32,'全唐诗/poet.song.140000.json','["大風吹起翠瑶山，近岸還成白雪團。", "一浪攙先千浪怒，打崖裂石與君看。"]'),
('cc211452-d21d-42fe-bea9-7593eca363b4','海岸七里沙二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','行人莫近岸邊行，便恐波頭打倒人。',32,'全唐诗/poet.song.140000.json','["行人莫近岸邊行，便恐波頭打倒人。", "若道岸高波不到，玉沙猶濕萬痕新。"]'),
('478f2bb3-82d3-44a6-8236-964526253357','鮓魚潭登舟','楊萬里','宋','宋诗','song-poetry','','[]','船閣寒沙待晚潮，行人舟子各相招。',32,'全唐诗/poet.song.140000.json','["船閣寒沙待晚潮，行人舟子各相招。", "銀山一朶三千丈，隔海飛來對面銷。"]'),
('c01577a0-af79-4c9b-a9ed-75dea24dbcd6','宿南嶺驛二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','蕨手猶拳已箸長，菊苗初甲可羹嘗。',32,'全唐诗/poet.song.140000.json','["蕨手猶拳已箸長，菊苗初甲可羹嘗。", "山村富貴無人享，一路春風野菜香。"]'),
('e4c72d7f-0cf9-48f2-88d4-3301ada86a36','宿南嶺驛二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','茅花似雪復如茸，一望平原淺草中。',32,'全唐诗/poet.song.140000.json','["茅花似雪復如茸，一望平原淺草中。", "盡日向人揮玉麈，知將何事語春風。"]'),
('b7340ef1-24f1-489e-b38b-c801dd983c9a','初十日早炊蕉步得家書并家釀二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','潢池東定得西還，病後塗中竟鮮懽。',32,'全唐诗/poet.song.140000.json','["潢池東定得西還，病後塗中竟鮮懽。", "爲許朝來有新喜，庭闈一騎報平安。"]'),
('e6458f6f-6c44-46a1-afb1-3993d03a8510','初十日早炊蕉步得家書并家釀二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','年年自漉雪前醅，今歲無緣得一杯。',32,'全唐诗/poet.song.140000.json','["年年自漉雪前醅，今歲無緣得一杯。", "政是荒村愁絕處，家中送得六尊來。"]'),
('31a38414-d953-4c45-bb56-6e678b2e080d','惠州豐湖亦名西湖二首  其一','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','左瞰豐湖右瞰江，五峰出沒水中央。',32,'全唐诗/poet.song.140000.json','["左瞰豐湖右瞰江，五峰出沒水中央。", "峰頭寺寺樓樓月，清殺東坡錦繡腸。"]'),
('69ac0b1e-a864-450e-b2a1-1aaa902f54c2','惠州豐湖亦名西湖二首  其二','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','三處西湖一色秋，錢塘潁水更羅浮。',32,'全唐诗/poet.song.140000.json','["三處西湖一色秋，錢塘潁水更羅浮。", "東坡元是西湖長，不到羅浮便得休。"]'),
('d394fd34-c19c-46ac-be16-a14e92f20da8','正月十二日游東坡白鶴峰故居其北思無邪齋真蹟猶存','楊萬里','宋','宋诗','song-poetry','','[]','詩人自古例遷謫，蘇李夜郎并惠州。',272,'全唐诗/poet.song.140000.json','["詩人自古例遷謫，蘇李夜郎并惠州。", "人言造物困嘲弄，故遣各捉一處囚。", "不知天公愛佳句，曲與詩人爲地頭。", "詩人眼底高四海，萬象不足供詩愁。", "帝將湖海賜湯沐，僅僅可以當冥搜。", "却令玉堂揮翰手，爲提椽筆判羅浮。", "羅浮山色濃潑黛，豐湖水光先得秋。", "東坡日與群仙遊，朝發崑閬夕不周。", "雲冠霞佩照宇宙，金章玉句鳴天球。", "但登詩壇將騷雅，底用蟻穴封王侯。", "元符諸賢下石者，祗與千載掩鼻羞。", "我來剝啄王粲宅，鶴峰無恙江空流。", "安知先生百歲後，不來弄月白蘋洲。", "無人挽住乞一句，猶道雪乳冰湍不。", "當年醉裏題壁處，六丁已遣雷電收。", "獨遺無邪四箇字，鸞飄鳳泊蟠銀鈎。", "如今亦無合江樓，嘉祐破寺風颼颼。"]'),
('7d16d0f0-078b-4ba7-94c1-806b289c6da3','解舟惠州東橋','楊萬里','宋','宋诗','song-poetry','','[]','南宦寧差北，西歸敢再東。',48,'全唐诗/poet.song.140000.json','["南宦寧差北，西歸敢再東。", "猿聲雲樹月，客枕露船風。", "綠髮春全白，蒼顔酒不紅。", "莫憎愁與病，留取伴衰翁。"]'),
('42ab9978-4712-4b4c-b8bf-ab52eeaefc06','放船','楊萬里','宋','宋诗','song-poetry','','[]','岸岸人家住，門門面水開。',48,'全唐诗/poet.song.140000.json','["岸岸人家住，門門面水開。", "老翁扶杖立，穉子看船來。", "一夜鳴春雨，諸灘漲綠醅。", "順流行自快，更著北風催。"]'),
('116a82ba-fe8a-4c3a-9426-5b6bb8727964','感興','楊萬里','宋','宋诗','song-poetry','','[]','行役忘衰暮，逢春感物華。',48,'全唐诗/poet.song.140000.json','["行役忘衰暮，逢春感物華。", "一來梅嶺外，三見木綿花。", "山鹿寧游市，江鷗本卧沙。", "紅塵無了日，白髮未還家。"]'),
('2f55a6f1-b83c-45d1-91ac-fb5232cca342','夜泊曲灣','楊萬里','宋','宋诗','song-poetry','','[]','順流一日快舟行，薄暮風濤特地生。',32,'全唐诗/poet.song.140000.json','["順流一日快舟行，薄暮風濤特地生。", "不是江神驚客子，勸人早泊莫追程。"]'),
('bc901730-77a0-4264-b6f8-98b217c5f22f','曲灣放船','楊萬里','宋','宋诗','song-poetry','','[]','梅子成陰夾道周，木綿吐焰滿江頭。',32,'全唐诗/poet.song.140000.json','["梅子成陰夾道周，木綿吐焰滿江頭。", "春來不是無桃李，臘月開花已落休。"]'),
('67aa9ff4-c9a2-42e7-908a-2e83a43c80b8','石灣雨作得鞏帥采若書約觀燈','楊萬里','宋','宋诗','song-poetry','','[]','昨暮顛風浪打頭，那知今日得安流。',64,'全唐诗/poet.song.140000.json','["昨暮顛風浪打頭，那知今日得安流。", "元宵不爲遊人好，細雨先供客子愁。", "病骨支離妨酒盞，詩仙招喚試燈毬。", "書生薄命多磨折，樂事良辰判却休。"]'),
('22045ad7-24b4-4d1c-884f-d2f64afeea9b','舟中望羅浮山','楊萬里','宋','宋诗','song-poetry','','[]','羅浮元不是羅浮，自是道家古蓬丘。',160,'全唐诗/poet.song.140000.json','["羅浮元不是羅浮，自是道家古蓬丘。", "弱水只知斷舟楫，葛仙夜偷來惠州。", "羅浮山高七萬丈，下視日月地上流。", "黄金爲橋接銀漢，翠琳作闕橫瓊樓。", "不知何人汗脚迹，觸忤清虛涴寒碧。", "天遣山鬼絕凡客，化金爲鐵瓊爲石。", "至今石樓人莫登，鐵橋不見空有名。", "玉匙金籥牢鎖扃，但見山高水泠泠。", "我欲騎麟翳鸞鳳，月爲環佩星爲從。", "前驅子晉後安期，飛上峰頭斸丹汞。"]'),
('a4ed1f85-4211-43f4-a53f-134ebe304b5e','南海東廟浴日亭','楊萬里','宋','宋诗','song-poetry','','[]','南海端爲四海魁，扶胥絕境信奇哉。',64,'全唐诗/poet.song.140000.json','["南海端爲四海魁，扶胥絕境信奇哉。", "日從若木梢頭轉，潮到占城國裏回。", "最愛五更紅浪沸，忽吹萬里紫霞開。", "天公管領詩人眼，銀漢星槎借一來。"]'),
('a570c3fc-8d3e-4f39-8a13-c59fd491f667','題南海東廟','楊萬里','宋','宋诗','song-poetry','','[]','羅浮山如萬石鍾，一股南走如渴龍。',192,'全唐诗/poet.song.140000.json','["羅浮山如萬石鍾，一股南走如渴龍。", "雷奔電邁遮不住，直抵海濱無去處。", "低頭飲海吐絳霞，舉頭戴著祝融家。", "珠宮玉室水精殿，萬水一日朝再衙。", "青山四圍作城郭，海濤半浸青山脚。", "客來莫上浴日亭，亭上見海君始驚。", "青山缺處如玉玦，潮頭飛來打雙闕。", "晴天無雲濺碎雪，天下都無此奇絕。", "大海更在小海東，西廟不如東廟雄。", "南來若不到東廟，西京未睹建章宮。", "海神喜我著綺語，爲我改容收霧雨。", "乾坤軒豁未能許，小試日光穿漏句。"]'),
('ad0b4968-69e4-4606-b118-02a0b5c34282','鑷白','楊萬里','宋','宋诗','song-poetry','','[]','止酒愁無那，哦詩意已闌。',24,'全唐诗/poet.song.140000.json','["止酒愁無那，哦詩意已闌。", "鑷髭非急務，也遣半時閑。"]'),
('fafa2551-6b72-4b52-9a9a-0b346371a226','和鞏采若游蒲澗','楊萬里','宋','宋诗','song-poetry','','[]','南中道是島夷居，也有安期宅一區。',64,'全唐诗/poet.song.140000.json','["南中道是島夷居，也有安期宅一區。", "屐齒苔痕猶故跡，霓旌鸞佩已清都。", "元戎解領三千騎，勝日來尋九節蒲。", "萬壑松風和澗水，鳴琴漱玉自相娛。"]'),
('5a7d9276-bd47-4ae4-8862-ff8f8d7ddcc8','船過靈洲','楊萬里','宋','宋诗','song-poetry','','[]','却緣野闊覺天低，政值潮平苦槳遲。',64,'全唐诗/poet.song.140000.json','["却緣野闊覺天低，政值潮平苦槳遲。", "洲觜兩船歸別港，岸頭數屋出疎籬。", "江山慘淡真如畫，煙雨空濛自一奇。", "病酒春眠不知曉，開門拾得一篇詩。"]'),
('1eeb3808-07dd-498e-8be8-b610bab02edc','近岸','楊萬里','宋','宋诗','song-poetry','','[]','十日都無一日晴，牽船客子總斜行。',32,'全唐诗/poet.song.140000.json','["十日都無一日晴，牽船客子總斜行。", "一川黄犢朝朝飽，岸草何曾減寸青。"]'),
('41095d63-251c-4f96-a807-4f819499d5e7','泊鴨步','楊萬里','宋','宋诗','song-poetry','','[]','江流自在水風輕，雲去天來半欲晴。',32,'全唐诗/poet.song.140000.json','["江流自在水風輕，雲去天來半欲晴。", "兩岸東西三十里，李花獨樹隔江明。"]'),
('515cc280-e300-46eb-ba7d-b5da44904e44','明發鴨步','楊萬里','宋','宋诗','song-poetry','','[]','兩歲春船各一時，今年船快去年遲。',32,'全唐诗/poet.song.140000.json','["兩歲春船各一時，今年船快去年遲。", "青山面目何曾改，清曉看來別樣奇。"]'),
('cf797786-4135-49d3-8c52-47372d7bcf40','過黄巢磯','楊萬里','宋','宋诗','song-poetry','','[]','黄巢磯與白沙灘，只是聞名已膽寒。',32,'全唐诗/poet.song.140000.json','["黄巢磯與白沙灘，只是聞名已膽寒。", "自笑南來三換歲，一年一度犯驚湍。"]'),
('f23bf564-9c60-4a66-a2c3-193fe8893d85','望清遠峽','楊萬里','宋','宋诗','song-poetry','','[]','刺船又入峽山間，江水初平失惡灘。',32,'全唐诗/poet.song.140000.json','["刺船又入峽山間，江水初平失惡灘。", "道是峽山天下險，老夫今作坦塗看。"]'),
('6eb2e5e9-005b-414c-8bca-b4041805ec93','舟人吹笛','楊萬里','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','長江無風水平綠，也無靴文也無縠。',96,'全唐诗/poet.song.140000.json','["長江無風水平綠，也無靴文也無縠。", "東西一望光浮空，瑩然千頃無瑕玉。", "船上兒郎不耐閑，醉拈橫笛吹雲煙。", "一聲清長響徹天，山猿啼月澗落泉。", "更打羊皮小腰鼓，頭如青峰手如雨。", "中流忽有一大魚，跳破琉璃丈來許。"]'),
('6bcecae5-eee6-46c6-9f40-3c7d89877f17','近峽','楊萬里','宋','宋诗','song-poetry','','[]','望峽初愁遠，當前忽不知。',24,'全唐诗/poet.song.140000.json','["望峽初愁遠，當前忽不知。", "如何船進處，却在棹停時。"]'),
('d52399ed-6cc4-44f0-987f-b8d7d8e2e9cc','清遠峽四首  其一','楊萬里','宋','宋诗','song-poetry','','[]','峽水都是泉，非雨元自足。',48,'全唐诗/poet.song.140000.json','["峽水都是泉，非雨元自足。", "不知幾滴珠，成此一川玉。", "旁將山染翠，仰爲天寫綠。", "何當雪月夜，孤艇葦間宿。"]'),
('6d29abd5-95bd-4fd8-86ef-fd2bb90d923b','清遠峽四首  其二','楊萬里','宋','宋诗','song-poetry','','[]','清晨霧雨重，不敢開船門。',48,'全唐诗/poet.song.140000.json','["清晨霧雨重，不敢開船門。", "小窗試微啟，逗入一船雲。", "何曾燒龍麝，香霏遶吾身。", "身在雲水上，何許覓點塵。"]'),
('f1460be9-0b7d-4f0f-b56a-078034fc6362','清遠峽四首  其三','楊萬里','宋','宋诗','song-poetry','','[]','清遠望峽山，山脚無半里。',48,'全唐诗/poet.song.140000.json','["清遠望峽山，山脚無半里。", "小舟行其間，五日翠未已。", "並馳兩蒼龍，中夾一玉水。", "送我到英州，渠當自回轡。"]'),
('708a0d6c-8332-4484-8e58-45eb83571d0b','清遠峽四首  其四','楊萬里','宋','宋诗','song-poetry','','[]','誰開峽山寺，政要避世喧。',48,'全唐诗/poet.song.140000.json','["誰開峽山寺，政要避世喧。", "深潭無來路，斷崖有青天。", "療饑摘山果，擊磬煩嶺猿。", "人跡今擾擾，祗緣一漁船。"]'),
('292d8b20-53f3-4583-bcd0-3a01b4108ca2','光口夜雨','楊萬里','宋','宋诗','song-poetry','','[]','峽江清空峽雨急，寒聲夜半蕭蕭發。',64,'全唐诗/poet.song.140000.json','["峽江清空峽雨急，寒聲夜半蕭蕭發。", "玻瓈盆面跳萬珠，一顆一聲清入骨。", "夢中搔首起來聽，聽來聽去到天明。", "一生聽雨今頭白，不識春江夜雨聲。"]'),
('1ff53aed-a388-4d52-9634-a6d08fef06cf','出真陽峽十首  其一','楊萬里','宋','宋诗','song-poetry','','[]','過盡危磯出小潭，回頭失却石峰巉。',32,'全唐诗/poet.song.140000.json','["過盡危磯出小潭，回頭失却石峰巉。", "春寒料峭元無事，知我猶藏一布衫。"]'),
('97548948-2810-44d5-9de4-552ae5e9a67c','出真陽峽十首  其二','楊萬里','宋','宋诗','song-poetry','','[]','細雨初來刺水紋，三針兩線未教繁。',32,'全唐诗/poet.song.140000.json','["細雨初來刺水紋，三針兩線未教繁。", "不知忽有何忙處，急洒千千萬萬痕。"]'),
('cb03c92e-5cbe-4ce3-9c14-4af0dc50a4f0','出真陽峽十首  其三','楊萬里','宋','宋诗','song-poetry','','[]','峽嶺分明是假山，亂堆怪石入雲間。',32,'全唐诗/poet.song.140000.json','["峽嶺分明是假山，亂堆怪石入雲間。", "上頭更種青瓊樹，下照春江玉鏡寒。"]'),
('329ab3ac-d28f-4d8d-bc46-f33a1cf4498a','出真陽峽十首  其四','楊萬里','宋','宋诗','song-poetry','','[]','峽中出了又逢灘，破浪牽船分外難。',32,'全唐诗/poet.song.140000.json','["峽中出了又逢灘，破浪牽船分外難。", "只是峽山臨欲別，此灘留我再看山。"]'),
('6ea4aa21-e464-4bbd-8b18-f52a8d2a9e99','出真陽峽十首  其五','楊萬里','宋','宋诗','song-poetry','','[]','江楓新染綠衣衫，知費春風幾把藍。',32,'全唐诗/poet.song.140000.json','["江楓新染綠衣衫，知費春風幾把藍。", "道是春光在桃李，試除桃李儘教參。"]'),
('d1f0d287-c34a-4122-98e5-c127bf7d66e4','出真陽峽十首  其六','楊萬里','宋','宋诗','song-poetry','','[]','入峽長思出峽行，出來却憶峽中清。',32,'全唐诗/poet.song.140000.json','["入峽長思出峽行，出來却憶峽中清。", "一江碧水供詩硯，兩岸青山作硯屏。"]'),
('bf179b39-6d84-4b94-9402-0015c7a53d43','出真陽峽十首  其七','楊萬里','宋','宋诗','song-poetry','','[]','只言英石冠南中，未識真陽一兩峰。',32,'全唐诗/poet.song.140000.json','["只言英石冠南中，未識真陽一兩峰。", "遮莫坡陀將不去，將詩描取小玲瓏。"]'),
('0fbd3c86-6fe5-48f5-8640-394f40de864c','出真陽峽十首  其八','楊萬里','宋','宋诗','song-poetry','','[]','今歲春流漲又銷，水痕猶印石間茅。',32,'全唐诗/poet.song.140000.json','["今歲春流漲又銷，水痕猶印石間茅。", "浮槎却被春流誤，長掛江邊小樹梢。"]'),
('1d2ac0bc-24b5-421d-861a-023f55fb85d2','出真陽峽十首  其九','楊萬里','宋','宋诗','song-poetry','','[]','春光濃裏更江行，畫舫分明是水亭。',32,'全唐诗/poet.song.140000.json','["春光濃裏更江行，畫舫分明是水亭。", "出了真陽恰惆悵，數峰如笋雨中青。"]'),
('2833922c-5655-48db-bda6-d98f63f78792','出真陽峽十首  其一○','楊萬里','宋','宋诗','song-poetry','','[]','未必陽山天下窮，英州窮到骨中空。',32,'全唐诗/poet.song.140000.json','["未必陽山天下窮，英州窮到骨中空。", "郡官只怨無供給，支與真陽數石峰。"]'),
('d42e53c9-1967-4bcf-9a0d-cbb3dd9be09b','山雲','楊萬里','宋','宋诗','song-poetry','','[]','春從底處領雲來，日日山頭絮作堆。',32,'全唐诗/poet.song.140000.json','["春從底處領雲來，日日山頭絮作堆。", "戀著好峰那肯去，欲開猶遶兩三回。"]'),
('e33994b2-e626-4776-82f0-55e5e8ecff23','碧落洞前灘水三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','水知山近已先狂，箭往星奔趁下瀧。',32,'全唐诗/poet.song.140000.json','["水知山近已先狂，箭往星奔趁下瀧。", "灘下洄流能耐事，漩漚百轉看它忙。"]'),
('7bc50d0a-7125-4606-8d2e-d218bcba1f15','碧落洞前灘水三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','石峰背後即英州，只不教人到岸頭。',32,'全唐诗/poet.song.140000.json','["石峰背後即英州，只不教人到岸頭。", "羅带春風吹不直，故將數摺惱行舟。"]'),
('e36dec4f-7ce3-4cba-8490-b566e955e4f0','碧落洞前灘水三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','碧落峰前上一灘，篙師叫得口都乾。',32,'全唐诗/poet.song.140000.json','["碧落峰前上一灘，篙師叫得口都乾。", "開門將謂船行遠，只在峰頭蘆荻灣。"]'),
('28f316a3-77ba-4333-b186-aa2e0260f681','北風','楊萬里','宋','宋诗','song-poetry','','[]','山雨無休歇，江雲政鬰葱。',48,'全唐诗/poet.song.140000.json','["山雨無休歇，江雲政鬰葱。", "如何急灘水，更著打頭風。", "草作傷心碧，花能可意紅。", "一年春好處，却在道塗中。"]'),
('cad24563-90f8-43f6-9ff4-af15c28cef77','正月二十八日峽外見燕子二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','社日今年定幾時，元宵過了燕先歸。',32,'全唐诗/poet.song.140000.json','["社日今年定幾時，元宵過了燕先歸。", "一雙貼水嬌無奈，不肯平飛故仄飛。"]'),
('431d1f5e-2f48-4641-b6d4-5fe22a1c766e','正月二十八日峽外見燕子二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','不宿青楓學子規，不穿綠柳伴鶑啼。',32,'全唐诗/poet.song.140000.json','["不宿青楓學子規，不穿綠柳伴鶑啼。", "雙飛只愛清江水，自喜身輕照舞衣。"]'),
('f8304694-88a4-4723-bb7d-4786225861fc','回望峽山二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','英州挽不來，峽山推不去。',24,'全唐诗/poet.song.140000.json','["英州挽不來，峽山推不去。", "行了一日船，依舊朝來處。"]'),
('9750866f-4cd0-4563-9667-aa16d608e7c4','回望峽山二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','浪喜出峽來，峽亦何曾出。',24,'全唐诗/poet.song.140000.json','["浪喜出峽來，峽亦何曾出。", "兩岸只無山，依舊江刻屈。"]'),
('70ce3f0d-7569-4f3f-a03d-806d6c97c987','碧落洞四首  其一','楊萬里','宋','宋诗','song-poetry','','[]','碧落諸峰是碧簪，忽於平地插瑶岑。',32,'全唐诗/poet.song.140000.json','["碧落諸峰是碧簪，忽於平地插瑶岑。", "洞中定有神仙宅，玉室金堂不可尋。"]'),
('90008628-1814-4487-9a7c-942ca58b0754','碧落洞四首  其二','楊萬里','宋','宋诗','song-poetry','','[]','夢中曾泊洞前船，落絮飛花是去年。',32,'全唐诗/poet.song.140000.json','["夢中曾泊洞前船，落絮飛花是去年。", "今日來尋泊船處，一江風雨草連天。"]'),
('69374da4-ccc1-42e7-b344-ac64d6d712a1','碧落洞四首  其三','楊萬里','宋','宋诗','song-poetry','','[]','洞裏仙人枉費功，鑿江屈曲做神通。',32,'全唐诗/poet.song.140000.json','["洞裏仙人枉費功，鑿江屈曲做神通。", "千縈萬繞留江住，畢竟奔流入峽中。"]'),
('78bbd489-75f5-4122-a1c1-23a238c5800e','碧落洞四首  其四','楊萬里','宋','宋诗','song-poetry','','[]','際會諸灘吼怒雷，遭逢江勢更縈回。',32,'全唐诗/poet.song.140000.json','["際會諸灘吼怒雷，遭逢江勢更縈回。", "今宵不到英州定，何用山雲送雨來。"]'),
('6395f648-5e75-4784-928f-f43b4d3a4908','郎石峰','楊萬里','宋','宋诗','song-poetry','','[]','四旁不與衆山連，特地孤尖立半天。',32,'全唐诗/poet.song.140000.json','["四旁不與衆山連，特地孤尖立半天。", "碧落諸峰非不好，讓它郎石一峰先。"]'),
('368bcf21-4a44-4115-a8d0-870e91289c10','正月晦日自英州舍舟出陸北風大作','楊萬里','宋','宋诗','song-poetry','','[]','北風吹得山石裂，北風凍得人骨折。',64,'全唐诗/poet.song.140000.json','["北風吹得山石裂，北風凍得人骨折。", "南來何曾識此寒，便恐明朝丈深雪。", "今朝幸不就船行，白浪打船君更驚。", "只是山行也不好，笋輿寸步風吹倒。"]'),
('f36b7c96-d7b9-470c-99e1-cf2125f22f7e','英石鋪道中','楊萬里','宋','宋诗','song-poetry','','[]','一路石山春更綠，見骨也無斤許肉。',128,'全唐诗/poet.song.140000.json','["一路石山春更綠，見骨也無斤許肉。", "一峰過了一峰來，病眼將迎看不足。", "先生盡日行石間，恰如蟻子緣假山。", "穿雲渡水千萬曲，此身元不離巖巒。", "莫嫌宿處破茅屋，四方八面森冰玉。", "孤峰高絕連峰低，圜者如廩尖如錐。", "蒼然秀色借不得，春風領入玉東西。", "英州那得許多石，誤入天公假山國。"]'),
('8a3d2802-773d-4b30-ad77-5acabd8cfd7b','神堂鋪前桃花','楊萬里','宋','宋诗','song-poetry','','[]','北江二月政春寒，初見桃花喜未殘。',32,'全唐诗/poet.song.140000.json','["北江二月政春寒，初見桃花喜未殘。", "臘月潮州見桃李，元來不作好春看。"]'),
('aa98d667-8d8a-417c-9905-042c41521609','過陳公逕二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','去歲陳公逕裏松，船中仰看愛松風。',32,'全唐诗/poet.song.140000.json','["去歲陳公逕裏松，船中仰看愛松風。", "只今身在松風裏，下看江船西復東。"]'),
('1dd3072a-6ed1-410c-8055-a43355ee77c9','過陳公逕二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','江行十日厭船遲，却換籃輿踏路泥。',32,'全唐诗/poet.song.140000.json','["江行十日厭船遲，却換籃輿踏路泥。", "江水別來纔兩日，陳公逕下再相隨。"]'),
('0ab3a740-c230-4d76-a614-f6f0bf48a2e7','鵝鼻鋪前桃花','楊萬里','宋','宋诗','song-poetry','','[]','歸來長恐已春遲，恰是東風二月時。',32,'全唐诗/poet.song.140000.json','["歸來長恐已春遲，恰是東風二月時。", "路上桃花亦懽喜，爲人濃抹濕燕支。"]'),
('20a8bfab-d17d-4cfd-ad53-fd17d063c8d6','南華道中二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','清曉新晴物物熙，小風淡日暖歸旗。',32,'全唐诗/poet.song.140000.json','["清曉新晴物物熙，小風淡日暖歸旗。", "不堪回首南華路，去歲梅花細雨時。"]'),
('ba7dcbfe-ead7-4ea5-a8c6-5bc50001feab','南華道中二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','騎吏歡呼不要嗔，二千里外北歸人。',32,'全唐诗/poet.song.140000.json','["騎吏歡呼不要嗔，二千里外北歸人。", "殷勤自掬曹溪水，浄洗先生面上塵。"]'),
('db61f819-069e-4b41-83ef-4846138fbe69','荔枝歌','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','粵犬吠雪非差事，粵人語冰夏蟲似。',160,'全唐诗/poet.song.140000.json','["粵犬吠雪非差事，粵人語冰夏蟲似。", "北人冰雪作生涯，冰雪一窖活一家。", "帝城六月日卓午，市人如炊汗如雨。", "賣冰一聲隔水來，行人未喫心眼開。", "甘霜甜雪如壓蔗，年年窨子南山下。", "去年藏冰減工夫，山鬼失守嬉西湖。", "北風一夜動地惡，盡吹北冰作南雹。", "飛來嶺外荔枝梢，絳衣朱裳紅錦包。", "三危露珠凍寒泚，火傘燒林不成水。", "北人藏冰天奪之，却與南人銷暑氣。"]'),
('896dab39-69af-4712-a306-005294964da6','嘗瓜二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','病骨那禁暑，衰年更作愁。',48,'全唐诗/poet.song.140000.json','["病骨那禁暑，衰年更作愁。", "有風依舊熱，初伏幾時秋。", "瓜果誰新餉，饞涎小忍休。", "金盆井花水，且看玉雙浮。"]'),
('c6c64e73-fa4c-4c2b-a359-fdee2c5911ba','嘗瓜二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','風露盈籃至，甘香隔壁聞。',48,'全唐诗/poet.song.140000.json','["風露盈籃至，甘香隔壁聞。", "綠摶罌一搦，白裂玉平分。", "蘚甃開冰段，梅山失火雲。", "老夫供晚酌，不用辦羶葷。"]'),
('57c02451-354c-470f-8992-2e9b9dd3e033','讀武惠妃傳','楊萬里','宋','宋诗','song-poetry','','[]','桂折秋風露折蘭，千花無朶可天顔。',32,'全唐诗/poet.song.140000.json','["桂折秋風露折蘭，千花無朶可天顔。", "壽王不忍金宮冷，獨獻君王一玉環。"]'),
('720beb22-b4d1-428e-920d-d5bce190e78f','聖筆石湖大字歌','楊萬里','宋','宋诗','song-poetry','','[]','石湖仙人補天手，整頓乾坤屈伸肘。',224,'全唐诗/poet.song.140000.json','["石湖仙人補天手，整頓乾坤屈伸肘。", "爾來化作懶卧龍，簸弄珠璣漱瓊玖。", "五雲萬里天九重，玉皇深拱蓬萊宮。", "豈無九虎守閶闔，北門半扉當朔風。", "夜令雲師敕風伯，鞭起卧龍湖底月。", "湖水卷上天中央，却煩北門護風雪。", "仙人馭風乘綠雲，玉宸殿上朝帝真。", "帝將北斗酌天酒，冰桃碧藕脯麒麟。", "傳呼玉蜍吸銀浦，黟霜調冰澆月兔。", "灑成羲畫河洛書，白璧一雙浮雨露。", "石湖二字天上歸，奎星壁宿落山扉。", "昭回下飾吳花草，姑蘇臺前近太微。", "詩人不直一杯水，自是渠儂命如紙。", "教人妬殺石湖仙，手攬星辰懷袖底。"]'),
('33fe7ea4-9f1f-421f-8e82-eef0223f4f46','淳熙甲辰十月一日擬省試萬民觀治象詩','楊萬里','宋','宋诗','song-poetry','','[]','魏闕春風裏，王城曉日端。',72,'全唐诗/poet.song.140000.json','["魏闕春風裏，王城曉日端。", "三朝垂治象，萬姓得榮觀。", "老穉看如堵，章程炳若丹。", "九天新雨露，一札妙龍鸞。", "遠覽周官舊，重瞻漢詔寬。", "歡聲將喜氣，銷盡柳邊寒。"]'),
('f059cc17-d8c7-46fa-b512-58c53e892d89','仲冬詔追造朝供尚書郎職舟行阻風青泥三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','東闕催人赴赤墀，北風欄我泊青泥。',32,'全唐诗/poet.song.140000.json','["東闕催人赴赤墀，北風欄我泊青泥。", "會當老子有行日，未信北風無住時。"]'),
('1b0f62a4-f9f5-470d-ad4b-174fc7b9e288','仲冬詔追造朝供尚書郎職舟行阻風青泥三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','破籬外面即江流，枯樹梢頭總客愁。',32,'全唐诗/poet.song.140000.json','["破籬外面即江流，枯樹梢頭總客愁。", "隔水遠山濃復淡，殷勤點綴一川秋。"]'),
('0731aa39-2b73-40ed-b16f-e94cc640b581','仲冬詔追造朝供尚書郎職舟行阻風青泥三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','江神風伯戰方酣，北浪吹翻總向南。',32,'全唐诗/poet.song.140000.json','["江神風伯戰方酣，北浪吹翻總向南。", "未放人扶下江柁，却教眼看上江帆。"]'),
('5c771e6e-1431-41ae-b581-7bd5c78ead87','明發青泥衝雪刺船三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','冰棹風船雪滿篷，詩人醉卧水晶宮。',32,'全唐诗/poet.song.140000.json','["冰棹風船雪滿篷，詩人醉卧水晶宮。", "追程未到君休問，且啟瓊窗看玉峰。"]'),
('0e17a029-a051-473f-9f16-9529fd57299f','明發青泥衝雪刺船三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','碧玉波頭綠錦絪，玉妃踏舞襪生塵。',32,'全唐诗/poet.song.140000.json','["碧玉波頭綠錦絪，玉妃踏舞襪生塵。", "先生奇觀誰分却，不分孤舟獨釣人。"]'),
('388828d5-0604-4ccc-ac28-0f8e59735d20','明發青泥衝雪刺船三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','紅玉麒麟未作灰，自溫瓊液寫銀杯。',32,'全唐诗/poet.song.140000.json','["紅玉麒麟未作灰，自溫瓊液寫銀杯。", "雪花萬片江千頃，更欠人間底物來。"]'),
('38743539-a63d-4f90-81cc-9f0920252fb3','過招賢渡','楊萬里','宋','宋诗','song-poetry','','[]','歸船舊掠招賢渡，惡灘橫將船閣住。',64,'全唐诗/poet.song.140000.json','["歸船舊掠招賢渡，惡灘橫將船閣住。", "風吹日炙衣滿沙，嫗牽兒啼投店家。", "一生憎殺招賢柳，一生愛殺招賢酒。", "柳曾爲我礙歸舟，酒曾爲我消詩愁。"]'),
('44e5dc76-f1f6-4894-9bca-ef9ab64bb693','三衢登舟午睡','楊萬里','宋','宋诗','song-poetry','','[]','午思昏昏不肯醒，倦投竹枕睡難成。',32,'全唐诗/poet.song.140000.json','["午思昏昏不肯醒，倦投竹枕睡難成。", "曉然有夢疑非夢，聽得人聲及水聲。"]'),
('fb19c639-0621-405e-852f-4c60278ad679','望橫山塔','楊萬里','宋','宋诗','song-poetry','','[]','水面生風分外嚴，竹根剩雪更新添。',32,'全唐诗/poet.song.140000.json','["水面生風分外嚴，竹根剩雪更新添。", "六年不見橫山塔，茅屋東邊忽半尖。"]'),
('17c78128-d901-410a-a226-2a6940ce9f5a','曉泊蘭溪','楊萬里','宋','宋诗','song-poetry','','[]','金華山高九天半，夜雪裝成珠玉案。',112,'全唐诗/poet.song.140000.json','["金華山高九天半，夜雪裝成珠玉案。", "蘭溪水清千頃强，朔風凍作瑠璃釭。", "日光雪光兩相射，病眼看來忘南北。", "恨身不如波上鷗，脚指爲楫身爲舟。", "恨身不如沙上雁，蘆花作家梅作伴。", "折綿冰酒未是寒，曉寒真欲冰我肝。", "急閉篛篷擁爐去，竹葉梨花十分注。"]'),
('3cbfd6cf-f4f9-41c6-92b9-05b00577812b','蘭溪解舟四首  其一','楊萬里','宋','宋诗','song-poetry','','[]','兩岸千千萬萬峰，看來冷白復寒紅。',32,'全唐诗/poet.song.140000.json','["兩岸千千萬萬峰，看來冷白復寒紅。", "人言雪嶺非銀嶺，三日晴光曬不融。"]'),
('5efd23e2-61f4-4079-aeaa-711d6e9ad0b6','蘭溪解舟四首  其二','楊萬里','宋','宋诗','song-poetry','','[]','日開五色暖征裘，雪滿羣山爽病眸。',32,'全唐诗/poet.song.140000.json','["日開五色暖征裘，雪滿羣山爽病眸。", "道是詩人窮到骨，暖邊爽裏放蘭舟。"]'),
('3c5750f1-f0d7-4b49-9a6a-f8ffbbb45013','蘭溪解舟四首  其三','楊萬里','宋','宋诗','song-poetry','','[]','只愁灘淺閣行舟，到得江深又不流。',32,'全唐诗/poet.song.140000.json','["只愁灘淺閣行舟，到得江深又不流。", "水鳥避人飛不徹，看他沒去看他浮。"]'),
('dd22334f-0951-4d0d-93d0-f80fd60554b9','蘭溪解舟四首  其四','楊萬里','宋','宋诗','song-poetry','','[]','際晚江風刮面來，曉寒已去却重回。',32,'全唐诗/poet.song.140000.json','["際晚江風刮面來，曉寒已去却重回。", "也知青女嫁滕六，巽二何須强作媒。"]'),
('f24688a7-d130-4c63-baa4-6b814ce00f4f','梳頭看可正平詩有寄養直時未祝髮等篇戲題七字二首  其一','楊萬里','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','却因理髮得披文，看盡廬山筆底春。',32,'全唐诗/poet.song.140000.json','["却因理髮得披文，看盡廬山筆底春。", "寄語可師休祝髮，癩邊猶有去年痕。"]'),
('330bd450-8a28-4191-a847-922437a5fe22','梳頭看可正平詩有寄養直時未祝髮等篇戲題七字二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','老子平生湯餠腸，客間湯餠亦何嘗。',32,'全唐诗/poet.song.140000.json','["老子平生湯餠腸，客間湯餠亦何嘗。", "怪來今晚加餐飯，一味盧山笋蕨香。"]'),
('b909b60e-ed72-45e3-b7fe-4705d31d1822','暮泊鼠山聞明朝有石塘之險','楊萬里','宋','宋诗','song-poetry','','[]','下水船逢上水船，夕陽仍更澀沙灘。',64,'全唐诗/poet.song.140000.json','["下水船逢上水船，夕陽仍更澀沙灘。", "雁來野鴨却驚起，我與舟人俱仰看。", "回望雪邊山已遠，如何篷底暮猶寒。", "今宵莫說明朝路，萬石堆心一急湍。"]'),
('39d3433d-0643-44c1-a932-14fb7a1fbf64','夜泊釣臺小酌','楊萬里','宋','宋诗','song-poetry','','[]','牛狸送我止嚴陵，黄雀隨人或帝城。',32,'全唐诗/poet.song.140000.json','["牛狸送我止嚴陵，黄雀隨人或帝城。", "海錯未來鄉味盡，一杯今夕笑先生。"]'),
('e1bfd741-576e-4830-8b17-8668c0532ae4','追和尤延之檢詳紫宸殿賀雪','楊萬里','宋','宋诗','song-poetry','','[]','錫山詩老立層霄，黄竹賡歌宴在瑶。',64,'全唐诗/poet.song.140000.json','["錫山詩老立層霄，黄竹賡歌宴在瑶。", "有客夢中聞雪作，曲肱篷底信船摇。", "遥知端葉飄香袖，笑向梅花趁早朝。", "未嘆山人負猿鶴，負渠縮項與長腰。"]'),
('d9e5d952-4e27-4257-b7e4-3d520319330e','和陳蹇叔郎中乙巳上元晴和','楊萬里','宋','宋诗','song-poetry','','[]','御柳梢頭晚不風，官梅面上雪都融。',64,'全唐诗/poet.song.140000.json','["御柳梢頭晚不風，官梅面上雪都融。", "如何閶闔新春夜，頓有芙蕖滿眼紅。", "十里沙河人最閙，三千世界月方中。", "買燈莫費東坡紙，今歲鼇山不入宮。"]'),
('3277705c-4b4c-4a61-bfc1-b1ec0dfcbf58','二月望日遞宿南宮和尤延之右司郎署疏竹之韻','楊萬里','宋','宋诗','song-poetry','','[]','此君見我眼猶青，笑我吟髭雪點成。',64,'全唐诗/poet.song.140000.json','["此君見我眼猶青，笑我吟髭雪點成。", "憶昔與君同舍日，聽渠將雨作秋聲。", "夜來遞宿三更悄，葉底春寒一倍生。", "夢入故園數新笋，穿籬破蘚幾莖莖。"]'),
('8dfc3e56-1acf-4c68-9784-6b9678941dfb','春寒早朝','楊萬里','宋','宋诗','song-poetry','','[]','十載江湖今又歸，朝雞不許夙興遲。',64,'全唐诗/poet.song.140000.json','["十載江湖今又歸，朝雞不許夙興遲。", "每聞撲鹿初鳴處，正是䰒鬆好睡時。", "病眼生憎紅蠟燭，曉光未到碧桃枝。", "誰能馬上追前夢，坐待金門放玉𥫽。"]'),
('2e2a1a4a-34cd-4eb9-b95d-a358df6f28d7','二月二十四日寺丞田丈清叔及學中舊同舍諸丈拉予同屈祭酒顔丈幾聖學官諸丈集於西湖雨中泛舟坐上二十人用遲日江山麗四句分韻賦詩余得融字呈同社','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','正月一度游玉壺，二月一度游真珠。',178,'全唐诗/poet.song.140000.json','["正月一度游玉壺，二月一度游真珠。", "是時新霽曉光初，西湖獻狀無遺餘。", "君王予告作寒食，來看孤山海棠色。", "海棠落盡孤山空，湖上模糊眼中黑。", "夜來三更湖月明，羣仙下墮嬉殊庭。", "東坡和靖相先後，李成郭熙在左右。", "惠崇捧硯大如箕，大年落筆疾於飛。", "磨墨爲雲灑爲雨，湖波掀舞山傾欹。", "畫作西湖煙雨障，今晨掛在孤山上。", "同來諸彥文章公，不數錢起兼吳融。", "何如玉船一舉百分滿，一笑千峰煙雨散。"]'),
('d1fbe8c9-2fdc-424b-993e-dc6196c9d2de','類試所戲集杜句跋杜詩呈監試謝昌國察院','楊萬里','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','有客有客字子美，日糴太倉五升米。',237,'全唐诗/poet.song.140000.json','["有客有客字子美，日糴太倉五升米。", "錦官城西生事微，盡醉江頭夜不歸。", "青山落日江湖白，嗜酒酣歌拓金戟。", "語不驚人死不休，萬草千花動凝碧。", "穉子敲針作釣鈎，老夫乘興欲東流。", "巡簷索共梅花笑，還如何遜在楊州。", "老去詩篇渾漫與，蛺蝶飛來黄鸝語。", "往時文采動人主，來如雷霆收震怒。", "一夜水高數尺强，濯足洞庭望八荒。", "閶闔晴開映蕩蕩，安得仙人九節杖。", "君不見西漢杜陵老，脫身事幽討。", "下筆如有神，汝與山東李白好。", "儒術於我何有哉，願吹野水添金杯。", "焉知餓死填溝壑，如何不飲令心哀。", "名垂萬古知何用，萬牛回首丘山重。"]'),
('06d72d57-6fa2-4a91-98a7-83b06afc8a26','予因集杜句跋杜詩呈監試謝昌國察院謝丈復集杜句見贈予以百家衣報之','楊萬里','宋','宋诗','song-poetry','','[]','棘圍深鎖武成宮，華裾織翠青如葱。',140,'全唐诗/poet.song.140000.json','["棘圍深鎖武成宮，華裾織翠青如葱。", "謝公文章如虎豹，林間一嘯四山風。", "天下幾人學杜甫，千江隔兮萬山阻。", "畫地爲餠未必似，更覺良工心獨苦。", "誰登李杜壇，浩如海波翻。", "奄有二子成三人，古風蕭蕭筆追還。", "我詩如曹鄶，拆東補西裳作带。", "令人還憶謝玄暉，崑崙虞泉入馬蹄。", "我願四方上下逐東野，只有相逢無別離。"]'),
('e5d42d8c-0230-4b95-9897-2c3ea0fdf2f0','楊花','楊萬里','宋','宋诗','song-poetry','','[]','只道垂楊管別離，楊花一去不思歸。',32,'全唐诗/poet.song.140000.json','["只道垂楊管別離，楊花一去不思歸。", "浮蹤浪跡無拘束，飛到蛛絲也不飛。"]'),
('97a4c393-fe5e-4ed2-9b99-12d126540093','擬花蕊亞枝紅詩','楊萬里','宋','宋诗','song-poetry','','[]','花密非無蕊，繽紛亂眼中。',72,'全唐诗/poet.song.140000.json','["花密非無蕊，繽紛亂眼中。", "千枝相亞閙，一色總成紅。", "赴曉桃如積，爭晴杏欲烘。", "金鬚迷不見，玉頰醉來同。", "頓覺江山麗，都將錦繡籠。", "春光誰畫得，分付少陵翁。"]'),
('5e40dff3-ef13-4498-afbb-2fab4686c833','四月五日車駕朝獻景靈宮省前迎駕起居口號','楊萬里','宋','宋诗','song-poetry','','[]','鳳輦雲行露未銷，鸞旗風動柳相高。',64,'全唐诗/poet.song.140000.json','["鳳輦雲行露未銷，鸞旗風動柳相高。", "晴雷出地傳清蹕，霽日吹紅染御袍。", "喜見天顔浮玉藻，歸從原廟薦櫻桃。", "小臣再得瞻黄繖，兩鬢星星不滿搔。"]'),
('022e6e1c-195b-42a5-b4b6-c25a67555ac2','沈虞卿秘監招游西湖','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','蘇公堤遠柳生煙，和靖園深竹映關。',64,'全唐诗/poet.song.140000.json','["蘇公堤遠柳生煙，和靖園深竹映關。", "船入芰荷香處去，人從雲水國中還。", "似寒如暖清和在，欲雨翻晴頃刻間。", "能爲蓬萊老僊伯，一杯痛快吸湖山。"]'),
('e9f01939-6328-4d9d-b480-9a43fc16ccdd','陳蹇叔郎中出閩漕別送新茶李聖俞郎中出手分似','楊萬里','宋','宋诗','song-poetry','','[]','頭綱別樣建溪春，小璧蒼龍浪得名。',64,'全唐诗/poet.song.140000.json','["頭綱別樣建溪春，小璧蒼龍浪得名。", "細瀉谷簾珠顆露，打成寒食杏花餳。", "鷓斑椀面雲縈字，兔褐甌心雪作泓。", "不待清風生兩腋，清風先向舌端生。"]'),
('4161897f-47bd-4f53-89e1-17815dc0b820','送鄉僧德璘監寺緣化結夏歸天童山二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','一別璘公十二年，故當刮目爲相看。',32,'全唐诗/poet.song.140000.json','["一別璘公十二年，故當刮目爲相看。", "問儂收得曹溪水，雩下春風吹已乾。"]'),
('c3438fac-6a57-42ba-8c13-06173865ba75','送鄉僧德璘監寺緣化結夏歸天童山二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','七百支郎夜忍饑，木魚閉口等君歸。',32,'全唐诗/poet.song.140000.json','["七百支郎夜忍饑，木魚閉口等君歸。", "還山大衆空歡喜，只有誠齋兩首詩。"]'),
('0cdef9ce-b944-4ebb-ad97-892b87c3536c','答提點綱馬驛程劉修武翰二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','公幹當年子建親，景文今代大蘇賓。',32,'全唐诗/poet.song.140000.json','["公幹當年子建親，景文今代大蘇賓。", "絕知將種仍詩種，不放騷人與外人。"]'),
('2204bb69-ca59-4fe3-b2a9-77a2756913ab','答提點綱馬驛程劉修武翰二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','解道征鴻數字秋，清於雪椀映冰甌。',32,'全唐诗/poet.song.140000.json','["解道征鴻數字秋，清於雪椀映冰甌。", "老來筆底心無毒，交割風光與子休。"]'),
('ea35c3e0-9163-45bf-884a-0b1db6a79e45','吳春卿郎中餉臘豬肉戲作古句','楊萬里','宋','宋诗','song-poetry','','[]','老夫畏熱飯不能，先生饋肉香傾城。',80,'全唐诗/poet.song.140000.json','["老夫畏熱飯不能，先生饋肉香傾城。", "霜刀削下黄水精，月斧斫出紅松明。", "君家豬紅臘前作，是時雪沒吳山脚。", "公子彭生初解縛，糟丘挽上凌煙閣。", "却將一臠配兩螯，世間真有楊州鶴。"]'),
('e97dab25-97fd-4299-ae2b-5305eca4aa2c','戲作司花謠呈詹進卿大監郎中','楊萬里','宋','宋诗','song-poetry','','[]','靈君觴客滕王家，鼇頭仙人作司花。',112,'全唐诗/poet.song.140000.json','["靈君觴客滕王家，鼇頭仙人作司花。", "仙人一笑春風起，開盡仙源萬桃李。", "李花冶白桃倡紅，坐客桃霞李雪中。", "仙人半酣舞造化，風吹雨打千花空。", "嫣香菸色付一掃，病莟殘英又嫌老。", "落花已對春風羞，新花也對春風愁。", "姚黄魏紫世無種，且據眼前桃李休。"]'),
('a233e63e-2a7e-4480-87d2-c2bf915d5e37','直宿南宮三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','獨直南宮午獨吟，祥雲淡淡竹陰陰。',32,'全唐诗/poet.song.140000.json','["獨直南宮午獨吟，祥雲淡淡竹陰陰。", "小風慢落鵝黄雪，看到槐花一寸深。"]'),
('43b805fb-42d6-45b3-842a-248eb6022695','直宿南宮三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','今年秋暑更禁它，無計商量奈熱何。',32,'全唐诗/poet.song.140000.json','["今年秋暑更禁它，無計商量奈熱何。", "一霎飄蕭涼一日，雨來銷得幾多多。"]'),
('a21b6619-9fd4-4a0a-bbed-0df4cc5dc465','直宿南宮三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','秋熱連宵睡不成，移床換枕到天明。',32,'全唐诗/poet.song.140000.json','["秋熱連宵睡不成，移床換枕到天明。", "今宵不熱還無睡，却爲宮簷瀉雨聲。"]'),
('af165ed6-639f-4abf-acfb-880561bb1758','大司成顔幾聖率同舍招游裴園泛舟繞孤山賞荷花晚泊玉壺得十絕句  其一','楊萬里','宋','宋诗','song-poetry','','[]','鳳城魚鑰曉開銀，國子先生領搢紳。',32,'全唐诗/poet.song.140000.json','["鳳城魚鑰曉開銀，國子先生領搢紳。", "山水光中金鑿落，芙蕖香裏葛頭巾。"]'),
('c3eacde4-1b88-404a-8d5a-bcd97e961d50','大司成顔幾聖率同舍招游裴園泛舟繞孤山賞荷花晚泊玉壺得十絕句  其二','楊萬里','宋','宋诗','song-poetry','','[]','小步深登野寺幽，古松將影入茶甌。',32,'全唐诗/poet.song.140000.json','["小步深登野寺幽，古松將影入茶甌。", "鈴聲忽起九天半，有塔危峰最上頭。"]'),
('fd6a1198-becd-4a1c-8e26-b2920038dc9e','大司成顔幾聖率同舍招游裴園泛舟繞孤山賞荷花晚泊玉壺得十絕句  其三','楊萬里','宋','宋诗','song-poetry','','[]','岸岸園亭傍水濱，裴園飛入水心橫。',32,'全唐诗/poet.song.140000.json','["岸岸園亭傍水濱，裴園飛入水心橫。", "旁人莫問游何許，只揀荷花閙處行。"]'),
('3b13e946-3ad9-405b-b643-5f60cd1dc6ef','大司成顔幾聖率同舍招游裴園泛舟繞孤山賞荷花晚泊玉壺得十絕句  其四','楊萬里','宋','宋诗','song-poetry','','[]','船開便與世塵疎，飄若乘風度太虛。',32,'全唐诗/poet.song.140000.json','["船開便與世塵疎，飄若乘風度太虛。", "坐上偶然遺餠餌，波間無數出龜魚。"]'),
('ca6ea1e0-7e30-4dcf-ab4f-cb2cc54a5591','大司成顔幾聖率同舍招游裴園泛舟繞孤山賞荷花晚泊玉壺得十絕句  其五','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖舊屬野人家，今屬天家不屬他。',32,'全唐诗/poet.song.140000.json','["西湖舊屬野人家，今屬天家不屬他。", "水月亭前且楊柳，集芳園下儘荷花。"]'),
('2dc6b8db-0d5e-4a07-9321-c9a046c32412','大司成顔幾聖率同舍招游裴園泛舟繞孤山賞荷花晚泊玉壺得十絕句  其六','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','小泛西湖六月船，船中人即水中仙。',32,'全唐诗/poet.song.140000.json','["小泛西湖六月船，船中人即水中仙。", "外鋪雲錦千弓地，中度瑠璃百摺天。"]'),
('e8040dab-f9cd-4d31-b8c5-e14dea33e798','大司成顔幾聖率同舍招游裴園泛舟繞孤山賞荷花晚泊玉壺得十絕句  其七','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','城中擔上買蓮房，未抵西湖泛野航。',32,'全唐诗/poet.song.140000.json','["城中擔上買蓮房，未抵西湖泛野航。", "旋折荷花剝蓮子，露爲風味月爲香。"]'),
('23cde9d6-f1dc-47f7-af37-c06d097520e7','大司成顔幾聖率同舍招游裴園泛舟繞孤山賞荷花晚泊玉壺得十絕句  其八','楊萬里','宋','宋诗','song-poetry','','[]','故人京尹劇風流，走送厨珍佐勝游。',32,'全唐诗/poet.song.140000.json','["故人京尹劇風流，走送厨珍佐勝游。", "青李來禽沈冰雪，黄金白璧斫蝤蛑。"]'),
('98d38d0c-8a6b-4b10-928c-1235696dec7b','大司成顔幾聖率同舍招游裴園泛舟繞孤山賞荷花晚泊玉壺得十絕句  其九','楊萬里','宋','宋诗','song-poetry','','[]','人間暑氣正如炊，上了湖船便不知。',32,'全唐诗/poet.song.140000.json','["人間暑氣正如炊，上了湖船便不知。", "湖上四時無不好，就中最說藕花時。"]'),
('168f1d54-5fc0-4075-9986-9f5af18c3a37','大司成顔幾聖率同舍招游裴園泛舟繞孤山賞荷花晚泊玉壺得十絕句  其一○','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','游盡西湖賞盡蓮，玉壺落日泊樓船。',32,'全唐诗/poet.song.140000.json','["游盡西湖賞盡蓮，玉壺落日泊樓船。", "莫嫌當處荷花少，剩展湖光幾鏡天。"]'),
('79c4353b-bb41-4b72-890d-878a011f4acb','謝胡子遠郎中惠蒲大韶墨報以龍涎心字香','楊萬里','宋','宋诗','song-poetry','','[]','墨家者流老蒲仙，碧梧採花和麝煙。',192,'全唐诗/poet.song.140000.json','["墨家者流老蒲仙，碧梧採花和麝煙。", "華陽黑水煎膠漆，太陰玄霜作肌骨。", "龍尾磨肌飲鼠鬚，落點髹几几不如。", "夷甫清瞳光敵日，一見墨卿驚自失。", "後來夔川有梁杲，爾來黟川有吳老。", "亦追時好得時名，竟爲蒲生豎降旌。", "吳滋往往玄尚白，梁墨濕濕黐黏壁。", "南宮先生來自西，惠然贈我四玄圭。", "我無鵲返鸞迴字，我無金章玉句子。", "得君此贈端何似，兀者得靴僧得髢。", "安得玉案雙鳴璫，金刀繡段底物償。", "送似龍涎心字香，爲君興雲繞明窗。"]'),
('07bc4974-fd77-4a2b-b1ea-861e4ac2c632','新凉五言呈尤延之','楊萬里','宋','宋诗','song-poetry','','[]','暑極無可增，夏餘亦復幾。',120,'全唐诗/poet.song.140000.json','["暑極無可增，夏餘亦復幾。", "幽人暍欲腊，日日望秋至。", "秋至涼不隨，夏去熱未已。", "一夕睡美餘，秋從簟波起。", "新涼來何方，灑若清到髓。", "夕前輕雨作，雨後微風駃。", "涼偶與之偕，未必涼因此。", "向來亦風雨，既止暑更倍。", "但令暑爲涼，老病有生意。", "何必問所來，亦莫悲徂歲。"]'),
('2ef20707-c4a7-4bf5-ba5b-45aa194569ab','小齋晚興','楊萬里','宋','宋诗','song-poetry','','[]','不會隣家養鴿兒，清晨齊放晚齊歸。',32,'全唐诗/poet.song.140000.json','["不會隣家養鴿兒，清晨齊放晚齊歸。", "網絲到處縈人鬢，欲打蜘蛛揀最肥。"]'),
('0561e93b-5f8a-4277-88c8-044a7738996e','尤延之和予新凉五言末章有早歸山林之句復和謝焉','楊萬里','宋','宋诗','song-poetry','','[]','投分詎云稀，會心諒亡幾。',120,'全唐诗/poet.song.140000.json','["投分詎云稀，會心諒亡幾。", "從君澹何奇，與我凜獨至。", "相逢情若忘，每別懷不已。", "偶因新涼篇，令予懦全起。", "藉草分澗芳，陟巘共石髓。", "松陰俯逝波，不徐亦不駃。", "平生還山約，終食能忘此。", "可憐各異縣，千里復三倍。", "它日寄相思，百書那寫意。", "從今可相疎，却嘆日爲歲。"]'),
('d764e811-8bce-4600-976f-425f19e1fd6a','省宿題天官廳後竹林','楊萬里','宋','宋诗','song-poetry','','[]','秋聲偷入翠琅玕，葉葉竿竿玉韻寒。',32,'全唐诗/poet.song.140000.json','["秋聲偷入翠琅玕，葉葉竿竿玉韻寒。", "聲在樹間元未是，秋聲只在竹林間。"]'),
('6914a1d2-078f-423a-b730-05151dd224ce','賀皇太子九月四日生辰四首  其一','楊萬里','宋','宋诗','song-poetry','','[]','地出雷初震，天昇日更重。',48,'全唐诗/poet.song.140000.json','["地出雷初震，天昇日更重。", "高飛千里鵠，潜躍九淵龍。", "隆準如高帝，虬鬚似太宗。", "八荒陰賜裏，戶戶是華封。"]'),
('4827ac02-1c53-4b86-9ae7-019bc97efdb8','賀皇太子九月四日生辰四首  其二','楊萬里','宋','宋诗','song-poetry','','[]','代邸躬仁儉，湯孫世聖賢。',48,'全唐诗/poet.song.140000.json','["代邸躬仁儉，湯孫世聖賢。", "誰云無二日，今恰見三天。", "甲觀初寒夕，神光似晝然。", "前星那解老，何但八千年。"]'),
('ca2e520e-97e6-4a77-8731-92f021482d00','賀皇太子九月四日生辰四首  其三','楊萬里','宋','宋诗','song-poetry','','[]','重九吹花節，千齡夢日時。',48,'全唐诗/poet.song.140000.json','["重九吹花節，千齡夢日時。", "東朝分菊水，南內賜萸枝。", "禹酒無多酌，堯樽更一巵。", "三宮千萬壽，剩費若干詩。"]'),
('338dc530-34da-48f0-9418-9c25b4b49fc9','賀皇太子九月四日生辰四首  其四','楊萬里','宋','宋诗','song-poetry','','[]','繼照姿天縱，分陰學日勤。',48,'全唐诗/poet.song.140000.json','["繼照姿天縱，分陰學日勤。", "橘中招綺夏，瓜處屏伾文。", "老別魚竿月，來依鶴禁雲。", "還將古爲鑑，聊當野人芹。"]'),
('bdec943c-5b0b-4cb5-b626-65b8b63cd904','和同年李子西通判','楊萬里','宋','宋诗','song-poetry','','[]','走馬看花拂綠楊，曲江同賞牡丹香。',64,'全唐诗/poet.song.140000.json','["走馬看花拂綠楊，曲江同賞牡丹香。", "向來年少今俱老，君拜監州我作郎。", "北闕小遲蒼玉佩，南征聊製芰荷裳。", "病身只作家山夢，徑菊詩葩兩就荒。"]'),
('3f4c3f30-41a1-4ed7-9d5d-c12c1bf23be2','九日都下黄雀食新','楊萬里','宋','宋诗','song-poetry','','[]','九日新霜薄，羣飛一網遮。',48,'全唐诗/poet.song.140000.json','["九日新霜薄，羣飛一網遮。", "裘披楊柳絮，色染木犀花。", "下箸欣鄉味，知儂憶故家。", "金杯浮菊蕊，相映兩光華。"]'),
('68cb5ff6-41e4-475b-9f94-8f2ea4a38f2a','九日即事呈尤延之','楊萬里','宋','宋诗','song-poetry','','[]','昨日茱萸未苦香，今朝籬菊頓然黄。',64,'全唐诗/poet.song.140000.json','["昨日茱萸未苦香，今朝籬菊頓然黄。", "浮英泛蕊多多著，舊酒新醅細細嘗。", "節裏且追千載事，鬢邊管得幾莖霜。", "正冠落帽都兒態，自笑狂夫老不狂。"]'),
('da0e3413-269a-4c60-9b50-c4e67839e7db','和周元吉左司東省培竹','楊萬里','宋','宋诗','song-poetry','','[]','雞省有貞植，鶩行銷晝煩。',168,'全唐诗/poet.song.140000.json','["雞省有貞植，鶩行銷晝煩。", "憎柳媚綠暗，伴梅耿黄昏。", "何須雪貿貿，始愛渠軒軒。", "堅守孤竹國，肯折先軫元。", "如何桃李時，筍短不出垣。", "周郎夜入直，挾策携酒尊。", "爲渠問玄夫，乃遇震爲坤。", "喜渠必蕃昌，吟到落金盆。", "曉喚郭橐駝，提耳細細言。", "汲水龍井泓，輦土天竺原。", "妙偷造化窟，仁及冰霜根。", "爲賦淇奧詩，絕去筆墨痕。", "何時淮陰市，能報漂母恩。", "周郎顧之笑，吾自哀龍孫。"]'),
('c8540241-e516-48fe-9385-7fc31e190b18','和周元吉左司夢歸之韻','楊萬里','宋','宋诗','song-poetry','','[]','半似清狂半白癡，不須人笑我心知。',64,'全唐诗/poet.song.140000.json','["半似清狂半白癡，不須人笑我心知。", "煙霞平日真成癖，山水中年却語離。", "錯計浪隨雲出岫，感君能遣雨催詩。", "居然喚起還家夢，橘刺藤梢隔槿籬。"]'),
('bfff4db8-dc46-445a-b319-0567db8b73d0','給事葛楚輔侍郎余處恭二詹事招儲禁同寮沈虞卿秘監諭德尤延之右司侍講何自然少監羅春伯大著二宮教及予泛舟西湖步登孤山五言','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','曉雨擣珠屑，吹作空中塵。',180,'全唐诗/poet.song.140000.json','["曉雨擣珠屑，吹作空中塵。", "拂水無落暈，映巒有遮痕。", "承華兩端尹，嘉招出城闉。", "一尊澆雲師，借風開晝昏。", "諸鬟忽脫帽，孤鏡亦捲裀。", "西湖翳復皎，南山洗如新。", "舍舟步柳堤，曳杖啄松門。", "乃是小上林，亦有虎守閽。", "桂落剩金粟，蓉粧濃繡屏。", "高堂竹梢上，幽榭荷葉濱。", "羣仙此小憩，呼酒領一欣。", "秋花隔水笑，笑我墮紗巾。", "更酬不知籌，互嘲還作春。", "行樂戒多取，況復仄羲輪。", "歸鬉兀頹玉，那知醉與醒。"]'),
('c0359380-3935-421c-bde3-d2b4fc9f8656','賀皇孫平陽郡王十月十九日生辰','楊萬里','宋','宋诗','song-poetry','','[]','玉曆當千運，天潢第一源。',48,'全唐诗/poet.song.140000.json','["玉曆當千運，天潢第一源。", "本支堯百世，有道宋曾孫。", "接武前星曜，依光太極尊。", "年年會慶節，更慶茁蘭孫。"]'),
('3d8014e3-3089-4473-a6ca-c7c8c215f01c','送王成之中書舍人使虜','楊萬里','宋','宋诗','song-poetry','','[]','帝遣唐朝第一人，玉門關外賜金銀。',64,'全唐诗/poet.song.140000.json','["帝遣唐朝第一人，玉門關外賜金銀。", "使星芒動梅花早，漢月光垂塞草春。", "故國山河迎詔旨，中原父老識詞臣。", "十分宣慰華戎了，歸爲君王轉大鈞。"]'),
('7dabd2db-e56f-4b10-959c-52dda6d036b5','李聖俞郎中求吾家江西黄雀醝法戲作醝經遺之','楊萬里','宋','宋诗','song-poetry','','[]','江夏無雙小道士，一丘一壑長避世。',208,'全唐诗/poet.song.140000.json','["江夏無雙小道士，一丘一壑長避世。", "裁雲縫霧作羽衣，蘆花柳綿當裘袂。", "身騎鴻鵠太液池，脚踏金蟇攀桂枝。", "渴飲南陽菊潭水，饑啄藍田栗玉芝。", "今年天田秋大熟，紫皇遣刈神倉穀。", "一雙鳬舄墮雲羅，夜隨弋人卧茅屋。", "賣身不直程將軍，却與彭越俱策勳。", "解衣戲入玉壺底，壺中別是一乾坤。", "水精鹽山兩岐麥，身在椒蘭衆香國。", "玉條脫下澡凝脂，金叵羅中酌瓊液。", "平生學仙不學禪，刳心洗髓糟床邊。", "諸公俎豆驚四筵，猶得留侯借箸前。", "昔爲飛仙今酒仙，更入太史滑稽篇。"]'),
('973ed5df-95fc-4a07-b1fe-4a4d4d12f444','食蒸餠作','楊萬里','宋','宋诗','song-poetry','','[]','何家籠餠須十字，蕭家炊餠須四破。',64,'全唐诗/poet.song.140000.json','["何家籠餠須十字，蕭家炊餠須四破。", "老夫饑來不可那，只要鶻崙吞一箇。", "詩人一腹大於蟬，饑飽翻手覆手間。", "須臾放筯付一莞，急喚龍團分蟹眼。"]'),
('0190ec2e-62a3-458c-8c55-9aeedc866217','早朝紫宸殿賀雪呈尤延之二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','雪花將瑞獻君王，晴早銷遲戀建章。',32,'全唐诗/poet.song.140000.json','["雪花將瑞獻君王，晴早銷遲戀建章。", "不肯獨清須带月，猶嫌未冷更吹霜。"]'),
('e94c2e25-6973-4a09-8f98-707740684978','早朝紫宸殿賀雪呈尤延之二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','雪妃月姊宴羣仙，珠閣銀樓集玉鸞。',32,'全唐诗/poet.song.140000.json','["雪妃月姊宴羣仙，珠閣銀樓集玉鸞。", "老子來看收不徹，梅梢拾得水精盤。"]'),
('e143d26f-be40-448f-8bc4-ac2bb5dcfe54','擬乙巳南郊慶成二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','已醊方諸月底泉，更昇爟火桂梢煙。',64,'全唐诗/poet.song.140000.json','["已醊方諸月底泉，更昇爟火桂梢煙。", "熉黄幄坐明金炬，太紫虛皇下碧天。", "玉路旂常龍十二，繡衣鹵簿虎三千。", "萬人隨駕還閶闔，看奪金雞雪柳邊。"]'),
('69a5aa2f-5735-424a-b518-9c44ac330e8f','擬乙巳南郊慶成二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','上瑞今年特地奇，大田多稼與雲齊。',64,'全唐诗/poet.song.140000.json','["上瑞今年特地奇，大田多稼與雲齊。", "星沈析木天街北，波靜崑崙渤澥西。", "帝在紫壇神在次，穹如蒼蓋月如珪。", "一人執玉千官肅，萬馬和霜不敢嘶。"]'),
('e417eaff-3812-412a-937d-4d1263089e52','代賀郊祀慶成二首','楊萬里','宋','宋诗','song-poetry','','[]','聖主勤民歲自豐，德威懷遠塞塵空。',128,'全唐诗/poet.song.140000.json','["聖主勤民歲自豐，德威懷遠塞塵空。", "鬰金祼鬯周茅屋，瑄玉親郊漢竹宮。", "已刺六經新作制，却追三代與同風。", "雞竿更霈如天澤，殿柳宸梅雪正融。", "天爲君王幸泰禋，飛雵疎雨凈香塵。", "金波玉李浮蒼璧，風馬雲車降紫旻。", "萬寶豐年貞上瑞，八方和氣藹成春。", "受釐未肯專宣室，鴻號還將壽兩親。"]'),
('5498d199-7668-4508-99a3-ee9457640e3b','和周元吉左司郊祀慶成韻','楊萬里','宋','宋诗','song-poetry','','[]','八觚泰畤六郊天，一柱明堂再饗先。',64,'全唐诗/poet.song.140000.json','["八觚泰畤六郊天，一柱明堂再饗先。", "日月旂常寒映雪，冕旒珠玉暖生煙。", "風回韶濩龍鱗外，花覆貔貅鳳闕前。", "喜溢天顔應未了，又迎慶壽入新年。"]'),
('c57de199-c70a-43d2-ac7a-cb8e98b54975','送章德茂少卿使虜','楊萬里','宋','宋诗','song-poetry','','[]','雪後聞君策馬蹄，長纓自請繫撐犁。',64,'全唐诗/poet.song.140000.json','["雪後聞君策馬蹄，長纓自請繫撐犁。", "光華劍佩伊吾北，彈壓風濤瀚海西。", "漢苑秦關愁外眼，邊花塞月醉中題。", "歸來聽履星辰上，誰道淮陰假鎮齊。"]'),
('bf54aedd-1a03-42b2-ac95-8bc67da53c7d','送詹進卿大監出宣城','楊萬里','宋','宋诗','song-poetry','','[]','今代稽山賀季真，前身江左謝宣城。',64,'全唐诗/poet.song.140000.json','["今代稽山賀季真，前身江左謝宣城。", "向來詔策無雙手，已逼雲霄尺五程。", "銀杏木瓜分我否，鴛鴦野鴨莫渠驚。", "玉皇香案方虛佇，看即徵黄侍紫清。"]'),
('0f3ca961-83da-49af-90b9-afe8b3be2739','和章德茂少卿拉館學之士四人訪王德脩提幹','楊萬里','宋','宋诗','song-poetry','','[]','西玉南金價則同，帝城相對落花風。',64,'全唐诗/poet.song.140000.json','["西玉南金價則同，帝城相對落花風。", "人如天上珠星聚，談到尊中竹葉空。", "白紵烏紗青寶玦，紫鸞黄鵠碧梧桐。", "千齡此遇還孤往，恨殺燈前欠老翁。"]'),
('0bdde09b-7526-46c4-b290-b3e3d33b2596','送何一之右司出守平江','楊萬里','宋','宋诗','song-poetry','','[]','十年一別再從游，又見魚書拜徹侯。',64,'全唐诗/poet.song.140000.json','["十年一別再從游，又見魚書拜徹侯。", "人物只今何水部，風流不減柳蘇州。", "白蘋洲上春傳語，烏鵲橋邊草喚悲。", "報政不應遲五月，鶑花紫禁竚歸舟。"]'),
('f3ab707b-9d04-4442-a83c-3c19bd5226be','送羅春伯大著提舉浙西','楊萬里','宋','宋诗','song-poetry','','[]','晁董聲名彼一時，夫君下筆與渠齊。',64,'全唐诗/poet.song.140000.json','["晁董聲名彼一時，夫君下筆與渠齊。", "承明厭直辭金馬，英蕩非關訪碧雞。", "山嶽動摇增氣色，詔書宣布舞羣黎。", "歸期只在千秋節，留賦蒼苔鳳掖西。"]'),
('a5c754b7-11bb-459a-8196-18ce62b819a4','德壽宮慶壽口號  其一','楊萬里','宋','宋诗','song-poetry','','[]','長樂宮前望翠華，玉皇來賀太皇家。',32,'全唐诗/poet.song.140000.json','["長樂宮前望翠華，玉皇來賀太皇家。", "青天白日仍飛雪，錯認東風轉柳花。"]'),
('2367fa56-8cd8-4f6b-8bb6-4b3a7e2374d0','德壽宮慶壽口號  其二','楊萬里','宋','宋诗','song-poetry','','[]','清曉鞭聲出禁中，驚開剩雨及殘風。',32,'全唐诗/poet.song.140000.json','["清曉鞭聲出禁中，驚開剩雨及殘風。", "金鴉銜取紅鸞扇，飛上玻瓈碧海東。"]'),
('f96960a1-73c8-42a1-98fa-7df7c6da474b','德壽宮慶壽口號  其三','楊萬里','宋','宋诗','song-poetry','','[]','春色何須羯鼓催，君王元日領春回。',32,'全唐诗/poet.song.140000.json','["春色何須羯鼓催，君王元日領春回。", "牡丹芍藥薔薇朵，都向千官帽上開。"]'),
('3172c3d9-a7bd-47b5-b4bf-6b626fe7a605','德壽宮慶壽口號  其四','楊萬里','宋','宋诗','song-poetry','','[]','雙金獅子四金龍，噴出香雲繞殿中。',32,'全唐诗/poet.song.140000.json','["雙金獅子四金龍，噴出香雲繞殿中。", "太上垂衣今上拜，百王曾有箇家風。"]'),
('00496c63-9015-4fe9-8d91-39e7a5426bc4','德壽宮慶壽口號  其五','楊萬里','宋','宋诗','song-poetry','','[]','帝捧瑶觴玉座前，綵衣三世祝堯年。',32,'全唐诗/poet.song.140000.json','["帝捧瑶觴玉座前，綵衣三世祝堯年。", "天皇八十一萬歲，休說莊椿兩八千。"]'),
('e51c7308-dd03-440f-8269-0634a485dc76','德壽宮慶壽口號  其六','楊萬里','宋','宋诗','song-poetry','','[]','天父晨興未出房，君王忍冷立風廊。',32,'全唐诗/poet.song.140000.json','["天父晨興未出房，君王忍冷立風廊。", "忽然鳴蹕珠簾捲，萬歲聲傳震八荒。"]'),
('b8719418-e80e-49e9-bfd6-789cc1b923bb','德壽宮慶壽口號  其七','楊萬里','宋','宋诗','song-poetry','','[]','花外班行霧外天，何緣子細望龍顔。',32,'全唐诗/poet.song.140000.json','["花外班行霧外天，何緣子細望龍顔。", "小窺玉色真難老，底用臞仙九轉丹。"]'),
('d79d9464-f8d0-48a6-8638-6909901d52bf','德壽宮慶壽口號  其八','楊萬里','宋','宋诗','song-poetry','','[]','甘露祥風天上來，今回恩數賽前回。',32,'全唐诗/poet.song.140000.json','["甘露祥風天上來，今回恩數賽前回。", "都將四海歡聲裏，釀作慈皇萬壽杯。"]'),
('ff37c1b1-e440-4d25-8938-e0560cad2594','德壽宮慶壽口號  其九','楊萬里','宋','宋诗','song-poetry','','[]','堯舜同時已甚都，祖孫四世古今無。',32,'全唐诗/poet.song.140000.json','["堯舜同時已甚都，祖孫四世古今無。", "誰將寫日摹天手，畫作皇王盛事圖。"]'),
('76302b6b-e9b7-4d34-b353-c4364239e6c4','德壽宮慶壽口號  其一○','楊萬里','宋','宋诗','song-poetry','','[]','甲戌王春試集英，小臣曾是老門生。',32,'全唐诗/poet.song.140000.json','["甲戌王春試集英，小臣曾是老門生。", "蒼顔華髮鵷行裏，也聽鈞天九奏聲。"]'),
('d5ba9ec6-1e48-4201-820f-ced2ba8be2ab','題曹仲本出示譙國公迎請太后圖自肅天仗以下皆紀畫也','楊萬里','宋','宋诗','song-poetry','','[]','德壽宮前春晝長，宮中花開宮外香。',255,'全唐诗/poet.song.140000.json','["德壽宮前春晝長，宮中花開宮外香。", "太皇頤神玉霄上，都人久不瞻清光。", "今晨忽見肅天仗，翠華黄屋從天降。", "一聲清蹕萬人看，天街冰銷樓雪殘。", "北來又有一紅繖，八鸞三騑金轂端。", "輦中似是瑶池母，鳳舄霞裳剪雲霧。", "太皇望見天開顔，萬國春風百花舞。", "乃是慈寧太母回鸞圖，母子如初千古無。", "朔雲邊雪旗脚濕，御柳宮梅寒影疎。", "向來慈寧隔沙漠，倩雁傳書雁難託。", "迎還騩馭彼何人，魏武子孫曹將軍。", "將軍元是一縫掖，忽攘兩臂挽五石。", "長揖單于如小兒，奉歸慈輦如折枝。", "功蓋天下只戲劇，笑隨赤松蠟雙屐，飄然南山之南北山北。", "君不見岳飛功成不抽身，却道秦家丞相嗔。"]'),
('48f8d4ac-06aa-4662-a0c4-9f3bea631606','正月二十四夜朱師古少卿招飲小樓看燈二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','光射瑠璃貫水精，玉虹垂地照天明。',32,'全唐诗/poet.song.140000.json','["光射瑠璃貫水精，玉虹垂地照天明。", "風流誰似朱夫子，解放元宵過後燈。"]'),
('a37a3aa9-212e-4b45-a8b5-1fda7c94c043','正月二十四夜朱師古少卿招飲小樓看燈二首  其二','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','南北高峰醒醉眸，市喧都寂似巖幽。',32,'全唐诗/poet.song.140000.json','["南北高峰醒醉眸，市喧都寂似巖幽。", "君言去歲西湖雨，城外荷聲到此樓。"]'),
('27553e74-5e1a-42f7-9da4-43d5c76cd91d','送劉孔章縣尉得官西歸','楊萬里','宋','宋诗','song-poetry','','[]','早宴黄花詣粉闈，晚挼春草染朝衣。',64,'全唐诗/poet.song.140000.json','["早宴黄花詣粉闈，晚挼春草染朝衣。", "却提猛士弓彎月，去掃封狐雪打圍。", "綠鬢朱顔君勝我，青春白日我思歸。", "何時共瀹青原茗，下看江鷗來去飛。"]'),
('0d5ef765-7cfe-42a9-8bab-ed19090df1a8','和陸務觀惠五言','楊萬里','宋','宋诗','song-poetry','','[]','官縛春無分，髯疎雪更欺。',48,'全唐诗/poet.song.140000.json','["官縛春無分，髯疎雪更欺。", "雲間墮詞客，事外得心期。", "我老詩全退，君才句總宜。", "一生非浪苦，醤瓿會相知。"]'),
('00046bdb-2932-41fb-bd27-7c40f2bbd9fc','雲龍歌調陸務觀','楊萬里','宋','宋诗','song-poetry','','[]','墨池楊子雲，雲間陸士龍。',264,'全唐诗/poet.song.140000.json','["墨池楊子雲，雲間陸士龍。", "天憎二子巧言語，只遣相別無相逢。", "長安市上忽再值，向來一別三千歲。", "王母桃花落幾番，北斗柄爛銀河乾。", "雙鬢成絲絲似雪，兩翁對面面如丹。", "借問別來各何向，渭水東流我西上。", "金印斗大直幾錢，錦囊山齊今幾篇。", "詩家不愁吟不徹，只愁天地無風月。", "君不見漢家平津侯，東閣冠蓋如雲浮。", "又不見當時大將軍，公卿雅拜如星奔。", "祗今雲散星亦散，也無鹿登臺榭羊登墳。", "何時與君上廬阜，都將硯水供瀑布。", "磨鎌更斫扶桑樹，擣皮作紙裁煙霧，雲錦天機織詩句。", "孤山海棠今已開，上巳未有游人來。", "與君火急到一回，一杯一杯復一杯。", "管他玉山頹不頹，詩名於我何有哉。"]'),
('ba46d908-79ba-432f-afa2-e57b63c24e2e','再和雲龍歌留陸務觀西湖小集且督戰云','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','我願身爲雲，東野化爲龍。',274,'全唐诗/poet.song.140000.json','["我願身爲雲，東野化爲龍。", "龍會入淵雲入岫，韓子却要長相逢。", "作意相尋偏不值，不知今年是何歲。", "剡藤玉板贈一番，廷珪烏丸灑未乾。", "乃是故人陸浚儀，詩骨點化黄金丹。", "謂宜天祿貯劉向，不然亦合雲臺上。", "却令去索催租錢，枉却清風明月三千篇。", "夜裝明發走不徹，半篙刺碎嚴灘月。", "老夫不願萬戶侯，但願與君酒船萬斛同拍浮。", "老夫不怯故將軍，但怯與君筆陣千里相追奔。", "少陵浣花舊時屋，太白青山何處墳。", "二仙死可埋丘阜，二仙生可著韋布。", "名挂廣寒宮裏樹，非煙非雲亦非霧，長使玉皇掉頭誦渠句。", "詩府誰得玉𥫽開，詩壇誰授黄鉞來。", "留君不住君急回，不道西出陽關無此杯。", "西山金盆儘渠頹，斯游明日方懷哉。"]'),
('7b5a9836-e113-4d5e-9371-4b56712b4c5d','上巳日予與沈虞卿尤延之莫仲謙招陸務觀沈子壽小集張氏北園賞海棠務觀持酒酹花予走筆賦長句','楊萬里','宋','宋诗','song-poetry','','[]','東風吹我入錦幄，海堂點注燕支薄。',96,'全唐诗/poet.song.140000.json','["東風吹我入錦幄，海堂點注燕支薄。", "不論宜雨更宜晴，莫愁傾國與傾城。", "半濃半淡晚明滅，欲開未開最奇絕。", "只銷一線日脚紅，頃刻千株開絳雪。", "偉哉詩人桑苧翁，持杯酌酒澆艷叢。", "坐看玉頰添醉暈，爲渠一醉何須問。"]'),
('9334b25e-3874-4fc0-9e34-3bf866facfc1','再和','楊萬里','宋','宋诗','song-poetry','','[]','太空無壁不可幄，顛風莫動花肌薄。',96,'全唐诗/poet.song.140000.json','["太空無壁不可幄，顛風莫動花肌薄。", "一春纔有一日晴，帝里游人爭出城。", "青天如水綠煙滅，晴與海棠成兩絕。", "坐中賓主詩中仙，開口揮毫俱玉雪。", "清泉白石欠此翁，若爲插脚鵷鷺叢。", "老眼作花花作暈，多慚猿鶴頻相問。"]'),
('f8d6c047-372b-40de-b97b-2123dd8278f5','醉卧海棠圖歌贈陸務觀','楊萬里','宋','宋诗','song-poetry','','[]','帝城二三月，海堂一萬株。',174,'全唐诗/poet.song.140000.json','["帝城二三月，海堂一萬株。", "向來青女拉滕六，戲與一撼即日枯。", "東皇夜遣司花女，手挼紅藍滴清露。", "染成片片浄練酥，亂點梢梢酣日樹。", "蓬萊仙人約老翁，寄牋招喚陸龜蒙，爲花一醉也不惜。", "就中一事最奇特，海棠兩岸繡帷裳，是間橫著雙胡床。", "龜蒙踞床忽倒卧，烏紗自落非風墮。", "落花滿面雪霏霏，起來索筆手如飛。", "卧來起來都是韻，是醉是醒君莫問。", "好箇海棠花下醉卧圖，如今畫手誰姓吳。"]'),
('7b084d5b-e82e-469c-99d5-1e5334ddcaa4','寒食雨中同舍約游天竺得十六絕句呈陸務觀  其一','楊萬里','宋','宋诗','song-poetry','','[]','游山不合作前期，便被山靈聖得知。',32,'全唐诗/poet.song.140000.json','["游山不合作前期，便被山靈聖得知。", "只等五更傾一雨，三更猶是月明時。"]'),
('b16b031f-cbf0-4ae7-a81e-e5939136df28','寒食雨中同舍約游天竺得十六絕句呈陸務觀  其二','楊萬里','宋','宋诗','song-poetry','','[]','筍輿衝雨復衝泥，一徑深深只覺遲。',32,'全唐诗/poet.song.140000.json','["筍輿衝雨復衝泥，一徑深深只覺遲。", "孤塔忽從雲外出，寺門漸近報儂知。"]'),
('04fb196d-b23f-43a3-9b8b-2b2186125439','寒食雨中同舍約游天竺得十六絕句呈陸務觀  其三','楊萬里','宋','宋诗','song-poetry','','[]','住山何敢望他僧，只是游山也不曾。',32,'全唐诗/poet.song.140000.json','["住山何敢望他僧，只是游山也不曾。", "可惜一條杉檜路，都將濕了不教行。"]'),
('6f26c315-9568-4c43-998f-64ed2551e44e','寒食雨中同舍約游天竺得十六絕句呈陸務觀  其四','楊萬里','宋','宋诗','song-poetry','','[]','破雨游山也莫嫌，却緣山色雨中添。',32,'全唐诗/poet.song.140000.json','["破雨游山也莫嫌，却緣山色雨中添。", "人家屋裏生松樹，穿出茅簷却覆簷。"]'),
('16a64767-b8b9-4ab1-9d5d-9de9aee80af9','寒食雨中同舍約游天竺得十六絕句呈陸務觀  其五','楊萬里','宋','宋诗','song-poetry','','[]','小溪曲曲亂山中，嫩水濺濺一線通。',32,'全唐诗/poet.song.140000.json','["小溪曲曲亂山中，嫩水濺濺一線通。", "兩岸桃花總無力，斜紅相倚卧春風。"]'),
('1c229ca3-051d-4e83-8083-c1fb70151230','寒食雨中同舍約游天竺得十六絕句呈陸務觀  其六','楊萬里','宋','宋诗','song-poetry','','[]','老檜如幢翠接連，山茶作塔綠縈纏。',32,'全唐诗/poet.song.140000.json','["老檜如幢翠接連，山茶作塔綠縈纏。", "山僧相識渾相忘，不到山中十五年。"]'),
('b5b068db-c9d3-46ec-aaef-50e44cd5a3a9','寒食雨中同舍約游天竺得十六絕句呈陸務觀  其七','楊萬里','宋','宋诗','song-poetry','','[]','三峰小石一方池，下有機泉仰面飛。',32,'全唐诗/poet.song.140000.json','["三峰小石一方池，下有機泉仰面飛。", "坐看跳珠復拋玉，忽然一噴與簷齊。"]'),
('d669ad04-ae26-4ecc-afd1-3532aa6fa669','寒食雨中同舍約游天竺得十六絕句呈陸務觀  其八','楊萬里','宋','宋诗','song-poetry','','[]','清遠溪中小閘頭，遮欄溪水不教流。',32,'全唐诗/poet.song.140000.json','["清遠溪中小閘頭，遮欄溪水不教流。", "山僧爲我放一板，濺雪奔雷怒未休。"]'),
('e2593943-50d9-44b6-a8dc-b97c269af7c0','寒食雨中同舍約游天竺得十六絕句呈陸務觀  其九','楊萬里','宋','宋诗','song-poetry','','[]','城裏哦詩枉斷髭，山中物物是詩題。',32,'全唐诗/poet.song.140000.json','["城裏哦詩枉斷髭，山中物物是詩題。", "欲將數句了天竺，天竺前頭更有詩。"]'),
('88950be7-f832-4a4c-829a-40f946a42f3b','寒食雨中同舍約游天竺得十六絕句呈陸務觀  其一○','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','忽見金絲嫋綺疏，又驚寒食到來初。',32,'全唐诗/poet.song.140000.json','["忽見金絲嫋綺疏，又驚寒食到來初。", "不知折盡西湖柳，插遍長安萬戶無。"]'),
('5a541669-cc12-4417-9d96-51200435a387','寒食雨中同舍約游天竺得十六絕句呈陸務觀  其一一','楊萬里','宋','宋诗','song-poetry','','[]','禪房寂寂水潺潺，澗草巖花點綴間。',32,'全唐诗/poet.song.140000.json','["禪房寂寂水潺潺，澗草巖花點綴間。", "忽有仙禽發奇響，頻伽來自補陀山。"]'),
('7c8bf71c-7af5-480e-9c92-f4a9e5dc3528','寒食雨中同舍約游天竺得十六絕句呈陸務觀  其一二','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','雨裏匆匆怨出郊，晴時不出却誰教。',32,'全唐诗/poet.song.140000.json','["雨裏匆匆怨出郊，晴時不出却誰教。", "西湖北畔名園裏，無數桃花只見梢。"]'),
('b9e703eb-486c-442b-9a1c-a6149060ef11','寒食雨中同舍約游天竺得十六絕句呈陸務觀  其一三','楊萬里','宋','宋诗','song-poetry','','[]','戶戶游春不放春，只愁春去不愁貧。',32,'全唐诗/poet.song.140000.json','["戶戶游春不放春，只愁春去不愁貧。", "今朝道是游人少，處處園亭處處人。"]'),
('653d5d66-472a-41b7-959e-8fb7407f898f','寒食雨中同舍約游天竺得十六絕句呈陸務觀  其一四','楊萬里','宋','宋诗','song-poetry','','[]','若道尋春被雨催，如何隨處兩三杯。',32,'全唐诗/poet.song.140000.json','["若道尋春被雨催，如何隨處兩三杯。", "晚晴曉雨如翻手，有底虧儂不好來。"]'),
('12610efd-57dc-4803-a2f5-653bed77af8a','寒食雨中同舍約游天竺得十六絕句呈陸務觀  其一五','楊萬里','宋','宋诗','song-poetry','','[]','萬頃湖光一片春，何須割破損天真。',32,'全唐诗/poet.song.140000.json','["萬頃湖光一片春，何須割破損天真。", "却將葑草分疆界，葑外垂楊屬別人。"]'),
('e35a5964-a0ae-442d-b525-088fd8941bfe','寒食雨中同舍約游天竺得十六絕句呈陸務觀  其一六','楊萬里','宋','宋诗','song-poetry','','[]','轎頂花枝儘閙裝，游人未暮已心忙。',32,'全唐诗/poet.song.140000.json','["轎頂花枝儘閙裝，游人未暮已心忙。", "無端更被千株柳，展取蘇堤分外長。"]'),
('ab0e3225-4c40-4dc9-a968-3ea6acacd885','和皇太子雨中賞梅偶成二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','日到青宮分外長，梅兼白雪一時芳。',32,'全唐诗/poet.song.140000.json','["日到青宮分外長，梅兼白雪一時芳。", "儲皇更著瓊瑶句，句裏天葩別樣香。"]'),
('2e3dafc9-7f19-4c5a-b2f6-ea35e803732a','和皇太子雨中賞梅偶成二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','玉淵堂下一梢長，倚頼春風壓衆芳。',32,'全唐诗/poet.song.140000.json','["玉淵堂下一梢長，倚頼春風壓衆芳。", "妙句忽從天上落，千花從此總無香。"]'),
('d6f740da-487b-482d-b511-416dfc2f5598','謝皇太子三月十九日召宴榮觀堂頒賜金杯襭羅','楊萬里','宋','宋诗','song-poetry','','[]','春草池塘太液旁，水精宮殿牡丹香。',64,'全唐诗/poet.song.140000.json','["春草池塘太液旁，水精宮殿牡丹香。", "慚非綺里攀鴻翼，也侍承華宴鳳莊。", "玉唾銀鈎看落筆，繡袍金椀拜盈箱。", "迎門兒女牽衣袖，搜得隨侯與夜光。"]'),
('e9feff05-d982-45ee-94dc-e864a7d6822e','餞趙子直制置閣學侍郎出帥益州分未到五更猶是春二十八字爲韻得猶字','楊萬里','宋','宋诗','song-poetry','','[]','錦水花潭照碧油，西清學士舊鼇頭。',64,'全唐诗/poet.song.140000.json','["錦水花潭照碧油，西清學士舊鼇頭。", "隨身琴鶴如清獻，治蜀功名更武侯。", "無晚十行看暮召，不應三峽隔辰猶。", "垂楊管得人離別，舞破春風勸玉舟。"]'),
('a1e61cc9-6f8d-4773-acd7-bd821fe2bada','鎖宿省中心氣大作通昔不寐得兩絕句  其一','楊萬里','宋','宋诗','song-poetry','','[]','酒病春愁恰併來，更衝花信宿鸞臺。',32,'全唐诗/poet.song.140000.json','["酒病春愁恰併來，更衝花信宿鸞臺。", "睡鄉堠子無三里，玉漏聲聲只喚回。"]'),
('245cff83-d6fb-4ab6-b16b-917f44cdfcda','鎖宿省中心氣大作通昔不寐得兩絕句  其二','楊萬里','宋','宋诗','song-poetry','','[]','絕恨詩人浪許癡，四更無睡只哦詩。',32,'全唐诗/poet.song.140000.json','["絕恨詩人浪許癡，四更無睡只哦詩。", "老鈴枕手眠窗底，急雨顛風總不知。"]'),
('2abe9847-3dfc-4813-bd77-e3572fea5ada','送王恭父監丞倅潼川','楊萬里','宋','宋诗','song-poetry','','[]','淡墨掄魁政少年，蓬山璧水得詩仙。',64,'全唐诗/poet.song.140000.json','["淡墨掄魁政少年，蓬山璧水得詩仙。", "集賢學士看文筆，國子先生費酒錢。", "濯錦江頭頻入夢，桃花水面送歸船。", "平分風月真聊爾，不日來朝尺五天。"]'),
('a6567f25-0d2f-444a-941a-34dae4199df7','題徐載叔雙桂樓','楊萬里','宋','宋诗','song-poetry','','[]','遥憐天上桂華孤，月中何不種兩株。',144,'全唐诗/poet.song.140000.json','["遥憐天上桂華孤，月中何不種兩株。", "唐人此句真絕唱，後來詩人半語無。", "向來何夕秋風起，吹脫廣寒雙桂子。", "落向君家樓閣前，種玉開花今幾年。", "清宵雙影寫窗戶，却兼月裏成三樹。", "年年八月九月時，黄金粟綴青瑶枝。", "秋風吹香入月去，風回却带天香歸。", "容齋仙人爲作碑，誠齋老人爲作詩。", "金蟇玉兔已傳誦，莫問姮娥知不知。"]'),
('4bf7fb80-72f7-4d83-88ca-9ae3d5c12d96','招陳益之李兼濟二主管小酌益之指蠶豆云未有賦者戲作七言蓋豌豆也吳人謂之蠶豆','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','翠莢中排淺碧珠，甘欺崖蜜軟欺酥。',64,'全唐诗/poet.song.140000.json','["翠莢中排淺碧珠，甘欺崖蜜軟欺酥。", "沙瓶新熟西湖水，漆櫑分嘗曉露腴。", "味與櫻梅三益友，名因蠶繭一絲絇。", "老夫稼圃方雙學，譜入詩中當稼書。"]'),
('6db37079-5bbf-4e84-a8c6-227059dd621b','初夏清曉赴東宮講堂行經和寧門外賣花市','楊萬里','宋','宋诗','song-poetry','','[]','剩雨殘風一向顛，花枝酒盞兩無緣。',64,'全唐诗/poet.song.140000.json','["剩雨殘風一向顛，花枝酒盞兩無緣。", "忽逢野老從湖上，擔取名園到內前。", "芍藥截留春去路，鹿葱禮上夏初天。", "衆紅半霎聊經眼，不枉皇州第二年。"]'),
('0251386f-87d7-4379-925d-68947eaf0c46','積雨新晴駕幸聚景園擬口號','楊萬里','宋','宋诗','song-poetry','','[]','帝心憂麥復憂桑，一念通天轉雨晹。',64,'全唐诗/poet.song.140000.json','["帝心憂麥復憂桑，一念通天轉雨晹。", "五色日華銷積靄，三春花草殿餘芳。", "黄雲暖照天顔喜，紅藥濃熏禁籞香。", "見說都人爭出郭，歡聲舞倦萬垂楊。"]'),
('58fe8f14-7790-42dc-8172-14768dac58ca','跋陸務觀劍南詩藁二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','今代詩人後陸雲，天將詩本借詩人。',64,'全唐诗/poet.song.140000.json','["今代詩人後陸雲，天將詩本借詩人。", "重尋子美行程舊，盡拾靈均怨句新。", "鬼嘯狨啼巴峽雨，花紅玉白劍南春。", "錦囊繙罷清風起，吹仄西窗月半輪。"]'),
('d5952376-955e-4636-bf8a-762eab22617a','跋陸務觀劍南詩藁二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','劍外歸乘使者車，浙東新得左魚符。',64,'全唐诗/poet.song.140000.json','["劍外歸乘使者車，浙東新得左魚符。", "可憐霜鬢何人問，焉用詩名絕世無。", "彫得心肝百雜碎，依前塗轍九盤紆。", "少陵生在窮如蝨，千載詩人拜蹇馿。"]'),
('6553a8dd-81b8-4e84-8340-6af0ee86b70d','新晴讀樊川詩','楊萬里','宋','宋诗','song-poetry','','[]','江妃瑟裏芰荷風，浄掃癡雲展碧穹。',64,'全唐诗/poet.song.140000.json','["江妃瑟裏芰荷風，浄掃癡雲展碧穹。", "嫩熱便嗔疎小扇，斜陽酷愛弄飛蟲。", "九千刻裏春長雨，萬點紅邊花又空。", "不是樊川珠玉句，日長淡殺箇衰翁。"]'),
('9e462da1-32a0-4493-9119-b9862543b44b','駕幸聚景晚歸有旨次日歇泊','楊萬里','宋','宋诗','song-poetry','','[]','身在長安夢故山，故山未去且長安。',64,'全唐诗/poet.song.140000.json','["身在長安夢故山，故山未去且長安。", "落紅滿地莫教掃，新綠隔牆聊借看。", "竹葉勸人行樂事，榴花爲我遣春寒。", "賜休又得明朝睡，不問三竿與兩竿。"]'),
('11ff21e7-fd76-486c-9a87-eaa26a733bc7','都下食筍自十一月至四月戲題','楊萬里','宋','宋诗','song-poetry','','[]','竹祖龍孫渭上居，供儂樽俎半年餘。',64,'全唐诗/poet.song.140000.json','["竹祖龍孫渭上居，供儂樽俎半年餘。", "斑衣戲綵春無價，玉版談禪佛不如。", "若怨平生食無肉，何如陋巷飯斯蔬。", "不須庾韭元脩菜，喫到憎時始憶渠。"]'),
('26413231-cb49-47d1-b0f2-832e853b8a47','酴醾','楊萬里','宋','宋诗','song-poetry','','[]','以酒爲名却謗他，冰爲肌骨月爲家。',64,'全唐诗/poet.song.140000.json','["以酒爲名却謗他，冰爲肌骨月爲家。", "借令落盡仍香雪，且道開時是底花。", "白玉梢頭千點韻，綠雲堆裏一枝斜。", "休休莫斸西莊柳，放上松梢分外佳。"]'),
('a95af052-47c4-4dba-829a-3651b8f89c4b','蚤謁景靈宮聞子規','楊萬里','宋','宋诗','song-poetry','','[]','帝里都無箇裏寬，苑深地禁到應難。',64,'全唐诗/poet.song.140000.json','["帝里都無箇裏寬，苑深地禁到應難。", "蔚然綠樹去天近，上有子規啼月殘。", "便覺恍如還故里，不知聞處是長安。", "野薔薇發桐花落，孤負南溪老釣竿。"]'),
('d63fbdf7-5667-423e-8ba8-47dabe574b93','南海陶令曾送水沈報以雙井茶二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','嶺外書來謝故人，梅花不寄寄爐熏。',64,'全唐诗/poet.song.140000.json','["嶺外書來謝故人，梅花不寄寄爐熏。", "瓣香急試博山火，兩袖忽生南海雲。", "苒惹鬚眉清入骨，縈盈窗几巧成文。", "瓊琚作報那能辦，雙井春風輟一斤。"]'),
('eea45285-f420-49eb-8368-e2a1978b2249','南海陶令曾送水沈報以雙井茶二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','沈水占城第一良，占城上岸更差强。',64,'全唐诗/poet.song.140000.json','["沈水占城第一良，占城上岸更差强。", "黑藏骨節龍筋瘠，斑出文章鷓翼張。", "衮盡殘膏添猛火，熬成熟水趁新湯。", "素馨熏染真何益，畢竟輸他本分香。"]'),
('b22bbee7-c6a9-4135-8748-97dbc7a848da','以六一泉煮雙井茶','楊萬里','宋','宋诗','song-poetry','','["\u6ed5\u738b\u9601"]','鷹爪新茶蟹眼湯，松風鳴雪兔毫霜。',64,'全唐诗/poet.song.140000.json','["鷹爪新茶蟹眼湯，松風鳴雪兔毫霜。", "細參六一泉中味，故有涪翁句子香。", "日鑄建溪當退舍，落霞秋水夢還鄉。", "何時歸上滕王閣，自看風爐自煮嘗。"]'),
('c69fe815-c31d-4c25-8d9a-fda6bb296e6b','謝人送常州草蟲扇','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','生怕炎天老又逢，草蟲扇子獻奇功。',64,'全唐诗/poet.song.140000.json','["生怕炎天老又逢，草蟲扇子獻奇功。", "還將多稼亭前月，卷盡西湖柳上風。", "蚱蜢翅輕塗翡翠，蜻蜓腰細滴猩紅。", "舊時綠鬢常州守，今作霜髯一秃翁。"]'),
('df1afdd6-dfee-4335-9e88-4a09851e3c7b','謝福建提舉應仲實送新茶','楊萬里','宋','宋诗','song-poetry','','[]','詞林應瑒繡衣新，天上茶仙月外身。',64,'全唐诗/poet.song.140000.json','["詞林應瑒繡衣新，天上茶仙月外身。", "解贈萬釘蒼玉胯，分嘗一點建溪春。", "三杯大道醺然後，七椀清風爽入神。", "聞道閩山官況好，何時乞得兩朱輪。"]'),
('f77f8d53-c23f-42ee-a7e2-1ab715f2e578','嘗枸杞','楊萬里','宋','宋诗','song-poetry','','[]','芥花菘莟餞春忙，夜吠仙苗喜晚嘗。',64,'全唐诗/poet.song.140000.json','["芥花菘莟餞春忙，夜吠仙苗喜晚嘗。", "味抱土膏甘復脆，氣含風露嚥猶香。", "作齏淡著微施酪，芼茗臨時莫過湯。", "却憶荆溪古城上，翠條紅乳摘盈箱。"]'),
('956cd091-7cb3-412f-9ba3-a0e60ebbff4f','幼圃','楊萬里','宋','宋诗','song-poetry','','[]','寓舍中庭劣半弓，燕泥爲圃石爲墉。',64,'全唐诗/poet.song.140000.json','["寓舍中庭劣半弓，燕泥爲圃石爲墉。", "瑞香萱草一兩本，葱葉蔊苗三四叢。", "穉子落成小金谷，蝸牛卜築別珠宮。", "也思日涉隨兒戲，一逕惟看蟻得通。"]'),
('7ada6c8c-fa89-4ffb-a1fb-bbe7f6b16a38','同三館餞王恭父監丞分韻予得何字','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','去歲從遊泛綠波，西湖今日又新荷。',64,'全唐诗/poet.song.140000.json','["去歲從遊泛綠波，西湖今日又新荷。", "生來長是歡悰少，老去更堪離別多。", "客裏送君留不住，尊前爲我飲無何。", "休休萬事付一醉，爲報驪駒未要歌。"]'),
('8a3e7f93-5cc9-4ade-9a40-349166150f4c','送伍耀卿監廟西歸','楊萬里','宋','宋诗','song-poetry','','[]','敬軒居士子胥孫，河出昆侖學有源。',64,'全唐诗/poet.song.140000.json','["敬軒居士子胥孫，河出昆侖學有源。", "秋鶚屢看書禰表，春風兩度對堯軒。", "釣竿已拂珊瑚樹，拄笏新霑雨露恩。", "暫作祝融香火吏，裹輪早晚到柴門。"]'),
('06a907f9-128c-4401-8cc0-ca1540c32cdd','謝岳大用提舉郎中寄茶果藥物三首 日鑄茶','楊萬里','宋','宋诗','song-poetry','','[]','瓷瓶蠟紙印丹砂，日鑄春風出使家。',64,'全唐诗/poet.song.140000.json','["瓷瓶蠟紙印丹砂，日鑄春風出使家。", "白錦秋鷹微露爪，青瑶曉樹未成芽。", "松梢鼓吹湯翻鼎，甌面雲煙乳作花。", "喚醒老夫江海夢，呼兒索鏡整烏紗。"]'),
('0a6ff96b-1b73-4cb3-af82-7349eb39c991','謝岳大用提舉郎中寄茶果藥物三首 紫團參','楊萬里','宋','宋诗','song-poetry','','[]','新羅上黨各宗枝，有兩曾參果是非。',64,'全唐诗/poet.song.140000.json','["新羅上黨各宗枝，有兩曾參果是非。", "入手截來花暈紫，聞香已覺玉池肥。", "舊傳飲子安心妙，新擣珠塵看雪飛。", "珍重故人相問意，爲言老矣只思歸。"]'),
('68412133-c588-4996-b613-ef5d27c1fad0','謝岳大用提舉郎中寄茶果藥物三首 新松實','楊萬里','宋','宋诗','song-poetry','','[]','三韓萬里半天松，方丈蓬萊東復東。',64,'全唐诗/poet.song.140000.json','["三韓萬里半天松，方丈蓬萊東復東。", "珠玉鍊成千歲實，冰霜吹落九秋風。", "酒邊腷膊牙車響，座上須臾漆櫑空。", "新果新嘗正新暑，繡衣使者念山翁。"]'),
('282c2cce-f42e-42da-8d81-7cc96fea6c80','西府直舍盆池種蓮二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','飛空天鏡墮莓苔，玉井移蓮旋旋栽。',64,'全唐诗/poet.song.140000.json','["飛空天鏡墮莓苔，玉井移蓮旋旋栽。", "坐看一花隨手長，挨開半葉出頭來。", "稍添菱荇相縈带，便有龜魚數往回。", "剩欲遶池三兩匝，數聲排馬苦相催。"]'),
('f8f3e37b-390f-42f0-84e7-44c6d27dcedb','西府直舍盆池種蓮二首  其二','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西府寒泉汲十尋，深澆淺灑碧森森。',64,'全唐诗/poet.song.140000.json','["西府寒泉汲十尋，深澆淺灑碧森森。", "高花已照紅粧鏡，小莟新抽紫玉簪。", "鈿破尚餘新雨恨，繖疎纔作半池陰。", "西湖瘦得盆來大，更伴詩人恐不禁。"]'),
('ef8e4715-6002-45ba-ba78-b63667cbfa2f','東宮講退觸熱入省倦甚小睡','楊萬里','宋','宋诗','song-poetry','','[]','承華下直直幾廷，新暑醺人睡不成。',64,'全唐诗/poet.song.140000.json','["承華下直直幾廷，新暑醺人睡不成。", "到得曲肱貪夢好，無端急雨打荷聲。", "起看翠蓋如相戲，亂走明珠却細傾。", "歸路關心最涼處，水風四面一橋橫。"]'),
('9a5fe90f-c720-4870-b297-c227d8f99465','和周元吉省中新竹','楊萬里','宋','宋诗','song-poetry','','[]','青士何年下大荒，羽儀禁省立如牆。',64,'全唐诗/poet.song.140000.json','["青士何年下大荒，羽儀禁省立如牆。", "錦綳半脫娟娟玉，粉節新塗拂拂霜。", "带雨小酣三日後，出林忽喜一梢長。", "今年秋閏防多暑，剩供先生格外涼。"]'),
('41c28fc2-f969-4459-ad71-db9e03499c76','題尤延之右司遂初堂二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','漫仕風中絮，歸心水上鷗。',48,'全唐诗/poet.song.140000.json','["漫仕風中絮，歸心水上鷗。", "把茅新結屋，藜杖舊經丘。", "花底春勾引，燈前夜校讎。", "何如添我住，二老更風流。"]'),
('0f111204-a69b-4d8c-9873-1bf884637aef','題尤延之右司遂初堂二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','詩瘦山如瘦，人遐室更遐。',48,'全唐诗/poet.song.140000.json','["詩瘦山如瘦，人遐室更遐。", "荒林庾信宅，古木謝敷家。", "醫國君臣藥，逃名子母瓜。", "只愁歸未得，綠却白鷗沙。"]'),
('2cf09c51-19bd-46f6-930c-4a5b3a9c9560','七字謝紹興帥丘宗卿惠楊梅二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','梅出稽山世少雙，情知風味勝他楊。',64,'全唐诗/poet.song.140000.json','["梅出稽山世少雙，情知風味勝他楊。", "玉肌半醉紅生粟，墨暈微深染紫裳。", "火齊堆盤珠徑寸，醴泉繞齒柘爲漿。", "故人解寄吾家果，未變蓬萊閣下香。"]'),
('0dcbffd7-d32c-4270-a7dd-f95f82b1850e','七字謝紹興帥丘宗卿惠楊梅二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','越絕諸楊盛一時，與儂瓜葛不曾知。',64,'全唐诗/poet.song.140000.json','["越絕諸楊盛一時，與儂瓜葛不曾知。", "老夫自笑吾衰矣，此客何從夢見之。", "也解過江尋德祖，政緣作尹是丘遲。", "渠伊不是南村派，未分先驅事荔支。"]'),
('a7ceab64-388d-4e6c-ac45-5431aeead868','小桃','楊萬里','宋','宋诗','song-poetry','','[]','小桃著子可憐渠，疎處全疎無處無。',32,'全唐诗/poet.song.140000.json','["小桃著子可憐渠，疎處全疎無處無。", "併綴一梢三十顆，縋枝欲折沒人扶。"]'),
('29f3359f-e543-4784-8ba8-e69c19ae9e2a','送周元吉顯謨左司將漕湖北三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','君詩日日說歸休，忽解西風一葉舟。',64,'全唐诗/poet.song.140000.json','["君詩日日說歸休，忽解西風一葉舟。", "黄鶴樓前作重九，水精宮裏過中秋。", "職親六閣仍金馬，喜入千屯看木牛。", "繡斧光華誰不羨，一賢去國欠人留。"]'),
('ed2ee034-e833-4ee2-9f01-a4566f524dc6','送周元吉顯謨左司將漕湖北三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','又見周郎携小喬，武昌赤壁醉嬌饒。',64,'全唐诗/poet.song.140000.json','["又見周郎携小喬，武昌赤壁醉嬌饒。", "蜀江雪水來三峽，吳苑風煙訪六朝。", "秋月春花出肝肺，新詞麗曲入笙簫。", "歸來却侍金鑾殿，好看霜毛映珥貂。"]'),
('2a00710d-3fda-4f00-9b0b-f7b774f51cd7','送周元吉顯謨左司將漕湖北三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','彼此江湖漫浪翁，相逢遞宿省西東。',64,'全唐诗/poet.song.140000.json','["彼此江湖漫浪翁，相逢遞宿省西東。", "兩窮握手論詩後，一笑投膠入漆中。", "臨水登山公別我，青鞋布襪我從公。", "貂裘已博江西艇，只待黄花半席風。"]'),
('32aed3e2-685c-41da-8f73-4c3bc90ef10a','簡陸務觀史君編修二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','聞道雲間陸士龍，釣臺絕頂嘯清風。',32,'全唐诗/poet.song.140000.json','["聞道雲間陸士龍，釣臺絕頂嘯清風。", "却將半掬催詩雨，灑入山村作歲豐。"]'),
('8e3c5585-d371-422a-8442-8e814689aa55','簡陸務觀史君編修二首  其二','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','員外治中高帝孫，幕中何幸有詩人。',32,'全唐诗/poet.song.140000.json','["員外治中高帝孫，幕中何幸有詩人。", "主人不減西湖長，青眼無妨顧德麟。"]'),
('7807d854-869e-446d-a4ff-021ec227520c','送王季德提刑寶文少卿','楊萬里','宋','宋诗','song-poetry','','["\u592a\u6e56"]','寶儲依舊接英游，蕩節何曾遠藻旒。',64,'全唐诗/poet.song.140000.json','["寶儲依舊接英游，蕩節何曾遠藻旒。", "卿月使星銀漢曉，繡衣綵服太湖秋。", "豺當道上狐何問，鷹擊霜前兔已愁。", "火急平反供一笑，紫荷玉笋待君侯。"]'),
('bf863094-31fc-48b3-9402-a0e5b8cdadbe','贈都下寫真葉德明','楊萬里','宋','宋诗','song-poetry','','[]','我昔山林人不識，或疑謫仙或狂客。',168,'全唐诗/poet.song.140000.json','["我昔山林人不識，或疑謫仙或狂客。", "仰看青天不看人，醉裏那知眼青白。", "一攜破硯入長安，素衣成緇綠鬢斑。", "上林麒麟著野馬，滄洲鷗鷺綴孔鸞。", "漢宮威儀既不入貴人樣，灞橋風雪又不見詩人相。", "不須覽鏡照清溪，我亦自憎塵俗狀。", "葉君著眼秋月明，葉君下筆秋風生。", "市人請畫即唾駡，只寫龍章鳳姿公與卿。", "肯來爲予寫衰貌，擲筆掉頭欣入妙。", "相逢可惜遲十年，不見詩翁昔年少。"]'),
('5896676b-a343-4e65-996d-1132c2521c33','初秋玩月','楊萬里','宋','宋诗','song-poetry','','[]','月華只是尋常月，如何入秋頓清絕。',128,'全唐诗/poet.song.140000.json','["月華只是尋常月，如何入秋頓清絕。", "潑在中庭滿地冰，飛上寒窗一堂雪。", "今宵無雨風亦無，涼氣却如風雨餘。", "九州四海幾人看，作意獨來尋老夫。", "仙人餐霞嚥朝日，老夫不願受此術。", "不如掇月入杯中，酒浪月波供一吸。", "老夫病肺怯清秋，對酒不飲月莫愁。", "老夫未眠月未落，相伴且到三更頭。"]'),
('798db836-4d48-43cd-b9cd-c95c84503f64','送孫檢正德操龍圖出知鎮江二首  其一','楊萬里','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','潤州太守去明州，誰寄長江萬里流。',64,'全唐诗/poet.song.140000.json','["潤州太守去明州，誰寄長江萬里流。", "雞省却煩三語掾，龍章卧護兩淮秋。", "古來北府多名酒，今復南徐說勝游。", "聊奉雙親小行樂，即持荷橐侍宸旒。"]'),
('712936ba-47e8-45f2-ad16-841b971ca021','送孫檢正德操龍圖出知鎮江二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','看花走馬紹興間，彼此春風各少年。',64,'全唐诗/poet.song.140000.json','["看花走馬紹興間，彼此春風各少年。", "黄甲諸儒今幾許，白頭同舍省東偏。", "昨宵歸夢月千里，餘債欠君詩兩篇。", "已乞閩山一窠闕，老身只要早歸田。"]'),
('983f1838-7f9d-482d-b20e-d2446dea5073','食雞頭子二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','江妃有訣煮真珠，菰飯牛酥軟不如。',64,'全唐诗/poet.song.140000.json','["江妃有訣煮真珠，菰飯牛酥軟不如。", "手擘雞顋金五色，盤傾驪頷琲千餘。", "夜光明月供朝嚼，水府龍宮恐夕虛。", "好與藍田餐玉法，編歸辟穀赤松書。"]'),
('d51c07ad-4c69-4ad9-bdf6-26b245a51efb','食雞頭子二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','三危瑞露凍成珠，九轉丹砂鍊久如。',64,'全唐诗/poet.song.140000.json','["三危瑞露凍成珠，九轉丹砂鍊久如。", "鼻觀溫芳炊桂歇，齒根熟軟剝胎餘。", "半甌鷹爪中秋近，一炷龍涎丈室虛。", "却憶吾廬野塘味，滿山柿葉正堪書。"]'),
('12f6d969-48e5-4679-a56f-189362b1d6b0','跋尤延之左司所藏光堯御書歌','楊萬里','宋','宋诗','song-poetry','','[]','鸞臺長史老野僧，月前病鶴霜後蠅。',242,'全唐诗/poet.song.140000.json','["鸞臺長史老野僧，月前病鶴霜後蠅。", "文書海裏衮不了，黑花亂發雙眼睛。", "故人同舍尤太史，敲門未揖心先喜。", "袖中傾下十斛珠，五色光芒射窗几。", "自言天風來帝旁，拾得復古殿中雲一張。", "向來太上坐朝罷，勝日光風花柳暇。", "浣花仄理冰雪容，宣城雞距針芒鋒。", "天顔有喜聊小試，西京書目供游戲。", "韓彭衛霍欣掛名，舒向卿雲感書字。", "漢廷多少失意人，九京寸恨不作塵。", "一朝翻入聖筆底，昭回之光喚渠起。", "小臣濫巾縫掖行，手抄孝經不徹章。", "何曾下筆寫史漢，再拜恭覽汗透裳。", "太史結廬伴鷗鷺，錫山山下荆溪渡。", "紅光紫氣上燭天，箇是深藏寶書處。"]'),
('4642536a-692d-4539-ad26-3391356ca383','賀皇太子九月四日生辰  其一','楊萬里','宋','宋诗','song-poetry','','[]','日日龍樓問寢時，雞人未動漏花遲。',32,'全唐诗/poet.song.140000.json','["日日龍樓問寢時，雞人未動漏花遲。", "前星一點朝天帝，只有清臺太史知。"]'),
('998b3601-4815-42cf-a1dd-9390040433b2','賀皇太子九月四日生辰  其二','楊萬里','宋','宋诗','song-poetry','','[]','清賞堂中無管弦，鳳山樓上有雲煙。',32,'全唐诗/poet.song.140000.json','["清賞堂中無管弦，鳳山樓上有雲煙。", "儲皇側畔何人侍，黄卷團欒是聖賢。"]'),
('83a68e5e-e1a8-4f04-af7b-45bdc6f282ea','賀皇太子九月四日生辰  其三','楊萬里','宋','宋诗','song-poetry','','[]','子晉吹笙未是仙，阿丕橫槊少全篇。',32,'全唐诗/poet.song.140000.json','["子晉吹笙未是仙，阿丕橫槊少全篇。", "小吟春著梅梢句，一日東風四海傳。"]'),
('aca56aba-3b94-4fb7-978d-85bf0d2c6f8e','賀皇太子九月四日生辰  其四','楊萬里','宋','宋诗','song-poetry','','[]','二聖多能似仲尼，儲皇家學自庭闈。',32,'全唐诗/poet.song.140000.json','["二聖多能似仲尼，儲皇家學自庭闈。", "銀鉤已有淳熙脚，玉句仍傳德壽衣。"]'),
('8540fc65-0f22-420e-a079-f7f985f6c4b6','賀皇太子九月四日生辰  其五','楊萬里','宋','宋诗','song-poetry','','[]','明河查上有仙翁，犯月撞星到碧穹。',32,'全唐诗/poet.song.140000.json','["明河查上有仙翁，犯月撞星到碧穹。", "金闕東邊銀榜處，大書天地長男宮。"]'),
('a3fce453-4dd5-4a21-bcf4-35681f62db62','賀皇太子九月四日生辰  其六','楊萬里','宋','宋诗','song-poetry','','[]','大安宮裏漆園椿，子榦孫枝葉葉新。',32,'全唐诗/poet.song.140000.json','["大安宮裏漆園椿，子榦孫枝葉葉新。", "今日四株高下碧，相承一樣八千春。"]'),
('e4403efb-f435-4563-ad7d-daac81d3834f','賀皇太子九月四日生辰  其七','楊萬里','宋','宋诗','song-poetry','','[]','菊花潭上菊花開，不是花潭是壽杯。',32,'全唐诗/poet.song.140000.json','["菊花潭上菊花開，不是花潭是壽杯。", "天賜生朝千斛水，一年一斛送將來。"]'),
('7f086354-1655-47d4-b0e1-32c82236e9c6','賀皇太子九月四日生辰  其八','楊萬里','宋','宋诗','song-poetry','','[]','禹子湯孫兼聖賢，一身雙美古無前。',32,'全唐诗/poet.song.140000.json','["禹子湯孫兼聖賢，一身雙美古無前。", "願陳萬國元良句，不用金昭玉粹篇。"]'),
('d207680b-a0cb-4a70-94c1-fb004bfecda3','賀皇太子九月四日生辰  其九','楊萬里','宋','宋诗','song-poetry','','[]','少陽拜賜太陽旁，黄菊紅萸滿壽觴。',32,'全唐诗/poet.song.140000.json','["少陽拜賜太陽旁，黄菊紅萸滿壽觴。", "陽德重重在初四，不須九日是重陽。"]'),
('0ff7744b-df91-42e7-a039-187c2d52b810','賀皇太子九月四日生辰  其一○','楊萬里','宋','宋诗','song-poetry','','[]','光堯初御六龍天，上直維參大火躔。',32,'全唐诗/poet.song.140000.json','["光堯初御六龍天，上直維參大火躔。", "天意分明昌宋德，誕辰三世總丁年。"]'),
('c86ea44b-2964-41d6-8ee5-fff09899d79b','尤延之檢正直廬窗前紅木犀一小株盛開戲呈延之','楊萬里','宋','宋诗','song-poetry','','[]','水沈國裏御風歸，栗玉肌膚不肯肥。',64,'全唐诗/poet.song.140000.json','["水沈國裏御風歸，栗玉肌膚不肯肥。", "元是金華學仙子，新將柿葉染秋衣。", "不應裝束追時好，無乃清癯悔昨非。", "爲妬尤郎得尤物，故將七字惱芳菲。"]'),
('dcfe47cd-781c-410d-aebe-78b7deacaa19','送張定叟二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','直上雲霄未遣休，分符京兆帝王州。',64,'全唐诗/poet.song.140000.json','["直上雲霄未遣休，分符京兆帝王州。", "赤丸窟裏無白額，碧落班中政黑頭。", "兩地好官纔半武，扁舟歸興恰中秋。", "只應銀信從天降，莫戀融峰與橘洲。"]'),
('2816d3a1-57dc-4008-bf35-148f04b09643','送張定叟二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','紫巖衣鉢付南軒，介弟曾同半夜傳。',64,'全唐诗/poet.song.140000.json','["紫巖衣鉢付南軒，介弟曾同半夜傳。", "師友別來真夢耳，江湖相對各潸然。", "但令門戶無遺恨，何必功名在早年。", "君向瀟湘我閩粵，寄書只在寄茶前。"]'),
('a18ec0bf-ae5a-4d5d-b075-40de208d1a36','新寒戲簡尤延之檢正','楊萬里','宋','宋诗','song-poetry','','[]','逗曉添衣併數重，隔晡剩熱尚斜紅。',64,'全唐诗/poet.song.140000.json','["逗曉添衣併數重，隔晡剩熱尚斜紅。", "秋生露竹風荷外，寒到雲窗霧閤中。", "半點暄涼能幾許，古來豪傑總成空。", "木犀香殺張園了，雪嗅金挼欠兩翁。"]'),
('f93f45a2-5844-411e-a517-b8e0ae2c7bf6','跋姜春坊梅山詩集二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','松風澗水打窗聲，玉佩瓊琚觸眼明。',64,'全唐诗/poet.song.140000.json','["松風澗水打窗聲，玉佩瓊琚觸眼明。", "當晝如何挂秋月，未春特地轉新鶑。", "只銷一卷梅山集，幻出多般景物情。", "老子平生有詩癖，爲君焚却老陶泓。"]'),
('10bd797c-2779-4035-93a3-1e8c4ff5a178','跋姜春坊梅山詩集二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','承華寮寀集鴛鸞，不減應徐讌魏園。',64,'全唐诗/poet.song.140000.json','["承華寮寀集鴛鸞，不減應徐讌魏園。", "中有釣璜清渭叟，向來授鉞少陵壇。", "錦心繡口搴花草，雪椀冰甌瀉肺肝。", "身到梅山得梅魄，老夫更借一枝看。"]'),
('32efbefa-2fd0-4a76-bef9-4886bf167025','早朝垂拱殿晚出東省','楊萬里','宋','宋诗','song-poetry','','[]','請外天難達，留中日不遑。',48,'全唐诗/poet.song.140000.json','["請外天難達，留中日不遑。", "烏啼金殿月，鷺集玉階霜。", "出晚緣堂白，歸時報錄黄。", "來年六十一，六十鬢蒼蒼。"]'),
('7f3151c8-1c51-4e73-8e94-fa2be70d4db4','跋京仲遠所藏楊補之紅綾上所作著色掀篷梅','楊萬里','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','朔雲暗天垂到地，朔風裂山吹脫耳。',178,'全唐诗/poet.song.140000.json','["朔雲暗天垂到地，朔風裂山吹脫耳。", "長江萬頃一艇子，一夜雪寒不成睡。", "詩翁曉起鬢髼鬆，縮頸微掀黄篾篷。", "夜來急雪已晴了，東方一抹輕霞紅。", "江梅的皪開獨樹，篷間截入梅尺許。", "老榦新枝紫復青，花琱白玉鬚黄金。", "滿身滿面都是雪，梅雪却與霞爭明。", "不知詩翁何處得霜鋸，和雪和梅斸將去。", "恐是并州快剪刀，不然吳剛修月斧。", "下無根榦上無梢，一眼橫陳梅半腰。", "東省拈出寒蕭蕭，至今花頭雪未銷。"]'),
('7d758d5e-e029-4e16-9355-13234bb54025','秋山','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','梧葉新黄柿葉紅，更兼烏臼與丹楓。',32,'全唐诗/poet.song.140000.json','["梧葉新黄柿葉紅，更兼烏臼與丹楓。", "只言山色秋蕭索，繡出西湖三四峰。"]'),
('8f0268e9-9c75-4c25-bae6-cfc3c4ff90ff','秋雨蚤作有歎','楊萬里','宋','宋诗','song-poetry','','[]','細雨澹無質，安得更有聲。',168,'全唐诗/poet.song.140000.json','["細雨澹無質，安得更有聲。", "如何却作泥，亦能妨晨征。", "宿昔忽過暄，心知非堅晴。", "何須暄晴極，然後寒雨生。", "寒暄使人覺，妙物亦何曾。", "翦翦自神妙，無乃與物矜。", "造物本非作，觀者或强名。", "老夫近稍聾，此事無暇聽。", "平生感秋至，此意念已平。", "獨念老病身，頗不耐夙興。", "何時歸故園，晏眠閉柴荆。", "鳴鷄亦不留，好夢無吾驚。", "他年憶此詩，惘如宿酒醒。", "思歸已可喜，而況真歸耕。"]'),
('9805e026-5b23-45f3-b4cb-ff3e7a8975ec','寄題王棶德脩知縣成都新居','楊萬里','宋','宋诗','song-poetry','','[]','子美百花潭北莊，君今占作詠歸堂。',64,'全唐诗/poet.song.140000.json','["子美百花潭北莊，君今占作詠歸堂。", "山分劍閣雲根瘦，江送蓬婆雪汁香。", "漱石枕流紅錦浪，浮家泛宅白鷗行。", "何人夜誦相如賦，給札蘭臺看堵牆。"]'),
('247c855b-d503-4c12-830a-b7e50fee8352','左藏南庫西廡下紙閤負暄戲題','楊萬里','宋','宋诗','song-poetry','','[]','水衡仙客住冰天，雪囓風餐更禁煙。',32,'全唐诗/poet.song.140000.json','["水衡仙客住冰天，雪囓風餐更禁煙。", "不是移來小暘谷，老夫凍折兩詩肩。"]'),
('1bbb7365-0973-45d5-a1f9-58ff2c54aa29','賀皇孫平陽郡王十月十九日生辰','楊萬里','宋','宋诗','song-poetry','','[]','前星炳煥領孫星，環拱中天日兩輪。',64,'全唐诗/poet.song.140000.json','["前星炳煥領孫星，環拱中天日兩輪。", "四葉重光同聖世，千秋佳節近生辰。", "本支秀茂旦復旦，典學熙明新又新。", "喜入威顔天一笑，壽觴分賜一枝椿。"]'),
('74a98e21-64dc-4ad2-8419-1b55a2ad717c','白紵歌舞四時詞 春','楊萬里','宋','宋诗','song-poetry','','[]','人生春睡要足時，海波可乾山可移。',64,'全唐诗/poet.song.140000.json','["人生春睡要足時，海波可乾山可移。", "珠宮宴罷曉星出，不是天上無鳴雞。", "昨來坐朝到日落，君王何曾一日樂。", "上林平樂半蒼苔，桃花又去楊花來。"]'),
('4c5e9244-4ada-4c43-adcb-c9e5fe3c94a3','白紵歌舞四時詞 夏','楊萬里','宋','宋诗','song-poetry','','[]','四月以後五月前，麥風槐雨黄梅天。',64,'全唐诗/poet.song.140000.json','["四月以後五月前，麥風槐雨黄梅天。", "君王若道嫌五月，六月炎蒸又何說。", "水精宮殿冰雪山，芙蕖衣裳菱芡盤。", "老農背脊曬欲裂，君王猶道深宮熱。"]'),
('be0d1b75-79c4-4c3f-9c5d-88e14ec111a1','白紵歌舞四時詞 秋','楊萬里','宋','宋诗','song-poetry','','[]','星芒欲滅天風急，月輪猶带銀河濕。',64,'全唐诗/poet.song.140000.json','["星芒欲滅天風急，月輪猶带銀河濕。", "青女椎冰作冷霜，吹到璇閨飛不入。", "苧羅山下浣紗人，萬妃無色抵一身。", "嬌餘貴極醉玉軟，强爲君王踏錦絪。"]'),
('576d9423-88fe-4f9d-9063-1f0b56fbea25','白紵歌舞四時詞 冬','楊萬里','宋','宋诗','song-poetry','','[]','祗愁窮臘雪作惡，不道雪天好行樂。',64,'全唐诗/poet.song.140000.json','["祗愁窮臘雪作惡，不道雪天好行樂。", "玻瓈盞底回青春，蒲萄錦外舞玉塵。", "陽春一曲小垂手，勸君一杯千萬壽。", "今年斛穀才八錢，明年切莫羨今年。"]'),
('2b2c5228-4fec-4edd-b4fb-4a2ac4922668','行路難五首  其一','楊萬里','宋','宋诗','song-poetry','','[]','君不見河陽花，今如泥土昔如霞。',174,'全唐诗/poet.song.140000.json','["君不見河陽花，今如泥土昔如霞。", "君不見武昌柳，春作金絲秋作帚。", "人生馬耳射東風，柳色桃花却長久。", "秦時東陵千戶侯，華蟲被體腰蒼璆。", "漢初沛邑刀筆吏，折腰如磬頭搶地。", "蕭相厥初謁邵平，中廷百拜百不應。", "邵平後來謁蕭相，故侯一拜一惆悵。", "萬事反覆何所無，二子豈是大丈夫。", "窮通流坎皆偶爾，摶扶未必賢槍榆。", "華胥別是一天地，醉鄉何曾有生死。", "儂欲與君歸去來，千愁萬恨付一杯。"]'),
('a6c25206-d850-4d40-acdf-055fc250dcae','行路難五首  其二','楊萬里','宋','宋诗','song-poetry','','[]','老夫少時不信老，長笑老人恃年少。',100,'全唐诗/poet.song.140000.json','["老夫少時不信老，長笑老人恃年少。", "如今老矣不笑人，却被少年開口笑。", "少年何苦笑老人，老人舊日顔如春。", "興來百盞山隤玉，醉後千篇筆有神。", "自古聖賢皆白骨，誰道今人不見古時月。", "孔子盜跖俱塵埃，杜陵老人今亦安在哉。"]'),
('c2ec15fc-b8f6-4502-aa6c-5d7d7c63effb','行路難五首  其三','楊萬里','宋','宋诗','song-poetry','','[]','黄金築臺賜白璧，車前八騶門列戟。',100,'全唐诗/poet.song.140000.json','["黄金築臺賜白璧，車前八騶門列戟。", "徹侯萬戶秩萬石，珠戶玉房貯傾國。", "傳呼一聲萬人開，將軍相國天上來。", "不知道旁雍門子，已歎麋鹿登高臺。", "雍門解遣孟嘗泣，孟嘗不泣渠何急。", "只知富貴如雲浮，不知貧賤饑死寒死愁不愁。"]'),
('97c515a5-cef6-4015-a043-ec2afa8b422d','行路難五首  其四','楊萬里','宋','宋诗','song-poetry','','[]','長門陳阿嬌，却要一生金屋貯嬌饒。',96,'全唐诗/poet.song.140000.json','["長門陳阿嬌，却要一生金屋貯嬌饒。", "長信班婕妤，却要一生紈扇從玉車。", "妾心祗作專房地，別人亦有承恩意。", "妾心不肯著別人，君心還肯如妾心。", "春風秋月渾不管，花落花開空自怨。", "千秋萬歲一笑休，月明空照古今愁。"]'),
('f3ebdf0d-00d0-4bf4-b10b-eb08edca5c8a','行路難五首  其五','楊萬里','宋','宋诗','song-poetry','','[]','造化小兒不耐閑，阿兄阿姊一似顛。',177,'全唐诗/poet.song.140000.json','["造化小兒不耐閑，阿兄阿姊一似顛。", "兩手雙弄赤白丸，來來去去繞青天。", "赤丸才向西山沒，白丸又向東山出。", "只銷三萬六千回，雪色少年成皺鐵，鐵色頭鬚却成雪。", "雙丸繞從地下復上天，少年一入地下更不還。", "日日喜歡能幾許，況有煩惱無喜歡。", "莫言酒不到劉伶墳上土，劉伶在時一醉曾三年。", "明珠一百斛，更添百斛也只心不足。", "侯印十九枚，更添一倍也只眉不開。", "先生笑渠不行樂，莫教人笑先生錯。"]'),
('d935859b-e51f-424e-902b-52f9c28db86e','寄題喻叔奇國博郎中園亭二十六詠 亦好園','楊萬里','宋','宋诗','song-poetry','','[]','金谷惟堪貯俗塵，輞川今復得詩人。',32,'全唐诗/poet.song.140000.json','["金谷惟堪貯俗塵，輞川今復得詩人。", "先生道是貧到骨，猶有山園斗大春。"]'),
('0514e5d9-eacd-4a23-9560-62c785e82156','寄題喻叔奇國博郎中園亭二十六詠 磬湖','楊萬里','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','洞庭張樂起天風，玉磬吹來墮圃中。',32,'全唐诗/poet.song.140000.json','["洞庭張樂起天風，玉磬吹來墮圃中。", "却被仙人鎔作水，爲君到底寫秋空。"]'),
('6e7aba47-d568-4087-b79d-ffab86c044cd','寄題喻叔奇國博郎中園亭二十六詠 釣磯','楊萬里','宋','宋诗','song-poetry','','[]','烏龍灘下白雲堆，上有狂奴舊釣臺。',32,'全唐诗/poet.song.140000.json','["烏龍灘下白雲堆，上有狂奴舊釣臺。", "一夕被君偷取去，至今猶带漢莓苔。"]'),
('c5f1f8c6-7268-41fc-9b83-cbe403d699a2','寄題喻叔奇國博郎中園亭二十六詠 蘆葦林','楊萬里','宋','宋诗','song-poetry','','[]','春有兒孫夏有朋，月中寒影雨中聲。',32,'全唐诗/poet.song.140000.json','["春有兒孫夏有朋，月中寒影雨中聲。", "臘晴銷盡一園雪，爲底林間雪不晴。"]'),
('80476dfa-262e-41cd-9517-152b15f1b46e','寄題喻叔奇國博郎中園亭二十六詠 亦好亭','楊萬里','宋','宋诗','song-poetry','','[]','亦好園中亦好亭，兩重好處兩重貧。',32,'全唐诗/poet.song.140000.json','["亦好園中亦好亭，兩重好處兩重貧。", "客來莫道無供給，抹月批風當八珍。"]'),
('df5f5128-eefd-4f03-8b50-8baedc66c7d3','寄題喻叔奇國博郎中園亭二十六詠 橫枝','楊萬里','宋','宋诗','song-poetry','','[]','冰爲仙骨水爲肌，意淡香幽祗自知。',32,'全唐诗/poet.song.140000.json','["冰爲仙骨水爲肌，意淡香幽祗自知。", "青女素娥非耐冷，一生耐冷是橫枝。"]'),
('be91508c-b5ba-4bec-833c-de585afb172a','寄題喻叔奇國博郎中園亭二十六詠 清淺池','楊萬里','宋','宋诗','song-poetry','','[]','橫枝直下是清池，花映清池水映枝。',32,'全唐诗/poet.song.140000.json','["橫枝直下是清池，花映清池水映枝。", "知是君描和靖句，不知和靖寄君詩。"]'),
('a9852a7a-e4fe-4a8c-b493-bd32e6103c26','寄題喻叔奇國博郎中園亭二十六詠 荼䕷洞','楊萬里','宋','宋诗','song-poetry','','[]','舊繞新縈綠萬蟠，架餘籬剩復垂欄。',32,'全唐诗/poet.song.140000.json','["舊繞新縈綠萬蟠，架餘籬剩復垂欄。", "先生醉帽堆香雪，知自荼䕷洞裏還。"]'),
('9258dc57-49de-4e0d-9f12-e9004d8abca0','寄題喻叔奇國博郎中園亭二十六詠 小山','楊萬里','宋','宋诗','song-poetry','','[]','湧岫跳峰尺許寬，坐看雲霧起巖間。',32,'全唐诗/poet.song.140000.json','["湧岫跳峰尺許寬，坐看雲霧起巖間。", "九疑荒遠巫陽嶮，未必真山勝假山。"]'),
('ea5ae43f-26fa-4409-a690-781d2341a7f2','寄題喻叔奇國博郎中園亭二十六詠 花屏','楊萬里','宋','宋诗','song-poetry','','[]','錦障豪華笑騃童，松圖冷淡惱山翁。',32,'全唐诗/poet.song.140000.json','["錦障豪華笑騃童，松圖冷淡惱山翁。", "玉山頹處誰扶著，花作屏風倚暖紅。"]'),
('53c92406-8a29-4a56-b5d8-f5a7b23d94c5','寄題喻叔奇國博郎中園亭二十六詠 紫君林','楊萬里','宋','宋诗','song-poetry','','[]','青士從來一徑幽，碧衫翠袖佩蒼璆。',32,'全唐诗/poet.song.140000.json','["青士從來一徑幽，碧衫翠袖佩蒼璆。", "何年筆戰明光殿，奪得詩仙紫綺裘。"]'),
('3dc72843-29ed-4135-8e73-58ffe587137e','寄題喻叔奇國博郎中園亭二十六詠 方池','楊萬里','宋','宋诗','song-poetry','','[]','水精方局石橋仙，知是柯山幾代孫。',32,'全唐诗/poet.song.140000.json','["水精方局石橋仙，知是柯山幾代孫。", "月借繁星作棋子，夜寒睹得一金盆。"]'),
('97b0df19-c607-405b-868f-9cb61bcbf35e','寄題喻叔奇國博郎中園亭二十六詠 野橋','楊萬里','宋','宋诗','song-poetry','','[]','亦好亭兼弄月亭，磬湖不許兩通行。',32,'全唐诗/poet.song.140000.json','["亦好亭兼弄月亭，磬湖不許兩通行。", "誰拋螮蝀湖光尾，便有先生拄杖聲。"]'),
('e2c98732-4ccf-4454-8128-7c7c38adbba0','寄題喻叔奇國博郎中園亭二十六詠 菊徑','楊萬里','宋','宋诗','song-poetry','','[]','身在京師夢在鄉，黄花又是一番黄。',32,'全唐诗/poet.song.140000.json','["身在京師夢在鄉，黄花又是一番黄。", "平生不解淵明語，菊却猶存徑却荒。"]'),
('7be4a53a-d90c-45dc-bb63-c5132a8ec1a2','寄題喻叔奇國博郎中園亭二十六詠 藥畦','楊萬里','宋','宋诗','song-poetry','','[]','雨餘想見藥苗肥，薯蕷堪羹杞可齏。',32,'全唐诗/poet.song.140000.json','["雨餘想見藥苗肥，薯蕷堪羹杞可齏。", "老賊何須投益智，先生只要買當歸。"]'),
('ee59252a-8a46-4c66-9594-4295b5bfd710','寄題喻叔奇國博郎中園亭二十六詠 弄月亭','楊萬里','宋','宋诗','song-poetry','','[]','碧天如水水如天，月入湖中璧樣圜。',32,'全唐诗/poet.song.140000.json','["碧天如水水如天，月入湖中璧樣圜。", "却被先生來弄碎，一團成百百成千。"]'),
('59ce095f-f65c-4443-a46e-f36b3439a5ae','寄題喻叔奇國博郎中園亭二十六詠 花嶼','楊萬里','宋','宋诗','song-poetry','','[]','桃李無言照水光，玻瓈盆底洗新粧。',32,'全唐诗/poet.song.140000.json','["桃李無言照水光，玻瓈盆底洗新粧。", "不須水上紅雲句，水上紅雲不解香。"]'),
('a47e1f15-c21e-4f30-ba43-eee71c0e2799','寄題喻叔奇國博郎中園亭二十六詠 柳隄','楊萬里','宋','宋诗','song-poetry','','[]','柳下湖光浄一天，湖邊垂柳起三眠。',32,'全唐诗/poet.song.140000.json','["柳下湖光浄一天，湖邊垂柳起三眠。", "小蠻自倚腰支裊，照鏡梳頭曉月前。"]'),
('eabd2c8a-343c-4bd5-8b3b-16650c40878e','寄題喻叔奇國博郎中園亭二十六詠 曲水','楊萬里','宋','宋诗','song-poetry','','[]','名園曲水費工夫，玉甃瓊磨滴水無。',32,'全唐诗/poet.song.140000.json','["名園曲水費工夫，玉甃瓊磨滴水無。", "誰把流觴借詩老，天生九曲一冰渠。"]'),
('cae2669a-8bb3-45c1-a1fa-4d256066b77d','寄題喻叔奇國博郎中園亭二十六詠 水簾','楊萬里','宋','宋诗','song-poetry','','[]','秧疇水落荇渠尖，玉石當中碧一奩。',32,'全唐诗/poet.song.140000.json','["秧疇水落荇渠尖，玉石當中碧一奩。", "石面平鋪波面皺，千花織出水精簾。"]'),
('7485ee20-1f7c-4ad5-9624-13fcd2e917d8','寄題喻叔奇國博郎中園亭二十六詠 水樂','楊萬里','宋','宋诗','song-poetry','','[]','渠水來從林外泓，水知湖近各爭鳴。',32,'全唐诗/poet.song.140000.json','["渠水來從林外泓，水知湖近各爭鳴。", "何人月下携枯木，寫取穿雲落澗聲。"]'),
('d4e0bdd2-fdfd-4b15-97c0-47937ac22ab8','寄題喻叔奇國博郎中園亭二十六詠 竹巖','楊萬里','宋','宋诗','song-poetry','','[]','石友拳然萬仞姿，竹君嘯處一川漪。',32,'全唐诗/poet.song.140000.json','["石友拳然萬仞姿，竹君嘯處一川漪。", "更無二客隨巾屨，誰見先生覓句時。"]'),
('dd8a3075-4ac1-4b30-98e3-d10b164c1e4f','寄題喻叔奇國博郎中園亭二十六詠 野塘','楊萬里','宋','宋诗','song-poetry','','[]','雁下菰蒲報夕寒，鷺將荇藻作朝餐。',32,'全唐诗/poet.song.140000.json','["雁下菰蒲報夕寒，鷺將荇藻作朝餐。", "野塘只許野人到，不要金張許史看。"]'),
('e7407438-c683-46e3-b062-135218fec3e4','寄題喻叔奇國博郎中園亭二十六詠 愛山堂','楊萬里','宋','宋诗','song-poetry','','[]','詩人性癖愛看山，曉坐堂中夕嬾還。',32,'全唐诗/poet.song.140000.json','["詩人性癖愛看山，曉坐堂中夕嬾還。", "只對月山無限好，月山外面八雙鬟。"]'),
('8729a18f-7cdd-4fa8-be56-4d7767fede12','寄題喻叔奇國博郎中園亭二十六詠 海棠塢','楊萬里','宋','宋诗','song-poetry','','[]','細雨初憐濕翠裳，新晴特地試紅粧。',32,'全唐诗/poet.song.140000.json','["細雨初憐濕翠裳，新晴特地試紅粧。", "無人會得東風意，春色都將付海棠。"]'),
('5dc8ef56-3a9f-470a-9dcc-ea03569a70ff','寄題喻叔奇國博郎中園亭二十六詠 月山','楊萬里','宋','宋诗','song-poetry','','[]','昔人只解笑移山，未信移山不作難。',32,'全唐诗/poet.song.140000.json','["昔人只解笑移山，未信移山不作難。", "一昨月山三里外，先生掇取近欄干。"]'),
('24098596-4aa7-4d0c-bd9c-7f7d50512f34','題永新吳景蘇主簿梯雲樓','楊萬里','宋','宋诗','song-poetry','','[]','誰道青雲不可梯，君家樓閣與雲齊。',64,'全唐诗/poet.song.140000.json','["誰道青雲不可梯，君家樓閣與雲齊。", "諍臣內相名垂日，諫草詞頭字印泥。", "我昔曾爲禾水客，夢中猶憶義山西。", "仇香自有家聲在，豈使鸞皇棘上栖。"]'),
('0989a41c-34e8-4f32-90fb-a3b75ba6ce82','題安城趙寬之慈順堂','楊萬里','宋','宋诗','song-poetry','','[]','天潢龍種與人殊，五鳳仍傳萬卷書。',64,'全唐诗/poet.song.140000.json','["天潢龍種與人殊，五鳳仍傳萬卷書。", "象服在堂萱草暖，綵衣上壽棣華初。", "雪中密竹能抽筍，冰底寒江更躍魚。", "趙氏弟兄俱玉樹，艮齋文字即瓊琚。"]'),
('a297e211-2c6b-4375-9c79-03675217bd33','寄題曾子與競秀亭','楊萬里','宋','宋诗','song-poetry','','[]','老夫上下蓼花灘，每過君家輒繫船。',64,'全唐诗/poet.song.140000.json','["老夫上下蓼花灘，每過君家輒繫船。", "尊酒燈前山入座，孤鴻月底水連天。", "暄凉書問二千里，場屋聲名三十年。", "競秀主人文似豹，不應霧隠萬峰邊。"]'),
('50076499-f01b-4c29-8fa5-b0238c60ecab','送朝士使虜','楊萬里','宋','宋诗','song-poetry','','[]','又見皇華賦北征，謫仙俊氣似秋鷹。',64,'全唐诗/poet.song.140000.json','["又見皇華賦北征，謫仙俊氣似秋鷹。", "詩成紫塞三更月，馬渡黄河十丈冰。", "趙北燕南有人否，禽胡歸漢竟誰曾。", "天家社稷英靈在，佳氣時時起五陵。"]'),
('8f3db5a8-e089-4d2a-9a98-eda56ad47df7','冬至稱賀紫宸殿及德壽宮','楊萬里','宋','宋诗','song-poetry','','[]','宮燭奔忙下玉除，晨曦拂掠麗儲胥。',64,'全唐诗/poet.song.140000.json','["宮燭奔忙下玉除，晨曦拂掠麗儲胥。", "東西班動雲開合，警蹕聲來電卷舒。", "隆準衣裳紅一點，御香煙霧碧千廬。", "勛華二聖天齊壽，亞歲年年賀帝居。"]'),
('75648aef-ace3-4400-99e0-21c9b6881e87','冬至後賀皇太子及平陽郡王','楊萬里','宋','宋诗','song-poetry','','[]','長樂鐘聲攪夢驚，建章星影照人行。',64,'全唐诗/poet.song.140000.json','["長樂鐘聲攪夢驚，建章星影照人行。", "千官燈語聽殘點，一夜霜寒在五更。", "金鑰玉𥫽開北闕，銀鞍絲控謁東明。", "青宮朱邸環天極，五色祥雲覆帝城。"]'),
('cd8e4224-2de1-4078-bd28-1ca19e002e66','跋張功父通判直閣所惠約齋詩乙藁','楊萬里','宋','宋诗','song-poetry','','[]','句裏勤分似，燈前得細嘗。',48,'全唐诗/poet.song.140000.json','["句裏勤分似，燈前得細嘗。", "孤芳後山種，一瓣放翁香。", "苦處霜爭澀，臞來鶴校强。", "不應窮活計，公子也忙忙。"]'),
('944fc145-6fb7-4cca-8f69-0f3fb3c0727e','張功父舊字時可慕郭功父故易之求予書其意再贈五字','楊萬里','宋','宋诗','song-poetry','','[]','冰雪相投處，風期一笑間。',48,'全唐诗/poet.song.140000.json','["冰雪相投處，風期一笑間。", "只今張桂隠，絕慕郭青山。", "功父雙何遠，相如了不關。", "鳥飛暮天碧，此句急追還。"]'),
('0f986bf1-f1f9-497f-b451-43facd9601a2','走筆和張功父玉照堂十絕句  其一','楊萬里','宋','宋诗','song-poetry','','[]','健青新走一梢長，外日東風引得狂。',32,'全唐诗/poet.song.140000.json','["健青新走一梢長，外日東風引得狂。", "定自今番春色裏，新枝別樣占年光。"]'),
('17788b1b-88ce-48c6-82e7-54f10f691710','走筆和張功父玉照堂十絕句  其二','楊萬里','宋','宋诗','song-poetry','','[]','年年春信遣人疑，賺出詩人枉覓詩。',32,'全唐诗/poet.song.140000.json','["年年春信遣人疑，賺出詩人枉覓詩。", "著意探梅偏不發，月斜偶見一橫枝。"]'),
('a3b1a8ba-dcb7-4373-b206-9c5beeada177','走筆和張功父玉照堂十絕句  其三','楊萬里','宋','宋诗','song-poetry','','[]','騃女癡兒總愛梅，道人衲子亦爭栽。',32,'全唐诗/poet.song.140000.json','["騃女癡兒總愛梅，道人衲子亦爭栽。", "何如雪後瓊瑶跡，印記詩人獨自來。"]'),
('28324b66-59fd-45db-bfe5-dd5eea122200','走筆和張功父玉照堂十絕句  其四','楊萬里','宋','宋诗','song-poetry','','[]','梅詩脫口已流傳，要趁梅前更雪前。',32,'全唐诗/poet.song.140000.json','["梅詩脫口已流傳，要趁梅前更雪前。", "喚醒誠齋山裏夢，落英如雪枕磚眠。"]'),
('30c5acb9-da98-45a8-a596-ebc5b0d51c48','走筆和張功父玉照堂十絕句  其五','楊萬里','宋','宋诗','song-poetry','','[]','紅紅紫紫儘紜紜，韻處終輸庾嶺君。',32,'全唐诗/poet.song.140000.json','["紅紅紫紫儘紜紜，韻處終輸庾嶺君。", "未說玉花冰雪骨，新陰先綠半春雲。"]'),
('9320b640-2565-44d7-baa4-45a746084d21','走筆和張功父玉照堂十絕句  其六','楊萬里','宋','宋诗','song-poetry','','[]','常年十月未花開，雪片今年九月回。',32,'全唐诗/poet.song.140000.json','["常年十月未花開，雪片今年九月回。", "便有早梅隨早雪，一枝笑看萬花摧。"]'),
('42b1acca-4795-4adb-b463-c122fc7a5a1c','走筆和張功父玉照堂十絕句  其七','楊萬里','宋','宋诗','song-poetry','','[]','今歲略無霜報寒，忽然一夜雪漫漫。',32,'全唐诗/poet.song.140000.json','["今歲略無霜報寒，忽然一夜雪漫漫。", "雪花要作梅花地，十月早梅和雪看。"]'),
('e763d09b-6969-4a7c-9702-6ab7fefdccb1','走筆和張功父玉照堂十絕句  其八','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','老見千花眼便昏，憶梅長爲賦招魂。',32,'全唐诗/poet.song.140000.json','["老見千花眼便昏，憶梅長爲賦招魂。", "只今身住西湖上，不羨淮南嶺上村。"]'),
('c6b6191c-6923-4b87-8849-f2c7ae3bbfe6','走筆和張功父玉照堂十絕句  其九','楊萬里','宋','宋诗','song-poetry','','[]','玉照堂中瀹早茶，下臨溪水織紋紗。',32,'全唐诗/poet.song.140000.json','["玉照堂中瀹早茶，下臨溪水織紋紗。", "十詩小試春風手，催發溪梅兩岸花。"]'),
('2949b76f-8fc7-448a-af95-63ca256782cb','走筆和張功父玉照堂十絕句  其一○','楊萬里','宋','宋诗','song-poetry','','[]','老嬾狂吟不要工，愛君七字晉唐風。',32,'全唐诗/poet.song.140000.json','["老嬾狂吟不要工，愛君七字晉唐風。", "更煩傳語梅花道，火急齊開小至中。"]'),
('6fd77952-b947-420c-b82e-e70c9fc45ef9','曉經八盤嶺赴東宮講堂','楊萬里','宋','宋诗','song-poetry','','[]','至前至後恰多晴，山北山南間一登。',64,'全唐诗/poet.song.140000.json','["至前至後恰多晴，山北山南間一登。", "瘦石經霜乾脫蘚，細泉滴澗旋成冰。", "海波貫日紅千丈，江霧縈樓玉萬層。", "資善堂前得春早，宮梅一朶掠觚稜。"]'),
('fac1128f-91ce-41e6-a435-764bd0c39415','出北關門送李舍人使虜','楊萬里','宋','宋诗','song-poetry','','[]','同寮緩轡出承華，又送雙星水北涯。',64,'全唐诗/poet.song.140000.json','["同寮緩轡出承華，又送雙星水北涯。", "霜外汀洲蘆葉曉，雪餘園圃竹梢斜。", "只驚睡起猶殘月，不覺歸時已落霞。", "白首鴛行徒索米，故山今日政梅花。"]'),
('069768fd-5585-44a3-a647-42f2f380231f','赴文德殿聽麻仍拜表','楊萬里','宋','宋诗','song-poetry','','[]','蒼龍觀闕啟槐宸，白玉階除振鷺羣。',64,'全唐诗/poet.song.140000.json','["蒼龍觀闕啟槐宸，白玉階除振鷺羣。", "仗外諸峰獻松雪，霜前一雁度宮雲。", "舍人就日宣麻制，丞相瞻天進表文。", "夙退自欣還自笑，素餐便當策殊勳。"]'),
('4286f62e-e996-4ad4-af15-d1be69ecb255','跋尤延之山水兩軸二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','水際蘆青荷葉黄，霜前木落蓼花香。',32,'全唐诗/poet.song.140000.json','["水際蘆青荷葉黄，霜前木落蓼花香。", "漁舟去盡天將夕，雪色飛來鷺一行。"]'),
('2fe1b6e6-db00-490c-a013-32f2b222cf2c','跋尤延之山水兩軸二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','水漱瓊沙冰已凘，野鳬半起半猶遲。',32,'全唐诗/poet.song.140000.json','["水漱瓊沙冰已凘，野鳬半起半猶遲。", "千竿脩竹一江碧，只欠梅花三兩枝。"]'),
('f5af16b2-779d-450f-87ef-fd0d7e972e12','紫宸殿拜表賀雪二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','怪來臘日起春風，一夜瓊花發禁中。',64,'全唐诗/poet.song.140000.json','["怪來臘日起春風，一夜瓊花發禁中。", "大地山河銀色界，九重樓觀水精宮。", "紫宸廊迥寒無價，文石庭乾掃不融。", "又喜來年書大有，誰知聖主是天公。"]'),
('324939d5-47e5-4ace-8c03-85730adade17','紫宸殿拜表賀雪二首  其二','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','稍緩鳴靴不住催，一聲再拜忽如雷。',64,'全唐诗/poet.song.140000.json','["稍緩鳴靴不住催，一聲再拜忽如雷。", "封章進了儀曹退，文武班齊上相來。", "白髮兩年陪賀雪，紫衣數輩小傳杯。", "賜休退食端何恨，未到西湖探早梅。"]'),
('4c8c675e-fb50-428d-8ee7-ac982945a089','衝雪送陸子靜','楊萬里','宋','宋诗','song-poetry','','[]','猛落還中歇，疎飛忽驟繁。',48,'全唐诗/poet.song.140000.json','["猛落還中歇，疎飛忽驟繁。", "平欺蘆屋脊，偏護竹籬根。", "對面看童子，低頭印手痕。", "銷魂送行客，行客更銷魂。"]'),
('aedcc388-20b3-4a7c-a53a-58367208c5ee','雪中送客過清水閘二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','雪中出去雪中回，深閉窗櫺偶一開。',32,'全唐诗/poet.song.140000.json','["雪中出去雪中回，深閉窗櫺偶一開。", "牆裏人家掃簷瓦，玉塵打入轎窗來。"]'),
('2584a89f-a6ca-4392-854c-82feb2eab3c8','雪中送客過清水閘二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','肩輿九步十傾欹，下有冰河不敢窺。',32,'全唐诗/poet.song.140000.json','["肩輿九步十傾欹，下有冰河不敢窺。", "冰上水禽行似箭，忽逢缺處得魚兒。"]'),
('77dcbf85-44d8-47fc-aab3-aa9e8435a275','和皇太子梅詩二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','清賞堂前隔俗塵，南枝得雪曉爭新。',32,'全唐诗/poet.song.140000.json','["清賞堂前隔俗塵，南枝得雪曉爭新。", "獨將却月凌風影，攙獻儲皇第一春。"]'),
('187b1736-e965-4c57-82e3-2e156842b3ca','和皇太子梅詩二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','梅仙踏雪步生塵，儲后梅詩雪共新。',32,'全唐诗/poet.song.140000.json','["梅仙踏雪步生塵，儲后梅詩雪共新。", "玉句金章雲錦字，問天覓得隔年春。"]'),
('8ebe34ff-c86d-4256-8e1d-2e3bed4faabf','和吳監丞景雪中湖上訪梅四首  其一','楊萬里','宋','宋诗','song-poetry','','[]','朔風敢傍貴人嚴，約束天花莫入簷。',32,'全唐诗/poet.song.140000.json','["朔風敢傍貴人嚴，約束天花莫入簷。", "藥玉船寬初瀲瀲，銷金帳暖政厭厭。"]'),
('d88bfae1-fcd8-4a0b-b76a-7c1ab64205f0','和吳監丞景雪中湖上訪梅四首  其二','楊萬里','宋','宋诗','song-poetry','','[]','七字全勝五字城，清於庾信及鍾嶸。',32,'全唐诗/poet.song.140000.json','["七字全勝五字城，清於庾信及鍾嶸。", "君詩妙絕端何似，不似梅花似麽生。"]'),
('a2c3de75-91fa-426e-81ff-642d361c2ae5','和吳監丞景雪中湖上訪梅四首  其三','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','雪與梅花兩逼真，不知誰好復誰新。',32,'全唐诗/poet.song.140000.json','["雪與梅花兩逼真，不知誰好復誰新。", "無端更入吳融手，剪取西湖半段春。"]'),
('c797fb71-3d55-4b8a-8f34-3d293c0eae57','和吳監丞景雪中湖上訪梅四首  其四','楊萬里','宋','宋诗','song-poetry','','[]','聞君踏雪訪梅花，不怕蘇堤十里賒。',32,'全唐诗/poet.song.140000.json','["聞君踏雪訪梅花，不怕蘇堤十里賒。", "老子怯寒那敢出，地爐榾柮是生涯。"]'),
('08df172b-1aca-440d-a8ee-34ac445a9fe5','早謁景靈宮','楊萬里','宋','宋诗','song-poetry','','[]','夜雪猶飄天目峰，曉晴先暖太清宮。',64,'全唐诗/poet.song.140000.json','["夜雪猶飄天目峰，曉晴先暖太清宮。", "雲翻孔雀金花碧，日射鴛鴦玉瓦紅。", "百辟焚香官柳影，一鴉飛立殿簷東。", "仰瞻九聖聯龍衮，萬歲千秋對昊穹。"]'),
('5ff5b5df-e90a-49c1-88f3-cfe335f0b21d','送吳監丞季行知簡州','楊萬里','宋','宋诗','song-poetry','','[]','勳烈涪陽異姓王，手扶西極漢天長。',64,'全唐诗/poet.song.140000.json','["勳烈涪陽異姓王，手扶西極漢天長。", "有孫文武千人傑，透紙風騷萬字香。", "小涉移中公事筆，又懷劍外史君章。", "同朝多日相從少，不唱陽關也斷腸。"]'),
('20b51d4a-959b-41ee-90fc-4b1441cf6902','送陸子靜刪定宮使','楊萬里','宋','宋诗','song-poetry','','[]','朝路江西不十人，又看一箇奉仙真。',64,'全唐诗/poet.song.140000.json','["朝路江西不十人，又看一箇奉仙真。", "可憐議論長傾坐，不管聲名解誤身。", "苦憶去年郊祀日，與渠並轡笑談春。", "何時相趁滄洲去，雪笠風蓑釣白蘋。"]'),
('467d9844-afb0-41d7-af5d-2c261fde87bb','雪晴二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','仙人翦水作花飛，忽化瓊瑶已大奇。',32,'全唐诗/poet.song.140000.json','["仙人翦水作花飛，忽化瓊瑶已大奇。", "復把瓊瑶化成水，滴來平地總琉璃。"]'),
('5b588ee0-d1fd-48ff-a164-41f740afbd97','雪晴二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','晴光雪色忽相逢，雨滴空階日影中。',32,'全唐诗/poet.song.140000.json','["晴光雪色忽相逢，雨滴空階日影中。", "珍重北簷殊韻勝，苛留殘玉不教融。"]'),
('673e62dc-d788-4836-94d8-34e74530b68a','和皇太子瑞雪二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','白玉花開碧玉天，縈樓繞殿舞翩然。',32,'全唐诗/poet.song.140000.json','["白玉花開碧玉天，縈樓繞殿舞翩然。", "儲皇善頌天皇德，瑞應金穰萬萬年。"]'),
('b733bf05-8a66-4a3c-8b31-523cfe2908be','和皇太子瑞雪二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','揉雲挼霧碎成塵，落不曾休酉達辰。',32,'全唐诗/poet.song.140000.json','["揉雲挼霧碎成塵，落不曾休酉達辰。", "鶴禁鏤冰成七字，野人拜賜敢辭頻。"]'),
('1f697f8e-ba08-401d-aedb-acc0f4bec888','雪後曉過八盤嶺詣東宮謝受左司告二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','扶桑梢上上朝暾，起早行遲却載奔。',32,'全唐诗/poet.song.140000.json','["扶桑梢上上朝暾，起早行遲却載奔。", "玉作宮城三萬雉，呼僮換馬入金門。"]'),
('9a1af1a4-5a45-47da-90ee-a0adc1769528','雪後曉過八盤嶺詣東宮謝受左司告二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','玉京世界大千中，銀屋樓臺一萬重。',32,'全唐诗/poet.song.140000.json','["玉京世界大千中，銀屋樓臺一萬重。", "好上寶蓮山上望，南高峰照北高峰。"]'),
('5be86142-3b22-46c6-83a1-d22313fdf5db','晴後再雪四首  其一','楊萬里','宋','宋诗','song-poetry','','[]','幸自晴光雪半開，誰將泥脚涴瓊瑰。',32,'全唐诗/poet.song.140000.json','["幸自晴光雪半開，誰將泥脚涴瓊瑰。", "水仙上訴姮娥泣，再遣天花散一回。"]'),
('3d241a1c-0f82-4404-9ddd-8523a6ab25fe','晴後再雪四首  其二','楊萬里','宋','宋诗','song-poetry','','[]','滕家仙子六瓊娘，煮露爲酥不剩漿。',32,'全唐诗/poet.song.140000.json','["滕家仙子六瓊娘，煮露爲酥不剩漿。", "滴作玉蟲千萬隻，一時飛滿白雲鄉。"]'),
('fd7e9dca-4c0a-4566-ae08-a1550c5d8ee8','晴後再雪四首  其三','楊萬里','宋','宋诗','song-poetry','','[]','天上瓊樓萬玉妃，月宮學舞試雲衣。',32,'全唐诗/poet.song.140000.json','["天上瓊樓萬玉妃，月宮學舞試雲衣。", "霓裳未徹天風起，腦子花鈿星散飛。"]'),
('fdcbf4bf-6815-4ce0-99c1-c171830e9c5c','晴後再雪四首  其四','楊萬里','宋','宋诗','song-poetry','','[]','八盤嶺上雪偏清，萬斛瓊塵作一傾。',32,'全唐诗/poet.song.140000.json','["八盤嶺上雪偏清，萬斛瓊塵作一傾。", "空裏仰看都不見，碧山映得却分明。"]'),
('ee8c8b57-c76e-4772-a2db-fe1da522d26b','讀子房傳','楊萬里','宋','宋诗','song-poetry','','[]','笑賭乾坤看兩龍，淮陰目動即雌雄。',32,'全唐诗/poet.song.140000.json','["笑賭乾坤看兩龍，淮陰目動即雌雄。", "興王大計無尋處，却在先生一躡中。"]'),
('0e1bf6fc-accb-4d74-99b6-ed0c1f887486','雪中講堂賜酒二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','玉果金柈碼碯觴，春坊傳令賜雲漿。',32,'全唐诗/poet.song.140000.json','["玉果金柈碼碯觴，春坊傳令賜雲漿。", "雪中上馬渾如夢，一片飛來醉面涼。"]'),
('2e62b801-a836-4e4e-b6fe-a7d4ac252fc0','雪中講堂賜酒二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','袖手垂鞭出帝闉，萬花欄馬舞新春。',32,'全唐诗/poet.song.140000.json','["袖手垂鞭出帝闉，萬花欄馬舞新春。", "是時也有青油繖，天上歸來雪滿身。"]'),
('ad262539-5dad-49a1-a0fb-34b0873c80c3','立春後一日和張功父園梅未花之韻','楊萬里','宋','宋诗','song-poetry','','[]','前夕三更月落時，東風已動萬花知。',64,'全唐诗/poet.song.140000.json','["前夕三更月落時，東風已動萬花知。", "江梅端合先交割，春色如何未探支。", "只欠梁溪冰柱句，追還和靖暗香詩。", "張家剩有葱根指，不把瓊酥滴一枝。"]'),
('bb557ec0-9ef1-40ff-a59f-6f821a23d761','白頭吟二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','文君自製白頭吟，怨思來時海未深。',32,'全唐诗/poet.song.140000.json','["文君自製白頭吟，怨思來時海未深。", "怨殺相如償底事，初頭苦信一張琴。"]'),
('a1d2fd2c-e5d6-4d77-9e6d-6ac0b99e786c','白頭吟二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','除却共姜是女師，柏舟便到白頭辭。',32,'全唐诗/poet.song.140000.json','["除却共姜是女師，柏舟便到白頭辭。", "勸渠莫怨終難勸，不道前夫怨阿誰。"]'),
('e4085401-443f-4ffc-8b0a-d0af7631d6d8','丁未元日大慶殿拜表賀正','楊萬里','宋','宋诗','song-poetry','','[]','獻歲朝未央，新霽快明發。',120,'全唐诗/poet.song.140000.json','["獻歲朝未央，新霽快明發。", "晨曦耿五色，宿靄欻四徹。", "洗清萬溝瓦，銷盡一月雪。", "素光從何來，晶熒落寒笏。", "回瞻背陰處，猶藏半簷白。", "夜來有微霜，雪上辨不得。", "時於翠幕頂，拂掠見瓊屑。", "還將黄金日，正射白銀闕。", "忽然捲班出，紅綠亂眼襭。", "歸來飲屠酥，笑向兒女說。"]'),
('c8ca030d-496b-4720-a112-a037c56cd211','元日癸卯占雲大熟','楊萬里','宋','宋诗','song-poetry','','[]','造物今年印，司花昨夜交。',48,'全唐诗/poet.song.140000.json','["造物今年印，司花昨夜交。", "雪留蘆荻脚，日到瑞香梢。", "白叟占嘉應，青精看滿抄。", "游絲也驩喜，不住舞蠨蛸。"]'),
('e964ddca-c9aa-43b0-934e-1e9ff9032945','送趙民則少監提舉二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','漢庭近日少宗盟，博選宗英副匠卿。',64,'全唐诗/poet.song.140000.json','["漢庭近日少宗盟，博選宗英副匠卿。", "高帝子孫誰宿德，翰林風月得先生。", "又持一節湖南去，政是三湘雁北征。", "但使遠民蒙福了，早歸詞禁賦新鶑。"]'),
('d6a75394-9d7d-4e73-9250-c4bcf8e8f605','送趙民則少監提舉二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','座主門生四十年，江湖契闊幾風煙。',64,'全唐诗/poet.song.140000.json','["座主門生四十年，江湖契闊幾風煙。", "同朝再接鴛行裏，握手相看鶴髮前。", "誤喜論詩追舊事，不知呼酒是離筵。", "老懷只作還山夢，輸與先生早著鞭。"]'),
('e2e67290-a88e-40c0-af75-47007c3cf0d2','雙峰定水璘老送木犀香五首  其一','楊萬里','宋','宋诗','song-poetry','','[]','春得鄞江信，香從定水來。',24,'全唐诗/poet.song.140000.json','["春得鄞江信，香從定水來。", "今年有奇事，正月木犀開。"]'),
('728b3ddc-07be-4de3-bf2d-4bd82f389812','雙峰定水璘老送木犀香五首  其二','楊萬里','宋','宋诗','song-poetry','','[]','萬杵黄金屑，九烝碧梧骨。',24,'全唐诗/poet.song.140000.json','["萬杵黄金屑，九烝碧梧骨。", "詩老坐雪窗，天香來月窟。"]'),
('475eb951-3211-48e0-b859-b92275949317','雙峰定水璘老送木犀香五首  其三','楊萬里','宋','宋诗','song-poetry','','[]','山童不解事，著火太酷烈。',24,'全唐诗/poet.song.140000.json','["山童不解事，著火太酷烈。", "要輸不盡香，急喚薄銀葉。"]'),
('6fd76a16-3373-4e2a-b651-129425ca0576','雙峰定水璘老送木犀香五首  其四','楊萬里','宋','宋诗','song-poetry','','[]','傳語雙峰老，汝師是如來。',24,'全唐诗/poet.song.140000.json','["傳語雙峰老，汝師是如來。", "如何一瓣香，却爲楊誠齋。"]'),
('482d031d-9a55-44c8-8dfa-1a32a2a79f0a','雙峰定水璘老送木犀香五首  其五','楊萬里','宋','宋诗','song-poetry','','[]','誰言定水禪，入定似枯木。',24,'全唐诗/poet.song.140000.json','["誰言定水禪，入定似枯木。", "飛入廣寒宮，收得香萬斛。"]'),
('dfdf0309-b684-4e56-995c-f80f3057e26e','人日出游湖上十首  其一','楊萬里','宋','宋诗','song-poetry','','[]','放閘冷泉亭，抽動一天碧。',24,'全唐诗/poet.song.140000.json','["放閘冷泉亭，抽動一天碧。", "平地跳雪山，晴空下霹靂。"]'),
('c0697c6e-42e3-4b12-8593-77e4879f95bf','人日出游湖上十首  其二','楊萬里','宋','宋诗','song-poetry','','[]','去時數點雨，歸時數片雪。',24,'全唐诗/poet.song.140000.json','["去時數點雨，歸時數片雪。", "雨雪兩不多，山路雙清絕。"]'),
('dca5499f-0a8f-494a-ac87-d971541733ec','人日出游湖上十首  其三','楊萬里','宋','宋诗','song-poetry','','[]','舊臘緣多雪，新年未有梅。',24,'全唐诗/poet.song.140000.json','["舊臘緣多雪，新年未有梅。", "殷勤下天竺，隔水兩株開。"]'),
('ed2ee56c-8a82-49ec-85db-4c5c1a84d6ea','人日出游湖上十首  其四','楊萬里','宋','宋诗','song-poetry','','[]','肩輿豈不穩，萬象非我有。',24,'全唐诗/poet.song.140000.json','["肩輿豈不穩，萬象非我有。", "呼童換馬來，湖山落吾手。"]'),
('c79c4017-9256-463d-8abb-b6962beec0ae','人日出游湖上十首  其五','楊萬里','宋','宋诗','song-poetry','','[]','樹隠重重竹，溪穿曲曲峰。',24,'全唐诗/poet.song.140000.json','["樹隠重重竹，溪穿曲曲峰。", "林深那有寺，煙遠忽聞鐘。"]'),
('1f927274-4c9e-45a0-8546-39c12a5e5ab4','人日出游湖上十首  其六','楊萬里','宋','宋诗','song-poetry','','[]','城中雪一尺，山中雪一丈。',24,'全唐诗/poet.song.140000.json','["城中雪一尺，山中雪一丈。", "地上都已消，却在松梢上。"]'),
('47e51d4e-5a53-43e5-83cc-d741194c2deb','人日出游湖上十首  其七','楊萬里','宋','宋诗','song-poetry','','[]','去歲遊春屐，苔痕故可尋。',24,'全唐诗/poet.song.140000.json','["去歲遊春屐，苔痕故可尋。", "人家隨岸遠，塔影落湖深。"]'),
('d37a63d4-8d8e-4192-9260-83a3ccba61ae','人日出游湖上十首  其八','楊萬里','宋','宋诗','song-poetry','','[]','客愛清殊絕，僧愁凍不勝。',24,'全唐诗/poet.song.140000.json','["客愛清殊絕，僧愁凍不勝。", "可憐兜率寺，齋供一湖冰。"]'),
('953dd0f5-a016-49b6-bc70-5866d4ec0aba','人日出游湖上十首  其九','楊萬里','宋','宋诗','song-poetry','','[]','上竺雪來時，四山都作凍。',24,'全唐诗/poet.song.140000.json','["上竺雪來時，四山都作凍。", "團團玉屏風，圍繞渾無縫。"]'),
('d1a68558-22e4-4541-9be3-9835e4b05eab','人日出游湖上十首  其一○','楊萬里','宋','宋诗','song-poetry','','[]','此行殊匆匆，天色不肯借。',24,'全唐诗/poet.song.140000.json','["此行殊匆匆，天色不肯借。", "更待海棠晴，滿意孤山下。"]'),
('b5ce0dbf-8dbb-4b02-8ad7-9a7a14e056bb','瑞香花新開五首  其一','楊萬里','宋','宋诗','song-poetry','','[]','外著明霞綺，中裁淡玉紗。',48,'全唐诗/poet.song.140000.json','["外著明霞綺，中裁淡玉紗。", "森森千萬筍，旋旋兩三花。", "小霽迎風喜，輕寒索幕遮。", "香中真上瑞，蘭麝敢名家。"]'),
('3adb8a0c-28f3-43e9-8721-e407d29a199e','瑞香花新開五首  其二','楊萬里','宋','宋诗','song-poetry','','[]','老子觀書倦，昏然睡思來。',48,'全唐诗/poet.song.140000.json','["老子觀書倦，昏然睡思來。", "夢中誰喚醒，窗外瑞香開。", "只道花頭細，能追國艷回。", "殷勤伴幽獨，渠與一瓶梅。"]'),
('923e4ff6-cf9a-4d2e-a234-a8b3f04ce48f','瑞香花新開五首  其三','楊萬里','宋','宋诗','song-poetry','','[]','短短熏籠小，團團錦帊圍。',48,'全唐诗/poet.song.140000.json','["短短熏籠小，團團錦帊圍。", "浮陽烘酒思，沈水著人衣。", "抹利通家遠，楠花具體微。", "春愁渾瘦盡，別有瘦中肥。"]'),
('10910978-256e-4b85-bce7-40b1b5f32b66','瑞香花新開五首  其四','楊萬里','宋','宋诗','song-poetry','','[]','雪裏移蒼斛，梢頭點翠芒。',48,'全唐诗/poet.song.140000.json','["雪裏移蒼斛，梢頭點翠芒。", "只銷三日暖，便坼數花房。", "紫袖染難透，瓊膚曬轉香。", "小留供鼻觀，開去未須忙。"]'),
('f4f3d763-6300-45f6-96ca-dd1994eb96c1','瑞香花新開五首  其五','楊萬里','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','馨德潜丘壑，春風是往還。',48,'全唐诗/poet.song.140000.json','["馨德潜丘壑，春風是往還。", "新從衆香國，移種洞庭山。", "孤韻真無對，千花夐莫攀。", "騷經吾欲續，譜入芷蘅間。"]'),
('41891544-6edc-4456-8fe1-fac37eed4eb6','謝李元德郎中餉家釀二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','長史銜杯太白醺，詼詞笑殺古來人。',32,'全唐诗/poet.song.140000.json','["長史銜杯太白醺，詼詞笑殺古來人。", "至今太白一船酒，不飲還將飲子雲。"]'),
('01d92590-9c3d-4615-acc0-5fce758c3799','謝李元德郎中餉家釀二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','惠山山下玉泉香，釀作鵝兒一拂黄。',32,'全唐诗/poet.song.140000.json','["惠山山下玉泉香，釀作鵝兒一拂黄。", "吏部只知防姓畢，不知吏部有它楊。"]'),
('b1cc459f-b4fb-4a42-aa61-178e808b78c6','初出貢院買山寒毬花數枝','楊萬里','宋','宋诗','song-poetry','','[]','寒毬著意殿餘芳，小底來禽大海棠。',64,'全唐诗/poet.song.140000.json','["寒毬著意殿餘芳，小底來禽大海棠。", "初喜艷紅明莟子，忽看淡白散花房。", "風光不到棘圍裏，春色也尋茅舍旁。", "便有蜜蜂三兩輩，喙長三尺繞枝忙。"]'),
('d0082f50-2f38-4235-9ced-91620cb6c2b7','紫牡丹二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','萬花不分不春妍，至竟專春是牡丹。',64,'全唐诗/poet.song.140000.json','["萬花不分不春妍，至竟專春是牡丹。", "紫錦香囊金屑暖，翠羅舞袖掌文寒。", "恨無國色天香句，借與風條日萼看。", "家有洛陽一千朶，三年歸夢繞欄干。"]'),
('e0e5710d-4ca2-4724-a7b2-dc682531a50e','紫牡丹二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','歲歲東風二月時，司花辛苦染晴枝。',64,'全唐诗/poet.song.140000.json','["歲歲東風二月時，司花辛苦染晴枝。", "夜輸百斛薔薇水，曉洗千層玉雪肌。", "寒食清明空過了，姚黄魏紫不曾知。", "春愁蹙得眉頭破，何處如今更有詩。"]'),
('71c71303-2446-42c3-bfab-1d072cbc8adf','上巳同沈虞卿尤延之王順伯林景思游湖上得十絕句呈同社  其一','楊萬里','宋','宋诗','song-poetry','','[]','鵠袍林裏過芳辰，聞道春來不識春。',32,'全唐诗/poet.song.140000.json','["鵠袍林裏過芳辰，聞道春來不識春。", "及至識春春已老，於中更老是詩人。"]'),
('fe9c1458-27f1-4ce7-81ce-3734b7457a4b','上巳同沈虞卿尤延之王順伯林景思游湖上得十絕句呈同社  其二','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','總宜亭子小如拳，著得西湖不見痕。',32,'全唐诗/poet.song.140000.json','["總宜亭子小如拳，著得西湖不見痕。", "湖上軒窗無不好，何須抵死揀名園。"]'),
('912c9f39-91bb-47a3-89f6-aaad72b0f9eb','上巳同沈虞卿尤延之王順伯林景思游湖上得十絕句呈同社  其三','楊萬里','宋','宋诗','song-poetry','','[]','孤山山後北山前，十里長堤隔兩邊。',32,'全唐诗/poet.song.140000.json','["孤山山後北山前，十里長堤隔兩邊。", "一行垂楊綠無縫，石橋通處過春船。"]'),
('2a517bd1-bc53-45f5-85d9-0d656ab611f1','上巳同沈虞卿尤延之王順伯林景思游湖上得十絕句呈同社  其四','楊萬里','宋','宋诗','song-poetry','','[]','天色䰒鬆未肯收，吾儕自樂不曾愁。',32,'全唐诗/poet.song.140000.json','["天色䰒鬆未肯收，吾儕自樂不曾愁。", "隨宜旋旋商量著，晴即閑行雨即休。"]'),
('91b7ee61-883f-4414-8cb1-47f0d092eb27','上巳同沈虞卿尤延之王順伯林景思游湖上得十絕句呈同社  其五','楊萬里','宋','宋诗','song-poetry','','[]','籃輿休上馬休騎，濕却青鞋也不辭。',32,'全唐诗/poet.song.140000.json','["籃輿休上馬休騎，濕却青鞋也不辭。", "揀取雨絲疎處去，携筇且謁水仙祠。"]'),
('5712fb2e-b50c-4397-85b7-9d0309f6242e','上巳同沈虞卿尤延之王順伯林景思游湖上得十絕句呈同社  其六','楊萬里','宋','宋诗','song-poetry','','[]','雨催杖屨却須回，捲上疎簾眼頓開。',32,'全唐诗/poet.song.140000.json','["雨催杖屨却須回，捲上疎簾眼頓開。", "十里湖光平似鏡，柳梢梢外一船來。"]'),
('833f43c7-0c55-4e14-ba93-3755408f794d','上巳同沈虞卿尤延之王順伯林景思游湖上得十絕句呈同社  其七','楊萬里','宋','宋诗','song-poetry','','[]','湖上春游只愛晴，何朝何夕不晴明。',32,'全唐诗/poet.song.140000.json','["湖上春游只愛晴，何朝何夕不晴明。", "絕憐疎雨微雲裏，點綴湖山分外清。"]'),
('252f8929-c2ec-4e16-9b1c-f8e6d8bbbb5e','上巳同沈虞卿尤延之王順伯林景思游湖上得十絕句呈同社  其八','楊萬里','宋','宋诗','song-poetry','','[]','憑久欄干可一杯，湖山飛入水中來。',32,'全唐诗/poet.song.140000.json','["憑久欄干可一杯，湖山飛入水中來。", "多情燕子能相勸，舞破東風去却回。"]'),
('b39dd2ef-0574-442b-bc00-521e576990d5','上巳同沈虞卿尤延之王順伯林景思游湖上得十絕句呈同社  其九','楊萬里','宋','宋诗','song-poetry','','[]','今年山路少人來，酒肆蕭然綺席埃。',32,'全唐诗/poet.song.140000.json','["今年山路少人來，酒肆蕭然綺席埃。", "政爾坐愁春寂寞，畫船簫鼓忽如雷。"]'),
('d54c16a0-5faf-47bb-ad17-388a4df92a99','上巳同沈虞卿尤延之王順伯林景思游湖上得十絕句呈同社  其一○','楊萬里','宋','宋诗','song-poetry','','[]','岸上湖中各自奇，山觴水酌兩皆宜。',32,'全唐诗/poet.song.140000.json','["岸上湖中各自奇，山觴水酌兩皆宜。", "只言游舫渾如畫，身在畫中元不知。"]'),
('49601aba-ac85-4ba4-b6b4-00528e7de95a','跋淳溪汪立義大學致知圖二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','杏壇何物是家風，只在當人阿堵中。',32,'全唐诗/poet.song.140000.json','["杏壇何物是家風，只在當人阿堵中。", "誰作新圖漏消息，淳溪溪上釣魚翁。"]'),
('af1591f4-c3b6-4602-8871-817f96bc92fb','跋淳溪汪立義大學致知圖二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','此事元無淺與深，著衣喫飯送光陰。',32,'全唐诗/poet.song.140000.json','["此事元無淺與深，著衣喫飯送光陰。", "却緣說似癡人夢，便向汪家圖裏尋。"]'),
('3d220bd4-c819-4891-83c9-918a497c2c0f','景靈宮聞子規','楊萬里','宋','宋诗','song-poetry','','[]','今年未有子規聲，忽向宮中樹上鳴。',64,'全唐诗/poet.song.140000.json','["今年未有子規聲，忽向宮中樹上鳴。", "告訴落花春不管，裴回曉月恨難平。", "斜風細雨又三月，柳絮浮雲空一生。", "豈不懷歸歸未得，倩渠傳語故園鶑。"]'),
('f92d0723-6653-48f2-8cf7-4a073fe4e48e','寄題劉成功錦里','楊萬里','宋','宋诗','song-poetry','','[]','嘉林市中塵一丈，嘉林寺後竹千竿。',96,'全唐诗/poet.song.140000.json','["嘉林市中塵一丈，嘉林寺後竹千竿。", "先君授徒竹窗底，我初識君俱少年。", "同師同舍同筆硯，火冷燈青飛雪片。", "春風一夜吹林花，南北飄零各星散。", "我今頭白苦思歸，羨君山園芋栗肥。", "爲君題作小錦里，君應一笑巾墮几。"]'),
('a67b60c4-de95-4481-8824-8140fad42d53','讀淵明詩','楊萬里','宋','宋诗','song-poetry','','[]','少年喜讀書，晚悔昔草草。',132,'全唐诗/poet.song.140000.json','["少年喜讀書，晚悔昔草草。", "迨今得書味，又恨身已老。", "淵明非生面，穉歲識已早。", "極知人更賢，未契詩獨好。", "塵中談久睽，暇處目偶到。", "故交了無改，乃似未見寶。", "貌同覺神異，舊翫出新妙。", "琱空那有痕，滅跡不須掃。", "腹腴八珍初，天巧萬象表。", "向來心獨苦，膚見欲幽討。", "寄謝潁濱翁，何謂淡且槁。"]'),
('61e9ba77-adf9-4688-9646-f76e8fd4ef5c','送謝子肅提舉寺丞二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','天台山秀古多賢，晚向池塘識惠連。',64,'全唐诗/poet.song.140000.json','["天台山秀古多賢，晚向池塘識惠連。", "十載江湖州縣底，一言金石冕旒前。", "方陪廷尉甘堂舍，又賦皇華小雅篇。", "拾得澄江春草句，端能染寄仄釐牋。"]'),
('1117d55c-ea60-4370-8b56-3172fe557ba2','送謝子肅提舉寺丞二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','誰遣孤舟蓑笠翁，强隨桃李競春風。',64,'全唐诗/poet.song.140000.json','["誰遣孤舟蓑笠翁，强隨桃李競春風。", "交情頃刻雲翻手，古意淒涼月印空。", "可笑能詩今謝脁，也能載酒過揚雄。", "待渠歸直金鑾日，我已煙沙放釣筒。"]'),
('9139f49b-23b9-4797-b94c-a77fe410356f','送錢寺正出守廣德軍二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','四十專城古已稀，君侯五七更英奇。',64,'全唐诗/poet.song.140000.json','["四十專城古已稀，君侯五七更英奇。", "九重臨遣廷尉正，千里驩迎循吏師。", "鴻雁同科金玉律，鵷雛先集鳳凰枝。", "少年勇退無人會，孤竹初心遜伯夷。"]'),
('5f68f590-63ef-4b69-8583-ffed95cc74e1','送錢寺正出守廣德軍二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','辛卯中書落筆年，曾陪學士堵牆間。',64,'全唐诗/poet.song.140000.json','["辛卯中書落筆年，曾陪學士堵牆間。", "看渠手把州麾去，故里春迎晝繡還。", "我似青蒿君玉樹，君方綠鬢我蒼顔。", "一尊話別休辭醉，報政歸來紫禁班。"]'),
('dd619a91-6b35-4ca3-94eb-2fd36424ed0e','鄉士李英才得老潘墨法善作墨梅復喜作詩艮齋目以三奇贈之七字予復同賦云','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','吾鄉李君磊嵬胸，夜持雲梯倚秋空。',112,'全唐诗/poet.song.140000.json','["吾鄉李君磊嵬胸，夜持雲梯倚秋空。", "月中奪得修月斧，斫倒南山千歲松。", "束歸丹竈和玉桂，燧出綠霧霏鸞龍。", "擣成玄圭與蒼璧，灑作橫枝歲寒色。", "庾嶺霜林和靖園，掇入生綃供戲劇。", "幻松作璧璧作梅，豪氣勃鬰尚不開。", "瓊艘滿釂梅雪下，吐出西湖有聲畫。"]'),
('cfa12a6d-72a6-42f3-9271-0a63f6dad4c1','送姜夔堯章謁石湖先生','楊萬里','宋','宋诗','song-poetry','','[]','釣璜英氣橫白蜺，欬唾珠玉皆新詩。',128,'全唐诗/poet.song.140000.json','["釣璜英氣橫白蜺，欬唾珠玉皆新詩。", "江山愁訴鶑爲泣，鬼神露索天洩機。", "彭蠡波心弄明月，詩星入腸肺肝裂。", "吐作春風百種花，吹散瀕湖數峰雪。", "青鞋布襪軟紅塵，千詩只博一字貧。", "吾友夷陵蕭太守，逢人說君不離口。", "袖詩東來謁老夫，慚無高價當璠璵。", "翻然却買松江艇，徑去蘇州參石湖。"]'),
('accfc2e4-5320-422e-b7e3-b6aba197443b','三月二十六殿試進士待罪集英殿門二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','金戺瑶階日月邊，曉風花柳带非煙。',64,'全唐诗/poet.song.140000.json','["金戺瑶階日月邊，曉風花柳带非煙。", "千官劍佩鳴雙闕，萬國英豪到九天。", "玉座忽臨黄繖正，御題初出紫衣傳。", "小臣何幸陪諸老，待罪重來十六年。"]'),
('14727b41-3c0b-4514-9c80-3301835932e7','三月二十六殿試進士待罪集英殿門二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','九虎遮藏造化機，御題過午始聞知。',64,'全唐诗/poet.song.140000.json','["九虎遮藏造化機，御題過午始聞知。", "乾坤闔闢兼文武，雲漢昭回具訓詞。", "武帝上嘉真戲耳，放勳清問政如斯。", "諸儒莫作公孫子，千載何曾遇聖時。"]'),
('d1f9183c-9873-498e-b223-bf5dc106a7b8','趙達明太社四月一日招遊西湖十首  其一','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','今日清和和又清，王孫領客出都城。',32,'全唐诗/poet.song.140000.json','["今日清和和又清，王孫領客出都城。", "好天勝日能多少，三到西湖始一晴。"]'),
('39590129-faf9-433f-a529-112c16d9499a','趙達明太社四月一日招遊西湖十首  其二','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','畫舫侵晨繫柳枝，主人生怕客來遲。',32,'全唐诗/poet.song.140000.json','["畫舫侵晨繫柳枝，主人生怕客來遲。", "嬌雲嫩日無風色，幸是湖船好放時。"]'),
('e839b5bf-fe18-460d-a1c9-5af184bfc58d','趙達明太社四月一日招遊西湖十首  其三','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','船從詠澤過孤山，徑度琉璃一簟間。',32,'全唐诗/poet.song.140000.json','["船從詠澤過孤山，徑度琉璃一簟間。", "隔岸多情楊柳樹，向人招喚俯煙鬟。"]'),
('ffa0bb2a-cf04-46fb-bce8-e5e129d34ccb','趙達明太社四月一日招遊西湖十首  其四','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','御池水滿苑門開，泥带飛花路带苔。',32,'全唐诗/poet.song.140000.json','["御池水滿苑門開，泥带飛花路带苔。", "到得孤山翻作惡，海棠閙日不曾來。"]'),
('20c7db61-43d4-4a09-8584-44953aa584dc','趙達明太社四月一日招遊西湖十首  其五','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','萍生兒子點疎星，荷捲文書立萬丁。',32,'全唐诗/poet.song.140000.json','["萍生兒子點疎星，荷捲文書立萬丁。", "回首南高峰上塔，手中攀得玉竛竮。"]'),
('f55ab5c0-c921-48bd-9a62-3be2b3b9b282','趙達明太社四月一日招遊西湖十首  其六','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','橘花如雪細吹香，杏子團枝未可嘗。',32,'全唐诗/poet.song.140000.json','["橘花如雪細吹香，杏子團枝未可嘗。", "行到陳朝枯柏處，孤山山背水中央。"]'),
('eb452a15-bc54-4b43-9154-c3908162ec8b','趙達明太社四月一日招遊西湖十首  其七','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','和靖先生墳已荒，空餘松竹故蒼蒼。',32,'全唐诗/poet.song.140000.json','["和靖先生墳已荒，空餘松竹故蒼蒼。", "王孫自洗鸕鷀杓，滿酌真珠酹一觴。"]'),
('2316024a-3595-457a-957f-4bc6ee9fdbdd','趙達明太社四月一日招遊西湖十首  其八','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','行盡孤山碧四圍，却尋初路得來時。',32,'全唐诗/poet.song.140000.json','["行盡孤山碧四圍，却尋初路得來時。", "好風借與歸船便，吹近瓊林却不吹。"]'),
('dc2ad24b-8778-434b-8948-a803c3dc7e96','趙達明太社四月一日招遊西湖十首  其九','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','風撩太液小荷欹，日麗長楊花影低。',32,'全唐诗/poet.song.140000.json','["風撩太液小荷欹，日麗長楊花影低。", "闌入苑中啼不歇，恨身不及一黄鸝。"]'),
('4e01add7-677d-4765-95eb-4a880f4a97b1','趙達明太社四月一日招遊西湖十首  其一○','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','葱蘢晚色正佳哉，苦被歸鞍緊緊催。',32,'全唐诗/poet.song.140000.json','["葱蘢晚色正佳哉，苦被歸鞍緊緊催。", "船壓浮荷沈水底，須臾船過却浮來。"]'),
('5aae3231-77d8-4d0f-9813-815d51a54380','紅玫瑰','楊萬里','宋','宋诗','song-poetry','','[]','非關月季姓名同，不與薔薇譜牒通。',64,'全唐诗/poet.song.140000.json','["非關月季姓名同，不與薔薇譜牒通。", "接葉連枝千萬綠，一花兩色淺深紅。", "風流各自燕支格，雨露何私造化功。", "別有國香收不得，詩人熏入水沈中。"]'),
('996c7061-2edb-4549-b68a-2c71d70522c5','省中直舍因敲新竹懷周元吉三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','老眼逢書怯細看，抄書一事更應難。',32,'全唐诗/poet.song.140000.json','["老眼逢書怯細看，抄書一事更應難。", "昨携如意敲新籜，右臂朝來作許酸。"]'),
('9e4a6f60-1516-47b7-9e3d-16e827b1d854','省中直舍因敲新竹懷周元吉三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','尚有周郎手種痕，懷人將竹當人看。',32,'全唐诗/poet.song.140000.json','["尚有周郎手種痕，懷人將竹當人看。", "寄言黄鶴樓前客，今歲新添十五竿。"]'),
('12a3c3f7-7aee-4e39-bbbf-42b67c44b9a3','省中直舍因敲新竹懷周元吉三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','老竹堅剛幼竹柔，此君年少也風流。',32,'全唐诗/poet.song.140000.json','["老竹堅剛幼竹柔，此君年少也風流。", "錦衣脫體未全瘦，雪粉圍腰猶半愁。"]'),
('5e8a9828-d99c-4d15-884a-20c2346197ad','含笑','楊萬里','宋','宋诗','song-poetry','','[]','大笑何如小笑香，紫花不似白花粧。',32,'全唐诗/poet.song.140000.json','["大笑何如小笑香，紫花不似白花粧。", "不知自笑還相笑，笑殺人來斷殺腸。"]'),
('7b571b52-ade1-4929-a18c-9ab771c9c019','枇杷','楊萬里','宋','宋诗','song-poetry','','[]','大葉聳長耳，一梢堪滿盤。',48,'全唐诗/poet.song.140000.json','["大葉聳長耳，一梢堪滿盤。", "荔支分與核，金橘却無酸。", "雨壓低枝重，漿流冰齒寒。", "長卿今尚在，莫遣作園官。"]'),
('65132cd0-6672-4a58-9784-1d6e882e06df','走筆送濟翁弟過浙東謁丘宗卿二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','出省還家思已昏，答書見客腹仍煩。',32,'全唐诗/poet.song.140000.json','["出省還家思已昏，答書見客腹仍煩。", "政愁獨酌無佳客，家裏詩人忽扣門。"]'),
('ad133404-4fce-4a1f-b1c8-4afc76777cde','走筆送濟翁弟過浙東謁丘宗卿二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','若見丘遲問老夫，爲言臞似向來臞。',32,'全唐诗/poet.song.140000.json','["若見丘遲問老夫，爲言臞似向來臞。", "更將雙眼寄吾弟，带去稽山看鑑湖。"]'),
('14ed17a1-da58-4300-b931-75cb81e9073a','題西湖僧房','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','竹林深處著禪房，下却疎簾自炷香。',32,'全唐诗/poet.song.140000.json','["竹林深處著禪房，下却疎簾自炷香。", "書畫隨宜遮四壁，閑欹瓦枕小藤床。"]'),
('3e85bd6b-b85c-48a3-9959-e81fb475f66a','省中見樹上啄木鳥戲題','楊萬里','宋','宋诗','song-poetry','','[]','一啄高高一啄低，一聲聲急一聲遲。',32,'全唐诗/poet.song.140000.json','["一啄高高一啄低，一聲聲急一聲遲。", "可憐去蠹勞心口，蟻入枯梨自不知。"]'),
('c1ffcd6c-141c-45ec-827f-117d6e6e676d','山丹花','楊萬里','宋','宋诗','song-poetry','','[]','春去無芳可得尋，山丹最晚出雲林。',64,'全唐诗/poet.song.140000.json','["春去無芳可得尋，山丹最晚出雲林。", "柿紅一色明羅袖，金粉羣蟲集寶簪。", "花似鹿葱還耐久，葉如芍藥不多深。", "青泥瓦斛移山蘤，聊著書窗伴小吟。"]'),
('719c136d-7cc1-4cf2-8e0d-b7fc26be8f20','四月十七日侍立集英殿觀進士唱名','楊萬里','宋','宋诗','song-poetry','','[]','殿上臚傳第一聲，殿前拭目萬人驚。',64,'全唐诗/poet.song.140000.json','["殿上臚傳第一聲，殿前拭目萬人驚。", "名登龍虎黄金榜，人在煙霄白玉京。", "香滿乾坤書一卷，風吹鬢髮雪千莖。", "舊時脫却銀袍處，還望清光侍集英。"]'),
('bbb89707-b2ed-4658-a0d0-1888c4420cf3','無題','楊萬里','宋','宋诗','song-poetry','','[]','坐看胡孫上樹頭，旁人只恐墮深溝。',32,'全唐诗/poet.song.140000.json','["坐看胡孫上樹頭，旁人只恐墮深溝。", "渠儂狡獪何須教，說與旁人莫浪愁。"]'),
('8b23959e-703d-4386-b20d-0e8059586f59','張功父索余近詩余以南海朝天二集示之蒙題七字','楊萬里','宋','宋诗','song-poetry','','[]','作者于今星樣稀，淒其望古駟難追。',64,'全唐诗/poet.song.140000.json','["作者于今星樣稀，淒其望古駟難追。", "空桑孤竹陶元亮，玉佩瓊琚杜拾遺。", "自笑吟秋如嬾婦，可能擊鼓和馮夷。", "報章不作南金直，慚愧君家丙藁詩。"]'),
('4528e80f-4a3f-4f47-ac1f-d486943ca0a0','蒲萄架','楊萬里','宋','宋诗','song-poetry','','[]','纔喜盤藤捲葉生，又驚壓架暗陰成。',64,'全唐诗/poet.song.140000.json','["纔喜盤藤捲葉生，又驚壓架暗陰成。", "夏褰涼潤青油幕，秋摘甘寒黑水精。", "近竹猶爭一尺許，拋鬚先罥兩三莖。", "今年乞種西江去，長是茅齋怯晚晴。"]'),
('52b2bc40-7531-40c2-81a1-1c4f72ab8584','送沈虞卿祕監脩撰將漕江東二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','蓬萊仙伯沈東陽，領袖諸儒太極旁。',64,'全唐诗/poet.song.140000.json','["蓬萊仙伯沈東陽，領袖諸儒太極旁。", "東壁二星雲漢近，西崑群玉簡編香。", "雞翹豹尾無多子，錦纜牙檣有底忙。", "建業江山入詩集，却歸天上侍虛皇。"]'),
('9dbbdf7c-e7ce-4746-82d0-41b97cf30afb','送沈虞卿祕監脩撰將漕江東二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','再入脩門訪舊遊，故人相見喜還愁。',64,'全唐诗/poet.song.140000.json','["再入脩門訪舊遊，故人相見喜還愁。", "茂林脩竹君髯碧，折葦枯荷我鬢秋。", "莫把昇沈著懷抱，古來賢聖幾公侯。", "一尊追送江東棹，夢逐清波弄白鷗。"]'),
('846c8d51-ddbe-4c2b-a87f-a559f9883862','臨賀別駕李子西同年寄五字詩以杜句君隨丞相後爲韻和以謝焉五首  其一','楊萬里','宋','宋诗','song-poetry','','[]','我本南溪老，手弄溪中雲。',48,'全唐诗/poet.song.140000.json','["我本南溪老，手弄溪中雲。", "誦詩愛招隠，讀騷續湘君。", "忽捧公府檄，遂遠先人墳。", "春暮歸未得，落花政紛紛。"]'),
('3de60199-58cd-4284-82d6-30b50aead056','臨賀別駕李子西同年寄五字詩以杜句君隨丞相後爲韻和以謝焉五首  其二','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','老拙誰肯伴，束書自相隨。',48,'全唐诗/poet.song.140000.json','["老拙誰肯伴，束書自相隨。", "此外無長物，猶有一鴟夷。", "小醉即孤詠，自遣不要奇。", "西湖妙天下，未羨習家池。"]'),
('41132de2-ad2b-4338-9384-7b2fc84d26b7','臨賀別駕李子西同年寄五字詩以杜句君隨丞相後爲韻和以謝焉五首  其三','楊萬里','宋','宋诗','song-poetry','','[]','謫仙幾代孫，今日臨賀丞。',48,'全唐诗/poet.song.140000.json','["謫仙幾代孫，今日臨賀丞。", "風月三千首，吾子豈未能。", "長把脩月斧，細彫玉壺冰。", "天池羽翼就，即看垂天鵬。"]'),
('a11e6045-27fe-43fc-b632-6b56b0387eee','臨賀別駕李子西同年寄五字詩以杜句君隨丞相後爲韻和以謝焉五首  其四','楊萬里','宋','宋诗','song-poetry','','[]','曲江與臨武，彼此昔相望。',48,'全唐诗/poet.song.140000.json','["曲江與臨武，彼此昔相望。", "一嶺大如礪，誰云隔尋丈。", "離合非人力，此事要天相。", "昇沈亦偶然，豈問優與髒。"]'),
('f273510f-6f7a-4876-be55-5177c67952c2','臨賀別駕李子西同年寄五字詩以杜句君隨丞相後爲韻和以謝焉五首  其五','楊萬里','宋','宋诗','song-poetry','','[]','買山藝花竹，長恐落人後。',48,'全唐诗/poet.song.140000.json','["買山藝花竹，長恐落人後。", "不見竹林人，山王非俎豆。", "市門能幾許，掉臂日奔湊。", "遲子來朝天，商略陳薄陋。"]'),
('792d7ee0-8309-4fb7-a278-c4b21b001f5c','游水月寺','楊萬里','宋','宋诗','song-poetry','','[]','菸日蔫雲乍暑天，倦投山寺借床眠。',32,'全唐诗/poet.song.140000.json','["菸日蔫雲乍暑天，倦投山寺借床眠。", "清涼世界誰曾到，却在紅塵紫陌邊。"]'),
('3eb01868-8338-454c-8bf3-f541cf45a525','題水月寺寒秀軒','楊萬里','宋','宋诗','song-poetry','','[]','小寺深門一逕斜，繞身縈面總煙霞。',64,'全唐诗/poet.song.140000.json','["小寺深門一逕斜，繞身縈面總煙霞。", "低低簷入低低樹，小小盆盛小小花。", "經藏中間看佛畫，竹林外面是人家。", "山僧笑道知儂渴，其實迎賓例瀹茶。"]'),
('d344a04f-c7f0-4250-a390-fc4c7b59a077','歸塗觀劉寺新疊石山','楊萬里','宋','宋诗','song-poetry','','[]','風月肝脾冰雪胸，道人妙手鑿虛空。',64,'全唐诗/poet.song.140000.json','["風月肝脾冰雪胸，道人妙手鑿虛空。", "斸翻諸嶺雲煙骨，幻出山巖紫翠峰。", "細看分明非飣餖，如何彫得許玲瓏。", "爲誰苦死忙歸去，知是斜陽是晚鐘。"]'),
('f76f875c-7651-49b2-9b35-75582ba81807','題劉寺僧房','楊萬里','宋','宋诗','song-poetry','','[]','曾醉山間金叵羅，山應識我我懷它。',64,'全唐诗/poet.song.140000.json','["曾醉山間金叵羅，山應識我我懷它。", "頓添花竹明松檜，依舊菰蒲暗芰荷。", "試問錦屏無恙否，向來梅樹已無多。", "未須看遍新亭榭，勝日重來一一過。"]'),
('d477a408-94d5-447e-a6e9-d7277af9272e','和嚴州添倅趙彥先寄四絕句  其一','楊萬里','宋','宋诗','song-poetry','','[]','不見王孫今九春，新詞麗曲爽心神。',32,'全唐诗/poet.song.140000.json','["不見王孫今九春，新詞麗曲爽心神。", "只言風月平分破，却是江湖一散人。"]'),
('2c7ab6f7-d788-477e-9114-a5bceca9a61d','和嚴州添倅趙彥先寄四絕句  其二','楊萬里','宋','宋诗','song-poetry','','[]','自摶蒼壁自抄書，雪乳一甌香一爐。',32,'全唐诗/poet.song.140000.json','["自摶蒼壁自抄書，雪乳一甌香一爐。", "有得俸錢無吏責，如公官況世間無。"]'),
('85dddceb-6b53-4ca2-9b90-ce0b9e50f7e1','和嚴州添倅趙彥先寄四絕句  其三','楊萬里','宋','宋诗','song-poetry','','[]','昌歜佳辰風自南，黄梅釀出雨鬖鬖。',32,'全唐诗/poet.song.140000.json','["昌歜佳辰風自南，黄梅釀出雨鬖鬖。", "綺琴繡段能分似，報不如儀獨不慚。"]'),
('43b1cfbf-cd90-4564-97d5-85e2159f04bb','和嚴州添倅趙彥先寄四絕句  其四','楊萬里','宋','宋诗','song-poetry','','[]','雛鳳今年又一鳴，芝蘭秀發不曾停。',32,'全唐诗/poet.song.140000.json','["雛鳳今年又一鳴，芝蘭秀發不曾停。", "州前爭探黄金榜，却報城隅最冷廳。"]'),
('448cecad-9344-4e0e-b9a1-c62c7bfc8850','戲題簷間蜘蛛','楊萬里','宋','宋诗','song-poetry','','[]','屋角籬尖竹樹陰，可憐用盡許機心。',64,'全唐诗/poet.song.140000.json','["屋角籬尖竹樹陰，可憐用盡許機心。", "凝身不動如無物，頓網輕摇試有禽。", "絲貫日華明五色，戲隨風舞忽千尋。", "看渠經緯來還去，忘却摧隤立不禁。"]'),
('d04ef65f-16d6-4615-9b54-13e4ec96b285','跋忠敏任公遺帖','楊萬里','宋','宋诗','song-poetry','','[]','市中貨鴆作參苓，遮莫秦和苦口爭。',32,'全唐诗/poet.song.140000.json','["市中貨鴆作參苓，遮莫秦和苦口爭。", "殺盡蒼生消底物，卞京兩把老蔓菁。"]'),
('50fb4c80-b1f3-4e20-ac5f-f66ac3d707e5','同尤延之京仲遠玉壺餞客二首  其一','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','南漪亭上據胡床，不負西湖五月涼。',32,'全唐诗/poet.song.140000.json','["南漪亭上據胡床，不負西湖五月涼。", "十里水風已無價，水風底裏更荷香。"]'),
('6e55214c-6374-4012-996a-922ab0078ef6','同尤延之京仲遠玉壺餞客二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','金杯玉酒沈寒冰，青李來禽尚带生。',32,'全唐诗/poet.song.140000.json','["金杯玉酒沈寒冰，青李來禽尚带生。", "不是此間無暑氣，湖風吹取過臨平。"]'),
('e1a8fe90-3338-4a7b-b943-8dd795eb59ad','玉壺餞客獨趙達明末至云迓族長於龍山且談道中事戲爲紀之二首  其一','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','南山行盡到西湖，却上扁舟赴玉壺。',32,'全唐诗/poet.song.140000.json','["南山行盡到西湖，却上扁舟赴玉壺。", "十里便成三十里，暑中何處不長塗。"]'),
('eba4c4e4-9465-4038-a11a-2ef0f21404d4','玉壺餞客獨趙達明末至云迓族長於龍山且談道中事戲爲紀之二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','公子從來火傘中，解衣未定語匆匆。',32,'全唐诗/poet.song.140000.json','["公子從來火傘中，解衣未定語匆匆。", "山行觸熱端何事，夾路楊梅樹樹紅。"]'),
('6b41f522-c36b-4048-9344-4ac6b6ed2a0a','食蓮子','楊萬里','宋','宋诗','song-poetry','','[]','綠玉蜂房白玉蜂，折來带露復含風。',32,'全唐诗/poet.song.140000.json','["綠玉蜂房白玉蜂，折來带露復含風。", "玻瓈盆面冰漿底，醉嚼新蓮一百蓬。"]'),
('6f40ba52-daa7-414f-ae5d-4615ddc0deb4','白蓮','楊萬里','宋','宋诗','song-poetry','','[]','井花新插白芙蕖，坐看紛紛脫雪膚。',32,'全唐诗/poet.song.140000.json','["井花新插白芙蕖，坐看紛紛脫雪膚。", "自拾落英浮水面，玉舟撩亂滿江湖。"]'),
('b6140d5b-80cc-4658-ae70-f2be1b7aea12','酷暑觀小僮汲水澆石假山','楊萬里','宋','宋诗','song-poetry','','[]','堂後簷前小石山，一峰瘦削四峰攢。',64,'全唐诗/poet.song.140000.json','["堂後簷前小石山，一峰瘦削四峰攢。", "忽騰絕壁三千丈，飛下清泉六月寒。", "乃是家僮聊戲事，倒傾古井作驚湍。", "老夫畏熱年來甚，更借跳珠裂玉看。"]'),
('6027edab-6a3c-40f4-b680-c03c68b31a73','清曉湖上三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','山腰輕束一綃雲，湖面初顰半蹙痕。',32,'全唐诗/poet.song.140000.json','["山腰輕束一綃雲，湖面初顰半蹙痕。", "未說湖山佳處在，清晨小出湧金門。"]');
